window.allTests = window.allTests || {};

// --- 2. ÜNİTE: TARIM DEVRİMİNİN ESKİ ÇAĞ'A ETKİLERİ - TEST 1 ---
window.allTests["test_u2_tarim_1"] = [
    {
        soru: "<i>\"İnsanlar binlerce yıl boyunca avlanarak ve yabani bitkileri toplayarak geçimlerini sağladılar. Yaklaşık MÖ 10.000 yılında Verimli Hilal olarak adlandırılan bölgede — Dicle, Fırat ve Nil nehirlerini çevreleyen topraklarda— bazı topluluklar, yabani buğday ve arpanın tohumlarını kasıtlı olarak toprağa ekmeye başladılar.\" (Kaynak: Jared Diamond, Tüfek, Mikrop ve Çelik, 1997, s. 85 – uyarlanmıştır)</i><br><br><b>Bu metne göre Tarım Devrimi’nin başladığı coğrafyanın en belirgin özelliği nedir?</b>",
        secenekler: [
            "A) Büyük çöllere yakın olması",
            "B) Nehir vadilerini kapsayan verimli topraklara sahip olması",
            "C) Deniz kıyısında yer alması",
            "D) Soğuk ikliminin tohumları koruması",
            "E) Ormanlarla kaplı geniş alanlara ev sahipliği yapması"
        ],
        cevap: "B) Nehir vadilerini kapsayan verimli topraklara sahip olması",
        aciklama: "Metin, Tarım Devrimi’nin Dicle, Fırat ve Nil nehirlerini kapsayan, 'Verimli Hilal' denen bölgede başladığını açıkça vurgulamaktadır. Bu nehir havzalarının alüvyonlu toprakları tarıma son derece elverişlidir. A, C, D ve E seçenekleri metinde geçen coğrafi özelliklere uymamaktadır."
    },
    {
        soru: "<i>\"Çiftçilik, avlanmanın yerini aldıkça insanlar artık yiyecek aramak için sürekli göç etmek zorunda kalmadılar. Kalıcı köyler kuruldu, insanlar aynı yerde oturarak komşularıyla uzun süreli ilişkiler geliştirdi.\" (Kaynak: Andrew Sherratt, Plough and Pastoralism, Cambridge, 1981 – uyarlanmıştır)</i><br><br><b>Metne göre tarımın yerleşik düzene geçişe katkısını sağlayan temel etken nedir?</b>",
        secenekler: [
            "A) İnsanların denizi keşfetmesi",
            "B) Hayvanların evcilleştirilmesi",
            "C) Yiyecek için göç etme zorunluluğunun ortadan kalkması",
            "D) Taş aletlerin gelişmesi",
            "E) Yazının icadı"
        ],
        cevap: "C) Yiyecek için göç etme zorunluluğunun ortadan kalkması",
        aciklama: "Metin, çiftçiliğin yiyecek arayışına dayalı göçü sona erdirdiğini, bunun da kalıcı yerleşimi mümkün kıldığını belirtmektedir. Hayvan evcilleştirme, taş aletler ve yazı gibi unsurlar metinde yer almamaktadır."
    },
    {
        soru: "<i>\"Sümer yazıtlarından biri şöyle der: Bugün çiftçi, tarlasının sürülmesini başlatmaktadır. Toprak yumuşatılmak zorundadır; bu iş öküz ve sabanla yapılır. Çiftçi, tohum saçmadan önce sulama kanalının açık olduğunu kontrol eder.\" (Kaynak: Thorkild Jacobsen, Çiftçinin Almanağı, MÖ yaklaşık 1700 – uyarlanmış Türkçe çeviri)</i><br><br><b>Bu Sümer yazıtı aşağıdaki hangi sonuca en güçlü kanıt oluşturur?</b>",
        secenekler: [
            "A) Sümerlerin denizcilikle geçimini sağladığına",
            "B) Tarımın hayvan gücü ve sulama altyapısı gerektirdiğine",
            "C) Sümer toplumunun göçebe bir yapıya sahip olduğuna",
            "D) Yazının yalnızca din adamları tarafından kullanıldığına",
            "E) Tahılın Sümerlerde icat edildiğine"
        ],
        cevap: "B) Tarımın hayvan gücü ve sulama altyapısı gerektirdiğine",
        aciklama: "Yazıtta öküz, saban ve sulama kanalı birlikte zikredilmektedir. Bu durum Sümer tarımının hem hayvan gücüne hem de suni sulama altyapısına dayandığını göstermektedir. Diğer seçenekler metinle desteklenmemektedir."
    },
    {
        soru: "<i>\"Çanak çömleğin bulunmasıyla birlikte insanlar fazla yiyeceği saklayabilir hâle geldi. Artık bir hasattan elde edilen tahıllar, gelecek yıl ekilmek veya açlık döneminde tüketilmek üzere kil kaplarda muhafaza ediliyordu.\" (Kaynak: Gordon Childe, Tarihte Ne Oldu?, 1936, s. 47 – uyarlanmıştır)</i><br><br><b>Metinden çıkarılabilecek en doğru sonuç hangisidir?</b>",
        secenekler: [
            "A) Çanak çömlek, tarımın icadından önce gelişmiştir",
            "B) Depolama teknolojisi toplumların geleceğe hazırlanmasını kolaylaştırmıştır",
            "C) Kil kaplar yalnızca dini törenlerde kullanılmıştır",
            "D) Depolama, ticaretin gelişmesine zarar vermiştir",
            "E) Tahıl üretimi çanak çömlek ihtiyacını ortadan kaldırmıştır"
        ],
        cevap: "B) Depolama teknolojisi toplumların geleceğe hazırlanmasını kolaylaştırmıştır",
        aciklama: "Metin, çanak çömleğin fazla ürünün depolanmasına imkân tanıdığını, bunun da gelecek sezon tohumluk tahıl saklamayı ve açlık dönemlerinde yedek erzak bulundurmayı mümkün kıldığını anlatmaktadır. Bu bilgi, depolama teknolojisinin toplumların öngörülü davranmasını kolaylaştırdığı sonucunu destekler."
    },
    {
        soru: "<i>\"İklim değişikliğiyle birlikte savana alanları küçülünce Nil kıyılarına sığınan insanlar, nehrin her yıl yaptığı taşkının bıraktığı siyah çamura tohum ekmeye başladılar. Nil’in bu yillik hediyesi, Misir uygarliginin temelini olusturdu.\" (Kaynak: John Romer, A History of Ancient Egypt, 2012, s. 29 – uyarlanmıştır)</i><br><br><b>Bu metne göre Mısır’da tarımın gelişmesinde hangi doğal faktör belirleyici olmuştur?</b>",
        secenekler: [
            "A) Güçlü ticaret rüzgârları",
            "B) Geniş çöl topraklarının varlığı",
            "C) Nil Nehri’nin düzenli taşkınlarıyla bıraktığı verimli çamur",
            "D) Akdeniz’e kıyı olmanın sağladığı iklim avantajı",
            "E) Yüksek dağlardan inen kar suları"
        ],
        cevap: "C) Nil Nehri’nin düzenli taşkınlarıyla bıraktığı verimli çamur",
        aciklama: "Metin, Nil’in taşkınlarının bıraktığı siyah çamurun tohumlar için son derece verimli bir zemin oluşturduğunu ve bunun Mısır uygarlığının temelini attığını belirtmektedir."
    },
    {
        soru: "<i>\"Mezopotamya’da saban, çiftçilik tarihinin en devrimci aracı olarak kabul edilmektedir. Bugün basit görünen bu alet, toprağı daha derinden işleyerek tohumun çimlenmesi için ideal bir ortam hazırlamaktaydı. Sabandan önce insanlar toprağa yalnızca çubukla delik açabiliyordu.\" (Kaynak: MEB 9. Sınıf Tarih Ders Kitabı, 2023, s. 38 – uyarlanmıştır)</i><br><br><b>Metne göre sabanın en önemli katkısı nedir?</b>",
        secenekler: [
            "A) Toprağı daha derinden işleyerek tohum için uygun ortam hazırlaması",
            "B) Hayvanları evcilleştirmesi",
            "C) Sulama kanallarını açması",
            "D) Tohumun depolanmasını sağlaması",
            "E) Taşımacılığı kolaylaştırması"
        ],
        cevap: "A) Toprağı daha derinden işleyerek tohum için uygun ortam hazırlaması",
        aciklama: "Metin doğrudan 'toprağı daha derinden işleyerek tohumun çimlenmesi için ideal bir ortam hazırlamak' ifadesini kullanmaktadır. Diğer seçenekler metinde yer almayan işlevlere işaret etmektedir."
    },
    {
        soru: "<i>\"Tarım toplumlarında artı ürün ortaya çıkınca herkese yetecek kadar yiyecek üretmek için tüm nüfusun tarlada çalışması zorunluluğu ortadan kalktı. Böylece bazı insanlar başka işlerle uğraşabildi: kap kacak yapan çömlekçiler, silah döken demirciler, tanrıya dua eden din adamları ortaya çıktı.\" (Kaynak: Bruce Trigger, A History of Archaeological Thought, 2006, s. 102 – uyarlanmıştır)</i><br><br><b>Bu metne göre artı ürünün toplumsal sonuçlarından hangisi çıkarılabilir?</b>",
        secenekler: [
            "A) Tarım nüfusun tamamını tarlada çalışmaya zorlamıştır",
            "B) Artı ürün, toplumda iş bölümünün ve uzmanlaşmanın doğmasını sağlamıştır",
            "C) Din adamları tarım öncesinde de vardı",
            "D) Demirciler tarımı geliştiren temel aktörlerdir",
            "E) Artı ürün yalnızca ticaret için kullanılmıştır"
        ],
        cevap: "B) Artı ürün, toplumda iş bölümünün ve uzmanlaşmanın doğmasını sağlamıştır",
        aciklama: "Metin, artı ürünün herkesin tarımla geçinmek zorunda kalmadığı bir düzen yarattığını ve bunun çömlekçi, demirci, din adamı gibi uzmanlaşmış mesleklerin doğmasını sağladığını açıkça ifade etmektedir. Bu durum toplumsal iş bölümünün temelini oluşturur."
    },
    {
        soru: "<i>\"Sümer şehrinde bir tüccar konuşuyor: Geçen yıl Ur tapınağına üç sepet arpa borçluydum. Tanrının hizmetçisi olan kâtipler bu borcu kil tablet üzerine yazdı. Hasat iyi olunca borcumu ödedim; kâtip tabletin üzerine çizgi çekerek borcu kapattı.\" (Kaynak: Marc Van De Mieroop, A History of the Ancient Near East, 2004, s. 56 – uyarlanmıştır)</i><br><br><b>Bu metin, tarımın Mezopotamya medeniyetine kazandırdığı hangi gelişmeyi örneklemektedir?</b>",
        secenekler: [
            "A) Deniz ticaretinin başlamasını",
            "B) Ticari kayıt tutma ve ekonomik borç ilişkisinin yazıyla belgelenmesini",
            "C) Tapınakların yalnızca din işleviyle sınırlı olduğunu",
            "D) Kâtiplerin tarım yapmadığını",
            "E) Arpa borcunun savaşın sonucu olduğunu"
        ],
        cevap: "B) Ticari kayıt tutma ve ekonomik borç ilişkisinin yazıyla belgelenmesini",
        aciklama: "Metin, tarım ürünleri üzerinden borç ilişkisinin kil tablet kaydıyla yönetildiğini göstermektedir. Bu örnek, tarıma dayalı artı ürünün ticareti, borç ilişkilerini ve nihayetinde erken yazılı belgeleri nasıl doğurduğunu somutlaştırmaktadır."
    },
    {
        soru: "<i>\"Mısır’da her yıl düzenli olarak yapılan Nil taşkınından önce köylüler tarlalarının sınırlarını belirleyen sınır taşlarını kaldırmak zorundaydı. Taşkın geçince devlet memurları tarlalar arasındaki sınırları yeniden çizmek ve haritalarını çizmek için geometri bilgisini kullanmak durumundaydı.\" (Kaynak: Herodot, Tarih, Kitap II, MÖ 5. yüzyıl – uyarlanmıştır)</i><br><br><b>Bu metne göre Mısır’da geometri bilgisinin gelişmesinin temel nedeni nedir?</b>",
        secenekler: [
            "A) Firavunların saraylarını süslemek istemesi",
            "B) Nil taşkınlarının yol açtığı tarla sınırlarının yeniden belirlenmesi zorunluluğu",
            "C) Dini metinlerin hesaplanması ihtiyacı",
            "D) Ticaret gemilerinin rota hesaplaması",
            "E) Savaş alanlarının planlanması"
        ],
        cevap: "B) Nil taşkınlarının yol açtığı tarla sınırlarının yeniden belirlenmesi zorunluluğu",
        aciklama: "Herodot’un aktarımına göre her yıl taşkın sonrasında tarla sınırlarını yeniden belirlemek zorunluluğu, Mısır’da geometrinin pratik bir ihtiyaçtan doğmasına neden olmuştur. Bu, tarımsal ihtiyaçların bilimsel gelişmeleri nasıl tetiklediğinin klasik bir örneğidir."
    },
    {
        soru: "<i>\"Çatalhöyük kazılarında bulunan duvar resimleri, dönemin insanlarının vahşi boğalarla yaptıkları ritüel törenlerini göstermektedir. Ancak kazıcılar aynı tabakada evcil sığır kemikleri, tahıl depolama kapları ve obsidyen bıçaklar da buldular. Bu bulgular, Çatalhöyük sakinlerinin hem avcı-toplayıcı hem de ilk çiftçi özelliklerini aynı anda taşıdığına işaret etmektedir.\" (Kaynak: Ian Hodder, Çatalhöyük: Leoparın Hikâyesi, 2006, s. 145 – uyarlanmıştır)</i><br><br><b>Bu arkeolojik bulgular ışığında Çatalhöyük hakkında en geçerli yorum hangisidir?</b>",
        secenekler: [
            "A) Çatalhöyük tamamen avcı-toplayıcı bir toplumdu",
            "B) Çatalhöyük tarımla ilgisi olmayan bir ritüel merkezi görevi görüyordu",
            "C) Çatalhöyük, avcı-toplayıcılıktan tarım toplumuna geçişin bir ara evresini temsil etmektedir",
            "D) Çatalhöyük’te yalnızca hayvancılık yapılmaktaydı",
            "E) Çatalhöyük’ün tarihi MÖ 10.000'den öncesine dayanmaktadır"
        ],
        cevap: "C) Çatalhöyük, avcı-toplayıcılıktan tarım toplumuna geçişin bir ara evresini temsil etmektedir",
        aciklama: "Aynı katmanda hem avcılık ritüellerini çağrıştıran duvar resimleri hem de evcil hayvan kemikleri ve tahıl kaplarının birlikte bulunması, toplumun geçiş evresinde olduğunu göstermektedir. Tek bir ekonomik modele indirgemek (A, B, D) mevcut kanıtları yok saymak anlamına gelir."
    },
    {
        soru: "<i>\"Hammurabi Kanunları'nın 48. maddesi şöyledir: Eğer bir adam borç almış ve ardından fırtına tarlasını yerle bir etmiş ya da hasat yapılamamışsa, o yıl için alacaklısına hiçbir tahıl ödemesi yapmak zorunda değildir.\" (Kaynak: Hammurabi Kanunları, MÖ yaklaşık 1754, Madde 48 – çeviri uyarlanmıştır)</i><br><br><b>Bu yasa maddesi, Mezopotamya’da tarımın toplumsal düzenle ilişkisi hakkında ne söylemektedir?</b>",
        secenekler: [
            "A) Mezopotamya’da devlet tarımsal riskleri paylaşan bir hukuki sistem kurmuştur",
            "B) Mezopotamya’da borç, yalnızca din adamları arasında geçerliydi",
            "C) Fırtınalar Mezopotamya’da yalnızca kentlerde hasar verirdi",
            "D) Hammurabi, tarım yapılmasını yasaklamıştır",
            "E) Bu madde, zenginlerin yoksulları sömürmesine olanak tanımaktadır"
        ],
        cevap: "A) Mezopotamya’da devlet tarımsal riskleri paylaşan bir hukuki sistem kurmuştur",
        aciklama: "Kanunun 48. maddesi, doğal afet durumunda borçlunun ödeme yükümlülüğünü askıya almaktadır. Bu hüküm, devletin tarımsal riski hukuki güvence aracılığıyla düzenlediğine, yani tarımın yalnızca ekonomik değil hukuki düzenin de temelini oluşturduğuna işaret etmektedir."
    },
    {
        soru: "<i>\"Erken Neolitik döneme ait Mezopotamya köylerinde yapılan iskelet analizleri ilginç bir tablo ortaya koymaktadır: Tarım öncesi avcı-toplayıcılara kıyasla erken çiftçilerde diş çürükleri daha fazla, kemik yoğunluğu ise daha düşüktür. Öte yandan aynı dönemde nüfus artışı belgelenmiştir.\" (Kaynak: Mark Nathan Cohen, Health and the Rise of Civilization, 1989, s. 116 – uyarlanmıştır)</i><br><br><b>Bu arkeolojik veriler tarım toplumu hakkında hangi çelişkili durumu ortaya koymaktadır?</b>",
        secenekler: [
            "A) Tarım hem refahı hem de nüfusu aynı anda düşürmüştür",
            "B) Tarım bireysel sağlığı olumsuz etkilerken toplam nüfus artışına yol açmıştır",
            "C) Avcı-toplayıcılar tarımcılardan daha kalabalık topluluklarda yaşamıştır",
            "D) Diş çürükleri tarım topluluklarında nüfusu azaltmıştır",
            "E) Tarım topluluklarında kemik yoğunluğu avcılardan yüksektir"
        ],
        cevap: "B) Tarım bireysel sağlığı olumsuz etkilerken toplam nüfus artışına yol açmıştır",
        aciklama: "Veriler paradoksal bir tablo sunar: Tarım karbonhidrat ağırlıklı beslenme nedeniyle diş çürüklüğünü artırmış, kemik yoğunluğunu düşürmüştür; yani bireysel sağlık düşmüştür. Ama aynı zamanda kalori artışı ve depolama nüfus büyümesini sağlamıştır. Bu çelişki, tarımın insanlık için hem kazanım hem de bedel olduğunu gösterir."
    },
    {
        soru: "<i>\"Antik Yunan tarihçisi Diodoros Siculus şöyle yazmıştır: Mısırlılar, Osiris tanrısının insanlara buğday ve arpa ekmeyi öğrettiğine inanırlardı; zira bu tahıllar tanrının armağanı olmadan toprakta kendiliklerinden bitmezdi. Osiris’e tapınma, hasat mevsiminin başında büyük törenlerle kutlanırdı.\" (Kaynak: Diodoros Siculus, Bibliotheca historica, MÖ 1. yüzyıl – uyarlanmıştır)</i><br><br><b>Bu metin, Tarım Devrimi’nin Mısır dini üzerindeki etkisi açısından nasıl yorumlanabilir?</b>",
        secenekler: [
            "A) Mısırlılar tarımı gereksiz bir uğraş olarak gördüğünden dini törenlerde hiç yer vermedi",
            "B) Tarımın doğaya bağımlılığı, toplumları doğa güçlerini tanrısallaştırmaya yöneltti",
            "C) Mısır’da yalnızca tahıl tanrısına tapılıyordu",
            "D) Osiris kültü tarımdan bağımsız olarak gelişmiştir",
            "E) Hasat törenleri yalnızca siyasi amaçlarla düzenleniyordu"
        ],
        cevap: "B) Tarımın doğaya bağımlılığı, toplumları doğa güçlerini tanrısallaştırmaya yöneltti",
        aciklama: "Mısırlıların tarımı bir tanrının hediyesi olarak yorumlaması ve hasat törenlerini dini ritüellerle kutlaması, tarıma bağımlı toplumların doğa güçlerini (nehir, yağmur, bereket) tanrısallaştırma eğilimini yansıtmaktadır. Bu örüntü birçok antik uygarlıkta tekrarlanır."
    },
    {
        soru: "<i>\"Sümer şehir devletleri, tapınakların etrafında örgütlendi. Tapınak yalnızca bir ibadet yeri değildi; aynı zamanda tahıl ambarı, zanaatkâr atölyesi ve ticaret merkeziydi. Rahipler hem ekonomiyi hem de toplumsal düzeni idare ediyordu.\" (Kaynak: Samuel Noah Kramer, History Begins at Sumer, 1956, s. 74 – uyarlanmıştır)</i><br><br><b>Bu metne göre Sümer tapınağının çok işlevli yapısı aşağıdakilerden hangisiyle açıklanabilir?</b>",
        secenekler: [
            "A) Rahiplerin yönetim yetkisinden yoksun olmasıyla",
            "B) Tarımsal artı ürünün depolanması ve yönetilmesi ihtiyacının kurumsal yapıları dönüştürmesiyle",
            "C) Tapınakların tamamen ticari amaçla kurulmasıyla",
            "D) Şehir devletlerinin tarım yerine hayvancılığa dayanmasıyla",
            "E) Rahiplerin tüm toprak mülkiyetinden vazgeçmesiyle"
        ],
        cevap: "B) Tarımsal artı ürünün depolanması ve yönetilmesi ihtiyacının kurumsal yapıları dönüştürmesiyle",
        aciklama: "Tarımsal artı ürün, merkezi depolama ve dağıtımı gerektirdi; tapınak bu işlevi üstlendi. Böylece dini kurumlar ekonomik ve idari aygıta dönüştü. Bu süreç, tarım üretiminin kurumsal yapıları nasıl şekillendirdiğinin somut göstergesidir."
    },
    {
        soru: "<i>\"Yazar Ursula Le Guin, kurgusal romanı The Word for World is Forest'te şöyle düşündürür: Toprağı sabanla yarmak, ona ne zaman meyve vereceğini söylemek, tabiatın döngüsüne müdahale etmektir. Başlangıçta bu bir ilerleme gibi görünür; ama aynı zamanda insanın doğadan uzaklaşmasının başlangıcıdır.\" (Kaynak: Ursula K. Le Guin, The Word for World is Forest, 1972 – uyarlanmış çeviri)</i><br><br><b>Le Guin’in bu metaforik ifadesi, tarım konusunda hangi tarih felsefesi sorusunu gündeme getirmektedir?</b>",
        secenekler: [
            "A) Tarım teknolojik açıdan mümkün müdür?",
            "B) Tarım, insan ile doğa arasındaki ilişkiyi kökten değiştiren bir müdahale midir?",
            "C) Tarım hangi yüzyılda icat edilmiştir?",
            "D) Saban mı yoksa orak mı daha etkili bir aletttir?",
            "E) Tarım hangi toplumda daha hızlı yayılmıştır?"
        ],
        cevap: "B) Tarım, insan ile doğa arasındaki ilişkiyi kökten değiştiren bir müdahale midir?",
        aciklama: "Le Guin, tarımı basit bir teknik ilerleme olarak değil, insanın doğa karşısındaki konumunu dönüştüren bir kırılma noktası olarak sunmaktadır. Bu felsefi yaklaşım, tarihçilerin 'Tarım Devrimi insan ile doğa arasındaki dengeyi nasıl değiştirdi?' sorusunu sormaya yöneltir."
    },
    {
        soru: "<i>\"MÖ 3000 civarında Mısır'da piramit inşaatlarında çalışan işçilere günlük arpa çorbası, ekmek ve soğan verildiğini gösteren yazıtlar bulunmuştur. Gıza platosu yakınlarındaki mezar yazıtlarında bu işçilerin devlet tarafından örgütlendiği ve ücretlerini yiyecek olarak aldıkları belirtilmektedir.\" (Kaynak: Mark Lehner, The Complete Pyramids, 1997, s. 224 – uyarlanmıştır)</i><br><br><b>Bu bulgu, tarımın Eski Mısır devlet organizasyonuna katkısı açısından ne anlama gelmektedir?</b>",
        secenekler: [
            "A) Mısır piramitleri köle emeğiyle değil, yiyecekle ödüllendirilen örgütlü işgücüyle inşa edilmiştir",
            "B) Mısır’da para ekonomisi tarımdan önce gelişmişti",
            "C) Piramitler tarımsal ürün yetersizliğine rağmen inşa edilmiştir",
            "D) Devlet işçilere yalnızca kuyumculuk ürünleri ödemiştir",
            "E) Gıza piramitleri, özel tüccarlar tarafından finanse edilmiştir"
        ],
        cevap: "A) Mısır piramitleri köle emeğiyle değil, yiyecekle ödüllendirilen örgütlü işgücüyle inşa edilmiştir",
        aciklama: "Yazıtlar, devletin tarımsal artı ürünü (arpa, ekmek, soğan) işgücünü örgütlemek ve ödüllendirmek için kullandığını göstermektedir. Bu, tarımsal üretimin devlet bürokratik kapasitesini doğrudan beslediğinin kanıtıdır. Köle emeği tezi bugün büyük ölçüde terk edilmiştir."
    },
    {
        soru: "<i>\"Orta Anadolu'daki Neolitik bir köyde bir kadının sabah erken saatte tahıl öğütme taşı başında oturduğunu hayal edin. Bugün onu gözlemlediğinizde görürsünüz ki elleri sertleşmiş, beli bükülmüş. Avcı-toplayıcı bir toplumun kadını günde 3–4 saat çalışırken, bu kadın tahıl işleme, ekmek pişirme ve sulama kanallarını temizleme gibi işlerle günde 8–10 saat geçirmektedir.\" (Kaynak: Yuval Noah Harari, Sapiens: İnsan Türünün Kısa Tarihi, 2011, s. 91 – uyarlanmıştır)</i><br><br><b>Bu metin, Tarım Devrimi hakkında hangi eleştirel yorumu desteklemektedir?</b>",
        secenekler: [
            "A) Tarım, kadınların çalışma süresini azaltmıştır",
            "B) Tarım, bireysel insan üzerindeki iş yükünü artırmış; kolektif gücü artırırken bireyi yormuştur",
            "C) Tarımda yalnızca erkekler çalışmıştır",
            "D) Neolitik dönemde tahıl ekimi bilinmiyordu",
            "E) Avcı-toplayıcılar tarımcılardan daha az verimli bir yaşam sürmüştür"
        ],
        cevap: "B) Tarım, bireysel insan üzerindeki iş yükünü artırmış; kolektif gücü artırırken bireyi yormuştur",
        aciklama: "Harari’nin bu pasajı, Tarım Devrimi’nin toplumlar için kazanım, bireyler için ise ağır bir bedel anlamına geldiğini ortaya koymaktadır. Avcı-toplayıcının günlük 3–4 saatlik iş yüküne karşın çiftçinin 8–10 saatlik çalışması, 'ilerleme' söylemini sorgulatmaktadır."
    },
    {
        soru: "<i>\"İndüs Vadisi Uygarlığı'nda yapılan arkeolojik kazılarda dikkat çekici bir bulgu elde edildi: Kentlerde belirgin bir saray ya da tapınak kompleksi yoktur, ancak tahıl ambarları şehrin en merkezi ve büyük yapıları arasındadır. Bu durum, İndüs şehirlerinde gücün farklı biçimde örgütlendiğine işaret etmektedir.\" (Kaynak: Rita Wright, The Ancient Indus: Urbanism, Economy and Society, 2010, s. 198 – uyarlanmıştır)</i><br><br><b>Bu bulgu, diğer erken uygarlıklarla kıyaslandığında İndüs Vadisi hakkında ne söylemektedir?</b>",
        secenekler: [
            "A) İndüs şehirlerinde tarım yapılmıyordu",
            "B) İndüs Vadisi’nde gıda dağıtımını kontrol eden kurumlar, dini ya da siyasi iktidarın önüne geçmiştir",
            "C) İndüs şehirleri tamamen tarım dışı ekonomiye dayanmaktaydı",
            "D) Tahıl ambarları İndüs’te yalnızca mezarlık amacıyla kullanılıyordu",
            "E) İndüs Vadisi’nde hiçbir zaman merkezi yönetim oluşmamıştır"
        ],
        cevap: "B) İndüs Vadisi’nde gıda dağıtımını kontrol eden kurumlar, dini ya da siyasi iktidarın önüne geçmiştir",
        aciklama: "Mısır ve Mezopotamya’da güç saraylarda ve tapınaklarda toplanırken, İndüs’te gücün simgesi tahıl ambarıdır. Bu, tarımsal üretimin farklı toplumlarda farklı iktidar yapıları yaratabileceğini gösterir; bağımsız analiz yeteneği gerektiren bir karşılaştırmadır."
    },
    {
        soru: "<i>\"Çin'in Yangzi ırmağı havzasında MÖ 7000 civarında çeltik tarımının başladığına dair kanıtlar mevcuttur. Buğday tarımından farklı olarak çeltik, su içinde yetişir; bu nedenle sulak tarla sistemi (paddy field) icat edilmek zorunda kalındı. Çeltik tarımının nüfus yoğunluğu üzerindeki etkisi buğday bölgelerinden daha güçlüydü.\" (Kaynak: Francesca Bray, The Rice Economies, 1986, s. 23 – uyarlanmıştır)</i><br><br><b>Bu metin, tarımın evrensel tek bir biçimde gelişip gelişmediği sorusuyla ilgili ne söylemektedir?</b>",
        secenekler: [
            "A) Tarım her yerde aynı teknikle uygulanmıştır",
            "B) Farklı bitki türleri, farklı tarım sistemleri ve farklı toplumsal sonuçlar doğurmuştur",
            "C) Çeltik tarımı buğday tarımından daha az önemlidir",
            "D) Çin’de tarım Mezopotamya’dan aktarılmıştır",
            "E) Su içinde yetişen tahıllar besleyici değildir"
        ],
        cevap: "B) Farklı bitki türleri, farklı tarım sistemleri ve farklı toplumsal sonuçlar doğurmuştur",
        aciklama: "Çeltik tarımının sulak tarla sistemini gerektirmesi ve yüksek nüfus yoğunluğuna yol açması, tarımsal gelişmenin coğrafyaya ve bitkiye göre farklılaştığını göstermektedir. Tarımın tek bir evrensel model izlemediğini fark etmek analitik bir beceri gerektirmektedir."
    },
    {
        soru: "<i>\"Hitit kanunlarında hayvan çalma suçu için ağır cezalar öngörülmüştür: Birinin öküzünü çalan kişi, eski kanunda on beş öküz ödeyecekti; yeni kanunda bu oran düşürülerek altıya indirildi. Ekin yakan kişi ise bir yıl köle olarak çalışacaktı.\" (Kaynak: Hitit Kanunları, MÖ 1650–1180, Maddeler 57–98 – uyarlanmıştır)</i><br><br><b>Hitit kanunlarının hayvan ve ekin korumasına bu denli önem vermesi ne hakkında bilgi vermektedir?</b>",
        secenekler: [
            "A) Hitit toplumunun ticaret yerine avcılığa dayandığı hakkında",
            "B) Tarım ve hayvancılığın Hitit ekonomisinin temelini oluşturduğu ve hukuki korumanın bu gerçeği yansıttığı hakkında",
            "C) Hukuk sisteminin dini gerekçelere dayandığı hakkında",
            "D) Hititlerde tarımın terk edildiği hakkında",
            "E) Cezaların yalnızca kölelere uygulandığı hakkında"
        ],
        cevap: "B) Tarım ve hayvancılığın Hitit ekonomisinin temelini oluşturduğu ve hukuki korumanın bu gerçeği yansıttığı hakkında",
        aciklama: "Bir toplumun hukuk sistemi, o toplumun neye değer verdiğini yansıtır. Hayvan ve ekin hırsızlığına öngörülen ağır cezalar, bu üretim araçlarının Hitit ekonomisinde ne denli hayati olduğunu göstermektedir. Bu soru, hukuku tarımsal ekonominin bir aynası olarak okumayı gerektirir."
    },
    {
        soru: "<i>\"Paleolitik insan kafatası ile erken Neolitik çiftçi kafatasları karşılaştırıldığında dikkat çekici bir fark göze çarpar: Avcı-toplayıcılarda yüz kasları daha gelişmiş ve çene kemikleri daha güçlüdür. Erken çiftçilerin öğütülmüş tahılı kolaylıkla çiğnemesi bu farka yol açmıştır.\" (Kaynak: David Perlmutter, Grain Brain, 2013, s. 48 – uyarlanmıştır)</i><br><br><b>Bu biyolojik bulgular, tarımın insan üzerindeki etkileri konusunda ne tür bir değerlendirme yapmayı gerektirir?</b>",
        secenekler: [
            "A) Tarım insanı yalnızca olumlu yönde etkilemiştir",
            "B) Tarımın biyolojik evrimi de etkilediği ve bu değişikliklerin her zaman avantajlı olmadığı değerlendirmesini",
            "C) Avcı-toplayıcıların çiftçilerden daha zeki olduğunu",
            "D) Öğütülmüş tahıl kemik yoğunluğunu artırmaktadır",
            "E) Kafatası şekli tarımın coğrafyasını belirler"
        ],
        cevap: "B) Tarımın biyolojik evrimi de etkilediği ve bu değişikliklerin her zaman avantajlı olmadığı değerlendirmesini",
        aciklama: "Kasların ve kemiklerin zayıflaması, tarımın yalnızca toplumsal ve ekonomik değil biyolojik etkileri de olduğunu ortaya koymaktadır. Bu bulgu, Tarım Devrimi’ni doğrusal bir ilerleme olarak değil çok boyutlu bir dönüşüm olarak değerlendirmeyi gerektirir."
    },
    {
        soru: "<i>\"Eski Ahit'te Yaratılış kitabında Kain ile Habil kıssası anlatılır: Çiftçi Kain topraktan ürünler sundu; çoban Habil ise sürüsünün ilk doğanlarından sundu. Tanrı Habil'in sunusunu kabul etti, Kain'inkini kabul etmedi. Bu, iki kardeş arasında kıskançlığa yol açtı.\" (Kaynak: Yaratılış 4:3–5, Kutsal Kitap – uyarlanmıştır)</i><br><br><b>Bu kutsal metin, Tarım Devrimi döneminde yaşanan toplumsal çatışma açısından nasıl sembolik okunabilir?</b>",
        secenekler: [
            "A) Çiftçiler ile çobanlar (yerleşikler ile göçebeler) arasındaki tarihsel gerilimin mitolojik bir yansıması",
            "B) Tarım ile hayvancılığın aynı anda var olamayacağını gösteren bir kanıt",
            "C) Tanrıların çiftçileri cezalandırdığına dair bir tarih belgesi",
            "D) Mezopotamya’da çiftçiliğin yasaklandığını anlatan bir kayıt",
            "E) Habil’in tarımın kurucusu olduğunun kanıtı"
        ],
        cevap: "A) Çiftçiler ile çobanlar (yerleşikler ile göçebeler) arasındaki tarihsel gerilimin mitolojik bir yansıması",
        aciklama: "Kain ile Habil kıssası, tarihçiler tarafından Yakın Doğu’da yerleşik çiftçiler ile göçebe çobanlar arasındaki tarihsel rekabet ve çatışmanın mitolojik dile getirilişi olarak yorumlanmaktadır. Bu soru metni sembolik düzeyde okuma becerisini test etmektedir."
    },
    {
        soru: "<i>\"Hintli tarih filozofu Romila Thapar şöyle yazar: Tarım, yalnızca besin üretmenin değil, zamanı kontrol etmenin de yoluydu. Ekim ve hasat mevsimleri, toplulukların takvim geliştirmesini zorunlu kıldı; böylece insanlar ilk kez zamanı ölçmeyi ve geleceği planlamayı öğrendi.\" (Kaynak: Romila Thapar, The Penguin History of Early India, 2002, s. 73 – uyarlanmıştır)</i><br><br><b>Thapar’ın argümanına göre tarımın zihinsel/kültürel etkileri arasında hangisi ön plana çıkmaktadır?</b>",
        secenekler: [
            "A) Tarım insanları okuryazar yaptı",
            "B) Tarım, zaman kavramının ve takvim sisteminin gelişmesini zorunlu kılarak insan düşüncesini dönüştürdü",
            "C) Tarım kutsal metin yazımını ortadan kaldırdı",
            "D) Tarım sayesinde insanlar geçmişi unuttular",
            "E) Takvim yalnızca dini kurumlar tarafından geliştirildi"
        ],
        cevap: "B) Tarım, zaman kavramının ve takvim sisteminin gelişmesini zorunlu kılarak insan düşüncesini dönüştürdü",
        aciklama: "Thapar’ın argümanı, tarımın insan zihnini yalnızca besleme değil, zamana hâkim olma biçiminde de dönüştürdüğüdür. Ekim-hasat döngüsü takvim bilimini zorunlu kılmış; bu da soyut düşünme ve planlama kapasitesini geliştirmiştir."
    },
    {
        soru: "<i>\"Arkeolog James Scott, Against the Grain (2017) adlı eserinde şu ilginç tezi öne sürer: İlk devletler, tarımın olduğu yerde değil, tahılın olduğu yerde kuruldu. Zira tahıl görünür, taşınabilir ve sayılabilirdir — devlet tarafından vergilendirmek için idealdir. Baklagiller ya da kök sebzeler gibi toprak altında büyüyen ya da farklı zamanlarda hasat edilen ürünleri vergilendirmek çok daha güçtür.\" (Kaynak: James C. Scott, Against the Grain: A Deep History of the Earliest States, 2017, s. 128)</i><br><br><b>Scott’ın argümanını doğrulayan hangi tarihsel örüntü gözlemlenebilir?</b>",
        secenekler: [
            "A) İlk devletlerin yüksek dağlık bölgelerde kurulmuş olması",
            "B) İlk büyük devletlerin (Sümer, Mısır, Harappa) buğday, arpa ya da pirinç üretim havzalarında yoğunlaşması",
            "C) Devletlerin meyve bahçeciliğini tercih eden bölgeleri yönetmekten kaçınması",
            "D) Tahıl vergilendirilmesinin tarihte hiçbir örnekte uygulanmaması",
            "E) Baklagil yetiştiriciliğinin her zaman devlet dışında kaldığı"
        ],
        cevap: "B) İlk büyük devletlerin (Sümer, Mısır, Harappa) buğday, arpa ya da pirinç üretim havzalarında yoğunlaşması",
        aciklama: "Scott’ın 'tahıl devlet kurar' tezi, Mezopotamya (buğday-arpa), Mısır (buğday), Çin (pirinç-darı) ve İndüs (buğday) gibi erken devletlerin tamamının tahıl üretim havzalarında kurulmuş olmasıyla desteklenmektedir. Bu soru, verilen tezi tarihsel verilerle test etmeyi gerektirdiğinden zor düzeydedir."
    },
    {
        soru: "<i>\"MÖ 6200 yıllarında Çatalhöyük ve çevre bölgelerde yaşanan ani soğuma (8.2 ka olayı) hayvancılık ve çiftçi topluluklarının dönüşümünü hızlandırmış olabilir. Artan iklim oynaklığı, artı ürünü tehdit edince yerleşik topluluklar ya daha geniş sulama sistemleri kurmak ya da farklı alanlara dağılmak durumunda kaldı. Bu baskı, erken örgütlenme biçimlerini ve hiyerarşi oluşumunu hızlandırmış olabilir.\" (Kaynak: Nick Brooks, Cultural Responses to Holocene Climate Change, 2006, Journal of World Prehistory)</i><br><br><b>Bu hipotez kabul edilirse, erken devlet ve hiyerarşi oluşumu sürecinde hangi faktörün belirleyici olduğu öne çıkar?</b>",
        secenekler: [
            "A) İnsan doğasındaki güç hırsı",
            "B) Dini inançların toplumu birleştirmesi",
            "C) İklim baskısının işbirliği ve merkezi örgütlenmeyi zorunlu kılması",
            "D) Yeni silah teknolojilerinin güçlü liderlere avantaj sağlaması",
            "E) Yazının hiyerarşiyi meşrulaştırması"
        ],
        cevap: "C) İklim baskısının işbirliği ve merkezi örgütlenmeyi zorunlu kılması",
        aciklama: "Hipotez, iklim baskısının toplulukları daha geniş sulama sistemleri kurmaya ya da göç etmeye zorladığını öne sürmektedir. Büyük altyapı projeleri merkezi koordinasyonu gerektirdiğinden bu baskı, erken hiyerarşi ve devlet oluşumunu hızlandırmış olabilir. 'Hydraulic hypothesis' (hidrolik uygarlık tezi) olarak da bilinen bu yaklaşım, tarihçiler arasında tartışmalıdır."
    },
    {
        soru: "<i>\"Eski Sümer'de \"lugal\" (kral) sözcüğünün kökeni \"büyük adam\" anlamına gelir. Erken Hanedanlık döneminde lugallar, önce sulama kanalı yöneticisi ya da tahıl ambarı denetçisi iken zamanla askeri komutan ve din adamı rolünü de üstlendi. İlk kral unvanları, tahıl hasatlarının kayıtlarını tutan kil tabletlerde görünür.\" (Kaynak: Thorkild Jacobsen, The Sumerian King List, 1939, s. 168 – uyarlanmıştır)</i><br><br><b>Bu bilgilere dayanarak erken Sümer siyasi iktidarının kökeni hakkında hangi bütünleşik yorum yapılabilir?</b>",
        secenekler: [
            "A) Siyasi iktidar önce din alanında ortaya çıkmış ve sonra tarımı denetim altına almıştır",
            "B) Siyasi iktidar tarımsal kaynakları (su, tahıl) yönetme işlevinden doğmuş ve zamanla çok işlevli hâle gelmiştir",
            "C) Lugal unvanı doğrudan askeri zaferden kaynaklanmaktadır",
            "D) Tahıl kayıtları tutmak siyasi güç kazandırmamıştır",
            "E) Erken Sümer’de tarım devlet kontrolü dışındaydı"
        ],
        cevap: "B) Siyasi iktidar tarımsal kaynakları (su, tahıl) yönetme işlevinden doğmuş ve zamanla çok işlevli hâle gelmiştir",
        aciklama: "Kanıtlar şu zinciri göstermektedir: Sulama yöneticisi → Tahıl denetçisi → Kral. Bu, siyasi iktidarın kaynağının tarımsal kaynakları kontrol etme işlevi olduğunu ortaya koymaktadır. İktidar zamanla askeri ve dini boyutlar da kazanmış, ancak temeli tarımsal yönetimdir. Bu soruyu yanıtlamak için siyasi iktidarın kökeni üzerine bütünleşik bir çıkarım yapabilmek gerekmektedir."
    },
    {
        soru: "<i>\"Arkeolog Timothy Earle, Eski Çağ'da erken şeflik (chiefdom) aşamasını incelerken şunu saptar: Siyasi otorite, prestij mallarının (bakır, obsidyen, deniz kabuğu) dağıtımını değil, önce tahıl depolama ve sulama altyapısının denetimini elinde bulunduran kişilere aitti. Yeniden dağıtım ekonomisi, tarımsal artı ürünü kim depolayıp dağıtırsa onun liderliğini pekiştiriyordu.\" (Kaynak: Timothy Earle, How Chiefs Come to Power, 1997, s. 67 – uyarlanmıştır)</i><br><br><b>Earle’ün tezi ile Marxist tarih anlayışı arasında kurulabilecek ilişki hangisidir?</b>",
        secenekler: [
            "A) Her ikisi de üretim araçları üzerindeki denetimin siyasi iktidara yol açtığını savunur",
            "B) Earle devleti dini ideolojiye bağlarken Marx bunu ekonomiye bağlar",
            "C) Earle siyasi iktidarı coğrafyaya bağlarken Marx onu sınıf çatışmasına bağlar",
            "D) İkisi de tarımı iktidar analizinin dışında tutar",
            "E) Earle tahılı prestij mallarına tercih ederken Marx prestij mallarına öncelik tanır"
        ],
        cevap: "A) Her ikisi de üretim araçları üzerindeki denetimin siyasi iktidara yol açtığını savunur",
        aciklama: "Earle, tarımsal artı ürünü (üretim aracı) kontrol edenin siyasi lider olduğunu savunmaktadır. Bu, Marx’ın 'üretim araçları üzerindeki mülkiyet toplumsal iktidarı belirler' teziyle örtüşmektedir. Bu soru, iki farklı teorik çerçeveyi karşılaştırma ve analiz etme yeteneği gerektirdiğinden zor düzeydedir."
    },
    {
        soru: "<i>\"Modern bir tarihçi şöyle yazar: Tarım Devrimi'nden sonra insanlığın büyük çoğunluğu daha sert, daha monoton ve daha kısıtlı bir hayat yaşamaya başladı. Onları ayakta tutan şey daha iyi bir beslenme değil, toprağa, krala ve tanrıya boyun eğmeyi meşrulaştıran ideolojiydi. Tahılın lezzetli olması, hiyerarşinin dayatıldığı gerçeğini gizleyen bir tatlıydı.\" (Kaynak: Yuval Noah Harari, Sapiens: İnsan Türünün Kısa Tarihi, 2011, s. 98–99 – uyarlanmıştır)</i><br><br><b>Harari’nin bu yorumunu destekleyen ve ona itiraz eden argümanlar bir arada değerlendirildiğinde hangi sentez yapılabilir?</b>",
        secenekler: [
            "A) Tarım hem bireysel refahı hem de eşitliği artırmıştır; Harari yanılmaktadır",
            "B) Tarım bireysel özgürlüğü kısıtlarken toplam nüfusu ve uygarlık birikimini artırmıştır; bu nedenle değerlendirme hangi ölçüte göre yapıldığına bağlıdır",
            "C) Tarım yalnızca egemenlerin çıkarına yaramış, toplumun tamamı zarar görmüştür",
            "D) Harari’nin iddiası arkeolojik kanıtlarla tamamen çelişmektedir",
            "E) İdeoloji, tarımsal toplumda hiçbir rol oynamaz"
        ],
        cevap: "B) Tarım bireysel özgürlüğü kısıtlarken toplam nüfusu ve uygarlık birikimini artırmıştır; bu nedenle değerlendirme hangi ölçüte göre yapıldığına bağlıdır",
        aciklama: "Harari’nin eleştirisi bireysel bakış açısından güçlüdür: bireysel sağlık geriledi, çalışma saatleri arttı, hiyerarşi dayatıldı. Ancak toplumsal düzeyde uygarlık, bilim, sanat ve nüfus büyüdü. Bu zıtlık 'ilerleme nedir?' sorusunu farklı ölçütlere göre farklı yanıtlar doğurduğunu göstermektedir. Bu soru karşıt argümanları sentezleme yeteneği gerektirdiğinden zor düzeydedir."
    },
    {
        soru: "<i>\"Tarihçi Karl Wittfogel, Doğu Despotizmi (1957) adlı eserinde şunu savunur: Büyük ölçekli sulama altyapısı, zorunlu olarak güçlü merkezi devletler doğurur. Zira kanalların inşası ve bakımı, geniş kalabalıkları koordine edebilecek ve zorla çalıştırabilecek bir otorite gerektirir. Nil, Dicle-Fırat ve Sarı Irmak havzalarındaki despotik devletler bu tezin kanıtıdır.\" (Kaynak: Karl A. Wittfogel, Oriental Despotism, 1957, s. 18 – uyarlanmıştır)</i><br><br><b>Wittfogel’in 'hidrolik despotizm' tezine yönelik en güçlü karşı argüman hangisi olabilir?</b>",
        secenekler: [
            "A) Sulama kanalları yalnızca küçük köylerde inşa edilmiştir",
            "B) İndüs Vadisi gibi büyük sulama altyapısına sahip bazı toplumların merkezi despotik devlet yapısından yoksun görünmesi",
            "C) Nil havzasında hiçbir zaman büyük sulama altyapısı yapılmamış olması",
            "D) Çin’de sulama hiçbir zaman devlet tarafından yönetilmemiştir",
            "E) Wittfogel’in eserinin çevrilmemiş olması"
        ],
        cevap: "B) İndüs Vadisi gibi büyük sulama altyapısına sahip bazı toplumların merkezi despotik devlet yapısından yoksun görünmesi",
        aciklama: "İndüs Vadisi Uygarlığı, gelişmiş sulama altyapısına sahipken net bir saray/merkezi despotizm kanıtından yoksundur. Bu, 'sulama → despotizm' bağıntısının evrensel olmadığını gösterir. Wittfogel’in tezi aşırı genelleyicidir; sulama gerekli ama yeterli koşul değildir. Bu soru teorik teze karşı-örnek bulma yeteneği gerektirdiğinden zor düzeydedir."
    },
    {
        soru: "<i>\"Sümer mitolojisinde Enkidu figürü son derece ilgi çekicidir: Başta vahşi bir yaratık olan Enkidu, tanrılar tarafından yaratılmış ve hayvanlarla birlikte yaşamaktaydı. Bir rahibe ile tanışmasının ardından ekmek yemeyi ve bira içmeyi öğrendi; hayvanlardan uzaklaştı ve şehre yerleşti. Antik Sümer şairi şöyle yazar: Enkidu artık bir insandı.\" (Kaynak: Gılgamış Destanı, Tablet I – uyarlanmış Türkçe çeviri, MÖ yaklaşık 2100)</i><br><br><b>Gılgamış Destanı’ndaki Enkidu’nun dönüşümü, Sümer uygarlığının Tarım Devrimi’ni nasıl algıladığını yorumlamak açısından ne anlama gelir?</b>",
        secenekler: [
            "A) Sümerliler tarımı gereksiz bir pratik olarak değerlendirmiştir",
            "B) Ekmek ve bira — tarımsal ürünler — uygarlığın ve insanlığın simgesi olarak kurgulanmıştır; doğadan kopuş vahşilikten insanlığa geçişin metaforu sayılmıştır",
            "C) Enkidu’nun hikâyesi yalnızca dinî bir alegoriden ibarettir ve tarımla ilgisi yoktur",
            "D) Gılgamış Destanı tarımın zararlı etkilerini eleştirmektedir",
            "E) Bira içmek Sümer kültüründe yasaklı bir eylemdi"
        ],
        cevap: "B) Ekmek ve bira — tarımsal ürünler — uygarlığın ve insanlığın simgesi olarak kurgulanmıştır; doğadan kopuş vahşilikten insanlığa geçişin metaforu sayılmıştır",
        aciklama: "Enkidu’nun ekmek yiyip bira içerek 'insan' olması, Sümerlerin tarımsal ürünleri uygarlığın simgesi saydığını göstermektedir. Avcı-toplayıcı vahşilikten tarım temelli medeniyete geçiş, destanda 'insanlaşma' olarak kodlanmıştır. Bu soru, mitolojik metni tarihsel bilinç açısından yorumlama becerisini gerektirdiğinden zor düzeydedir ve programın doruk noktasıdır."
    }
];

// --- 2. ÜNİTE: TARIM DEVRİMİNİN ESKİ ÇAĞ'A ETKİLERİ - TEST 2 ---
window.allTests["test_u2_tarim_2"] = [
    {
        soru: "<i>\"İnsanlık tarihinin en büyük dönüşümlerinden biri, MÖ 10.000-8.000 yılları arasında gerçekleşti. Bilim insanları bu dönüşümü Neolitik Devrim ya da Tarım Devrimi olarak adlandırır. Bu süreçte insanlar, yabani bitkileri kültüre alarak ve vahşi hayvanları evcilleştirerek kendi besin kaynaklarını üretmeye başladılar.\" (Kaynak: Colin Renfrew & Paul Bahn, Archaeology: Theories, Methods and Practice, 2012, s.271 – uyarlanmıştır)</i><br><br><b>Bu metne göre Neolitik Devrim kavramının özünü oluşturan değişim hangisidir?</b>",
        secenekler: [
            "A) İnsanların ateşi keşfetmesi",
            "B) İnsanların hayvanları avlaması",
            "C) İnsanların besin üretimini kendi kontrolüne alması",
            "D) İnsanların deniz kıyılarına yerleşmesi",
            "E) İnsanların metal aletler kullanmaya başlaması"
        ],
        cevap: "C) İnsanların besin üretimini kendi kontrolüne alması",
        aciklama: "Metin, Tarım Devrimi’nin özünü 'bitkilerin kültüre alınması ve hayvanların evcilleştirilmesi' yani besin üretiminin insan kontrolüne girmesi olarak tanımlamaktadır. Diğer seçeneklerde yer alan ateş, denize yerleşme ve metal kullanımı metinde geçmemektedir."
    },
    {
        soru: "<i>\"Tarım başlamadan önce insanlar küçük gruplar hâlinde göç ederek yaşıyordu. Bir bölgedeki av ve yabani bitkiler tükenince grup yeni alanlara geçiyordu. Tahılların ekilip biçilmesi ise insanları toprağa bağladı; çünkü tarlayı terk etmek emeğin ve yatırımın ziyan olması demekti.\" (Kaynak: Peter Bellwood, First Farmers: The Origins of Agricultural Societies, 2005, s.14 – uyarlanmıştır)</i><br><br><b>Metne göre tarımın insanları belirli bir yere bağlamasının temel nedeni nedir?</b>",
        secenekler: [
            "A) Tarım aletlerinin taşınmasının güç olması",
            "B) Tarla yatırımını terk etmenin kayıp doğurması",
            "C) Devletin göçe izin vermemesi",
            "D) İklimin göçü imkânsız kılması",
            "E) Hayvanların taşınamaması"
        ],
        cevap: "B) Tarla yatırımını terk etmenin kayıp doğurması",
        aciklama: "Metin, tarlayı terk etmenin emek ve yatırım kaybına yol açacağını belirtmektedir. Göçün sona ermesinin nedeni ekonomik bir bağlılıktır. Devlet baskısı, iklim ve araç taşıma güçlüğü metinde yer almamaktadır."
    },
    {
        soru: "<i>\"Eski Mısır'da her yıl Nil taşkını biterken halk ırmak kenarındaki çamurlu toprağa buğday ve arpa tohumları ekiyordu. Güneş ve nehrin getirdiği silt sayesinde hasatlar boldu. Firavun Ramses II dönemine ait bir yazıtta şöyle geçer: Nehir her yıl gelir, ve toprak yeniden canlanır; tanrıların armağanı asla tükenmez.\" (Kaynak: Ramses II dönemi Karnak tapınağı yazıtından uyarlanmıştır, MÖ yaklaşık 1260)</i><br><br><b>Bu yazıta göre Mısır tarımının sürekliliğini sağlayan temel unsur hangisidir?</b>",
        secenekler: [
            "A) Farklı toprak katmanlarından yararlanılması",
            "B) Firavunun kanallar kazdırması",
            "C) Nil taşkınının getirdiği silt ile toprağın yenilenmesi",
            "D) Köylülerin tarım tekniklerini geliştirmesi",
            "E) Depolanan tohumların saklanması"
        ],
        cevap: "C) Nil taşkınının getirdiği silt ile toprağın yenilenmesi",
        aciklama: "Yazıt açıkça 'nehir her yıl gelir ve toprak yeniden canlanır' demektedir. Taşkının getirdiği silt (alüvyon), toprağı doğal olarak yenilemiştir. Diğer seçenekler metinde desteklenmemektedir."
    },
    {
        soru: "<i>\"Erken Neolitik köylerde bulunan obsidyen, deniz kabuğu ve bakır eserler, bu köylerin yüzlerce kilometre ötedeki bölgelerle bağlantı kurduğunu göstermektedir. Fazla üretilen tahıl, komşu toplulukların ihtiyaç duyduğu hammaddelerle takas ediliyor; böylece ilk ticaret ağları oluşuyordu.\" (Kaynak: Katherine Piquette & Ruth Whitehouse, Writing as Material Practice, 2013, s. 89 – uyarlanmıştır)</i><br><br><b>Bu metne göre erken ticaret ağlarının oluşmasını mümkün kılan temel etken nedir?</b>",
        secenekler: [
            "A) Deniz ulaşımının başlaması",
            "B) Tahıl üretiminde ortaya çıkan fazlalık",
            "C) Metal araçların icadı",
            "D) Nüfusun azalması",
            "E) Köylerin birleşmesi"
        ],
        cevap: "B) Tahıl üretiminde ortaya çıkan fazlalık",
        aciklama: "Metin, fazla tahılın hammaddelerle takas edildiğini ve bunun ticaret ağlarını doğurduğunu belirtmektedir. Deniz ulaşımı veya metal araç metinde geçmez; neden değil, araç olarak ele alınmaktadır."
    },
    {
        soru: "<i>\"Arpa ve buğday yalnızca ekmek yapmak için kullanılmıyordu. Mezopotamya'da fermantasyon yöntemiyle yapılan bira, hem besin değeri hem de ekonomik işlev taşıyordu. Sümer yazıtlarında inşaat işçilerine günde birkaç litre bira verildiği kayıt altına alınmıştır; bira böylece bir tür ücret işlevi görüyordu.\" (Kaynak: Patrick McGovern, Uncorking the Past, 2009, s. 58 – uyarlanmıştır)</i><br><br><b>Bu metne göre Mezopotamya’da biranın toplumsal işlevi aşağıdakilerden hangisiyle örtüşmektedir?</b>",
        secenekler: [
            "A) Yalnızca dini törenlerde kullanılan kutsal bir içki olmasıyla",
            "B) Hem beslenme hem de emek ödemesinde araç olarak kullanılmasıyla",
            "C) Yalnızca firavunlara sunulan bir statü simgesi olmasıyla",
            "D) Ticaret amacıyla yabancı ülkelere ihraç edilmesiyle",
            "E) Hastalıkları tedavi etmekte kullanılan bir ilaç olmasıyla"
        ],
        cevap: "B) Hem beslenme hem de emek ödemesinde araç olarak kullanılmasıyla",
        aciklama: "Metin, biranın hem besin değeri taşıdığını hem de işçilere ücret olarak ödendiğini belirtmektedir. Bu iki işlev B seçeneğiyle tam örtüşmektedir. Dini tören, ihracat ve ilaç işlevleri metinde geçmemektedir."
    },
    {
        soru: "<i>\"MÖ 9000 yıllarına ait Karaçadag Dağları (Güneydoğu Türkiye) bölgesinde yapılan genetik araştırmalar, modern ekmeklik buğdayının bu bölgedeki yabani buğdaydan (Triticum dicoccoides) köken aldığını ortaya koymuştur. Bilim insanları bu bölgeyi dünyanın en önemli tarım merkezlerinden biri olarak kabul etmektedir.\" (Kaynak: Manfred Heun et al., Site of Einkorn Wheat Domestication Identified by DNA Fingerprinting, Science, 1997)</i><br><br><b>Bu genetik araştırma bulgusu, tarihsel açıdan ne anlam taşımaktadır?</b>",
        secenekler: [
            "A) Buğdayın Mısır’da kültüre alındığını kanıtlamaktadır",
            "B) Anadolu’nun tarımın ilk ortaya çıktığı bölgelerden biri olduğunu göstermektedir",
            "C) Yabani buğdayın kültüre alınamayacağını ortaya koymaktadır",
            "D) Tarım devriminin yalnızca genetik nedenlerle açıklanabileceğini savunmaktadır",
            "E) Buğdayın MÖ 5000'den önce var olmadığını göstermektedir"
        ],
        cevap: "B) Anadolu’nun tarımın ilk ortaya çıktığı bölgelerden biri olduğunu göstermektedir",
        aciklama: "Araştırma, ekmeklik buğdayın Güneydoğu Türkiye’deki yabani türden geldiğini ortaya koymakta ve bu bölgeyi önemli bir tarım merkezi olarak tanımlamaktadır. Mısır iddiası metinle çelişir; genetik açıklama iddiası ise metni aşmaktadır."
    },
    {
        soru: "<i>\"Sümer edebiyatında \"Çiftçi ve Çoban\" adlı bir tartışma şiiri yer alır. Şiirde çiftçi şunu der: Ben tarlama bakıyorum; sen sürünü otlatıyorsun. Benim ürünüm depolanır ve kışı geçirir; senin hayvanları ise karda açlıktan ölür. Tanrılar benim işimi daha değerli kılmıştır.\" (Kaynak: Thorkild Jacobsen, The Harps that Once... Sumerian Poetry in Translation, 1987, s. 183 – uyarlanmıştır)</i><br><br><b>Bu Sümer şiiri, tarım toplumunda yaşanan hangi toplumsal farkındalığı yansıtmaktadır?</b>",
        secenekler: [
            "A) Çiftçilerin çobanlara üstünlüğünü resmî olarak ilan etmesi",
            "B) Tarımın depolama avantajıyla hayvancılığa göre daha güvenilir bir geçim kaynağı sayılması",
            "C) Sümer tanrılarının çobanlara düşman olması",
            "D) Çiftçilerin devlet tarafından ödüllendirilmesi",
            "E) Hayvancılığın Sümer’de yasaklanması"
        ],
        cevap: "B) Tarımın depolama avantajıyla hayvancılığa göre daha güvenilir bir geçim kaynağı sayılması",
        aciklama: "Şiirde çiftçi, ürününü depolayabildiğini ve kışı sorunsuz geçirdiğini vurgularken çobanın hayvanları kışta ölmektedir. Bu karşılaştırma, tarımın hayvancılığa kıyasla depolama aracılığıyla daha güvenli bir geçim sağladığı görüşünü yansıtmaktadır."
    },
    {
        soru: "<i>\"Catalhöyük'te yapılan kazılarda 9000 yıllık bir yerleşim katmanı bulunmuştur. Evler yan yana, kapısız inşa edilmiş; giriş çatıdaki deliklerden merdivenle yapılıyordu. Cenazeler evin tabanına gömülüyordu. Arkeologlar tüm bu özelliklerden toplumun güçlü bir ata kültüne ve kolektif mülkiyet anlayışına sahip olduğunu çıkarsamaktadır.\" (Kaynak: Ian Hodder, The Leopard's Tale: Revealing the Mysteries of Catalhöyük, 2006, s. 97 – uyarlanmıştır)</i><br><br><b>Bu arkeolojik bulgulardan hareketle Çatalhöyük toplumu hakkında hangi yorum en tutarlıdır?</b>",
        secenekler: [
            "A) Çatalhöyük sakinleri yabancılara karşı savunma amaçlı mimari geliştirmiştir",
            "B) Yerleşim düzeni ve ata gömme geleneği, kolektif/aile temelli bir toplumsal yapıya işaret etmektedir",
            "C) Evlerin çatıdan girilmesi, Çatalhöyük'ün bir kale şehri olduğunu kanıtlamaktadır",
            "D) Çatalhöyük, tarım yerine ticaretle geçinen bir kentti",
            "E) Özel mülkiyet anlayışı Çatalhöyük'te çok gelişmişti"
        ],
        cevap: "B) Yerleşim düzeni ve ata gömme geleneği, kolektif/aile temelli bir toplumsal yapıya işaret etmektedir",
        aciklama: "Cenaze gömme, kapısız bitişik evler ve kolektif yaşam düzeni, bu toplumun bireysel değil kolektif ve ata merkezli bir yapıya sahip olduğunu göstermektedir. Kale yorumu tek bir mimari özelliği aşırı geneller; ticaret ve özel mülkiyet metinle çelişir."
    },
    {
        soru: "<i>\"Eski Mısır'da \"nomos\" adı verilen bölgeler, nehrin taşkın alanına göre şekillenirdi. Her nomo'nun başında bir \"nomark\" bulunur ve bu kişi sulama kanallarının bakımından, hasat vergisinin toplanmasından ve tahılın depolanmasından sorumlu tutulurdu. Firavun merkezi otoritesini nomarklar aracılığıyla kırsal alana yayardı.\" (Kaynak: Barry Kemp, Ancient Egypt: Anatomy of a Civilisation, 2006, s. 186 – uyarlanmıştır)</i><br><br><b>Bu metne göre Mısır’da bürokratik yapının temel işlevi neydi?</b>",
        secenekler: [
            "A) Askeri seferler organize etmek",
            "B) Din hizmetlerini düzenlemek",
            "C) Tarımsal kaynakları (sulama, hasat vergisi, depolama) merkezi olarak yönetmek",
            "D) Ticareti denetleyerek yabancı malların girişini engellemek",
            "E) Tapınak inşaatlarını koordine etmek"
        ],
        cevap: "C) Tarımsal kaynakları (sulama, hasat vergisi, depolama) merkezi olarak yönetmek",
        aciklama: "Metin, nomarkların görevlerini açıkça sulama, vergi ve depolama üzerinden tanımlamaktadır. Bürokratik yapının özü tarımsal kaynakları yönetmektir. Askeri, dini ve ticari işlevler bu metinde birincil değildir."
    },
    {
        soru: "<i>\"Avustralya yerlisi Aborijinlerin yaşam biçimi üzerine araştırma yapan antropolog Marshall Sahlins (1972), avcı-toplayıcıların günde ortalama 3-5 saat çalışarak ihtiyaçlarını karşıladığını; kalan zamanı dinlenerek, sosyalleşerek ve ritüeller icra ederek geçirdiklerini gözlemledi. Sahlins bu toplulukları \"bolluk içindeki ilk toplumlar\" olarak nitelendirdi.\" (Kaynak: Marshall Sahlins, Stone Age Economics, 1972, s. 2 – uyarlanmıştır)</i><br><br><b>Sahlins’in bu tezi kabul edilirse, Tarım Devrimi’nin insan refahına etkisi hakkında hangi kritik soru gündeme gelir?</b>",
        secenekler: [
            "A) Neden tüm toplumlar aynı anda tarıma geçmedi?",
            "B) Tarım nüfusu artırmış mıdır?",
            "C) Tarım bireylerin yaşam kalitesini artırmış mıdır, yoksa çalışma yükünü mü yoğunlaştırmıştır?",
            "D) Avcı-toplayıcılar neden göçebeliği bırakmak istemedi?",
            "E) Tarım hangi coğrafyada daha verimli uygulanmıştır?"
        ],
        cevap: "C) Tarım bireylerin yaşam kalitesini artırmış mıdır, yoksa çalışma yükünü mü yoğunlaştırmıştır?",
        aciklama: "Sahlins’in bulgusu, avcı-toplayıcıların az çalışıp çok dinlendiğini göstermektedir. Bu veri, tarımın 'ilerleme' olduğu varsayımını sorgulatır: Tarım nüfusu büyütmüş olabilir, ama birey başına çalışma yükü artmış olabilir. Bu gerilim, C seçeneğinde özetlenmiştir."
    },
    {
        soru: "<i>\"MÖ 2350 civarında yaşayan Akad İmparatoru Sargon'un yazıtlarında şöyle geçer: Ben Sargon, tahıl ambarlarını fethettim; kanalları açtırdım; nehrin suyunu kuzeyden güneye aktardım; tüm toprakları bol mahsul veren bahçelere çevirdim. Büyük tanrı Enlil bana bu gücü verdi.\" (Kaynak: Sargon Yazıtı, Akad dönemi, MÖ yaklaşık 2350 – uyarlanmış çeviri)</i><br><br><b>Bu yazıt, tarımsal altyapı ile siyasi güç arasındaki ilişki hakkında ne söylemektedir?</b>",
        secenekler: [
            "A) Sargon, tarımı savaşın yerine geçen bir etkinlik olarak gördü",
            "B) Siyasi meşruiyet kısmen tarımsal altyapıyı kontrol etme ve geliştirme üzerinden kurulmuştur",
            "C) Akad İmparatorluğu’nda tarım dini kurumların kontrolündeydi",
            "D) Sargon'un amacı yalnızca dini bir hedefe ulaşmaktı",
            "E) Kanallar yalnızca savaş sonrası yıkılan köylere hizmet etti"
        ],
        cevap: "B) Siyasi meşruiyet kısmen tarımsal altyapıyı kontrol etme ve geliştirme üzerinden kurulmuştur",
        aciklama: "Sargon tahıl ambarlarını fethettikten ve kanallar inşa ettirdikten sonra bu başarıları gücünün kanıtı olarak sunar. Tarımsal altyapı üzerindeki hakimiyet, siyasi meşruiyetin ayrılmaz parçasıdır. Tanrı Enlil referansı iktidarı kutsal kılma çabasıdır."
    },
    {
        soru: "<i>\"Antik Çin'de Zhou hanedanı döneminde \"jing tian\" (iyi tarla) sistemi uygulandı. Bir tarla dokuz eşit parçaya bölünür; sekiz aile kendi parçasını işler, dokuzuncu ortak parça ise devlet için ortak olarak ekilirdi. Bu sistem, vergi ve toprak kullanımını aynı anda düzenliyordu.\" (Kaynak: Cho-yun Hsu, Ancient China in Transition, 1965, s. 108 – uyarlanmıştır)</i><br><br><b>Zhou dönemi 'jing tian' sistemi, tarım ile devlet organizasyonu arasındaki ilişki açısından ne göstermektedir?</b>",
        secenekler: [
            "A) Çin’de devletin tarım dışında gelir kaynakları aradığını",
            "B) Tarımsal üretimin fiziksel düzenlenmesinin aynı zamanda vergi ve devlet finansmanını çözdüğünü",
            "C) Çin’de mülkiyet her zaman özel ellerde olduğunu",
            "D) Dokuzuncu parçanın köylüler tarafından değil köleler tarafından işlendiğini",
            "E) Zhou hanedanının tarımsal sistemi Mezopotamya'dan aldığını"
        ],
        cevap: "B) Tarımsal üretimin fiziksel düzenlenmesinin aynı zamanda vergi ve devlet finansmanını çözdüğünü",
        aciklama: "Tarlanın dokuzda biri devlet için ayrılmıştır; bu sayede tek bir arazi düzenlemesi hem üretimi hem vergiyi hem de toplumsal görevi çözüyor. Tarımın fiziksel organizasyonu devlet finansman sistemine dönüştürülmüştür."
    },
    {
        soru: "<i>\"Yunan filozofu Hesiodos, MÖ 700 civarında yazdığı İşler ve Günler eserinde çiftçilik takvimini ayrıntılı biçimde anlattı: Pleiades yıldız kümesi ufukta belirince biçin; Ülker battığında süre; yağmur yağan günler ekme vaktidir. Hesiodos, çiftçiyi kozmosa bağlayan bu takvimi hem pratik rehber hem de toplumsal ahlakın temeli olarak sundu.\" (Kaynak: Hesiodos, İşler ve Günler, MÖ yaklaşık 700, çev. F. Akderin – uyarlanmıştır)</i><br><br><b>Hesiodos’un çiftçilik takvimini kozmosla ilişkilendirmesi, tarımın Antik Yunan toplumundaki işlevi açısından ne anlam taşır?</b>",
        secenekler: [
            "A) Yunanistan’da tarımın yalnızca din adamları tarafından yapıldığını",
            "B) Tarımın yıldız gözlemine dayalı astronomik bilgiyi ve toplumsal ahlakı birbiriyle bütünleştirdiğini",
            "C) Hesiodos’un yalnızca astronomi alanında yazdığını",
            "D) Antik Yunan’da tarım takvimlerinin bilimsel değerden yoksun olduğunu",
            "E) Tarımın Yunan toplumunda önemsiz bir uğraş sayıldığını"
        ],
        cevap: "B) Tarımın yıldız gözlemine dayalı astronomik bilgiyi ve toplumsal ahlakı birbiriyle bütünleştirdiğini",
        aciklama: "Hesiodos yıldız hareketlerini (Pleiades, Ülker) ekip-biçme zamanıyla ilişkilendirmiş; böylece tarım gözlemsel astronomiyi zorunlu kılmıştır. Üstelik çiftçiliği ahlaki bir ödev olarak sunar; bu da tarımın toplumsal düzeni meşrulaştırma işlevi gördüğünü ortaya koyar."
    },
    {
        soru: "<i>\"Sümer toplumunda çiftçi, nehir kenarlarındaki sulama kanallarını açmak ve temizlemek için komşularıyla birlikte çalışmak zorundaydı. Bir köylünün tek başına kanal açması neredeyse imkânsızdı. Bu zorunlu iş birliği, \"asgar\" adı verilen köy meclislerinin oluşmasına zemin hazırladı.\" (Kaynak: Henri Frankfort, The Birth of Civilisation in the Near East, 1951, s. 57 – uyarlanmıştır)</i><br><br><b>Bu metin, tarımsal altyapının toplumsal örgütlenme biçimlerini nasıl etkilediğini açıklamaktadır. Bu etki nasıl değerlendirilebilir?</b>",
        secenekler: [
            "A) Tarım, toplumları atomize ederek bireyci bir yapıya yöneltmiştir",
            "B) Sulama gibi kolektif altyapı gereksinimleri, ortak karar alma kurumlarının doğmasını tetiklemiştir",
            "C) Köy meclisleri tarımdan bağımsız olarak var olmuştur",
            "D) Sümer’de sulama yalnızca devlet kurumları tarafından organize edilmiştir",
            "E) Asgar meclisleri yalnızca din işlerini yürütmüştür"
        ],
        cevap: "B) Sulama gibi kolektif altyapı gereksinimleri, ortak karar alma kurumlarının doğmasını tetiklemiştir",
        aciklama: "Sulama kanalları tek başına açılamazdı; bu ortaklık zorunluluğu köy meclislerini doğurdu. Tarımsal altyapı ihtiyacı, siyasi-idari kurumların nüvesini oluşturmuştur. Bu zincir —tarım → kolektif zorunluluk → kurum— analitik bir okuma gerektirmektedir."
    },
    {
        soru: "<i>\"Tarihçi Fernand Braudel, Maddi Uygarlık adlı eserinde şunu yazar: Buğday Akdeniz uygarlığı için ne anlam ifade ediyorsa, pirinç Güneydoğu Asya uygarlığı için, mısır ise Mezoamerika uygarlığı için aynı anlamı taşır. Her büyük uygarlık bir temel tahıl üzerine inşa edilmiştir; tahıl değiştikçe uygarlığın dokusu da değişmektedir.\" (Kaynak: Fernand Braudel, Civilisation matérielle, économie et capitalisme, 1979, C.1, s.104 – uyarlanmıştır)</i><br><br><b>Braudel’in argümanından çıkarılabilecek en kapsamlı tarih yorumu hangisidir?</b>",
        secenekler: [
            "A) Bütün uygarlıklar aynı tahılı kullandığından aynı kültürü paylaşmaktadır",
            "B) Coğrafyaya özgü temel tahıllar, her uygarlığın ekonomik ve kültürel dokusunu biçimlendirmiştir",
            "C) Pirinç yiyen toplumlar buğday yiyenlerden daha gelişmiştir",
            "D) Uygarlıklar arasındaki tek fark hangi tahılı yetiştirdikleridir",
            "E) Braudel tahılı simgesel değil, yalnızca besin değeri açısından ele almaktadır"
        ],
        cevap: "B) Coğrafyaya özgü temel tahıllar, her uygarlığın ekonomik ve kültürel dokusunu biçimlendirmiştir",
        aciklama: "Braudel’in tezi, coğrafyanın belirlediği temel tahılın her uygarlığın özgün yapısını şekillendirdiğini savunmaktadır. Bu yaklaşım, tarımı coğrafya ve kültür arasındaki köprü olarak konumlandırır. A seçeneği yanlış; uygarlıkların farklı tahıllar üzerine kurulduğu vurgulanmaktadır."
    },
    {
        soru: "<i>\"İsrail'in Negev çölünde MÖ 6000'e tarihlenen bir mezarlıkta yapılan iskelet analizleri, kadın bireyler üzerinde omurga deformasyonu ve el eklemlerinde ciddi aşınma izleri saptadı. Araştırmacılar bu bulguları uzun saatler öğütme taşı başında çalışmakla ilişkilendirdi; bu dönem çiftçi toplumunun kadınlarına yoğun fiziksel iş düştüğüne işaret ediyordu.\" (Kaynak: Ron Pinhasi & Jay Stock, The Bioarchaeology of Metabolic Bone Disease, 2011, s. 217 – uyarlanmıştır)</i><br><br><b>Bu iskelet bulguları, Tarım Devrimi’nin toplumsal cinsiyet eşitsizliğiyle ilişkisi hakkında ne söylemektedir?</b>",
        secenekler: [
            "A) Tarım, kadın ve erkekler arasında iş yükünü eşit biçimde dağıtmıştır",
            "B) Tarım dönemi kadınlarının iskelet verisi, ağır ve tekrarlayan iş yüküne maruz kaldıklarını göstermektedir",
            "C) Omurga bozuklukları yalnızca yaşlılıktan kaynaklanmaktadır",
            "D) Erkekler tahıl öğütme işini üstlendiğinden daha fazla yıpranmıştır",
            "E) Iskelet verileri sosyal hiyerarşi hakkında bilgi vermez"
        ],
        cevap: "B) Tarım dönemi kadınlarının iskelet verisi, ağır ve tekrarlayan iş yüküne maruz kaldıklarını göstermektedir",
        aciklama: "Kadın iskeletlerinde öğütme taşına bağlı omurga ve el eklem hasarı, tarım toplumunda kadınların ağır fiziksel iş yüküne sistematik biçimde maruz kaldığını göstermektedir. Bu bulgular toplumsal cinsiyet ve iş bölümü konusunda somut bir kanıt sunar."
    },
    {
        soru: "<i>\"Eski Ahit'te Levililer bölümü şöyle der: Tarlandan biçtiğinde tarlasının köşelerini biçme; biçtikten sonra düşen başakları toplama. Bunları yoksul ve yabancı için bırak; ben Tanrınız'ım. Bu \"leket\" (artık başak) geleneği, erken tarım toplumlarının artı ürünü toplumsal dayanışma aracına nasıl dönüştürdüğünü göstermektedir.\" (Kaynak: Levililer 19:9-10, Kutsal Kitap; yorum: David Graeber, Debt: The First 5000 Years, 2011 – uyarlanmıştır)</i><br><br><b>Bu metne göre erken tarım toplumlarında artı ürünün nasıl bir toplumsal işlev üstlendiği anlaşılmaktadır?</b>",
        secenekler: [
            "A) Artı ürün yalnızca devlet hazinesine aktarılmıştır",
            "B) Artı ürün, zengin tüccarlar tarafından ihraç edilmiştir",
            "C) Artı ürün, dini buyruklarla desteklenen yeniden dağıtım mekanizması aracılığıyla toplumsal dayanışmayı besleyebilmiştir",
            "D) Leket geleneği yalnızca ekonomik bir pratiktir, dinle ilgisi yoktur",
            "E) Bu uygulama yalnızca Mezopotamya'ya özgüdür"
        ],
        cevap: "C) Artı ürün, dini buyruklarla desteklenen yeniden dağıtım mekanizması aracılığıyla toplumsal dayanışmayı besleyebilmiştir",
        aciklama: "Leket geleneği, tarımsal artı ürünün yoksullarla paylaşılmasını dini bir yükümlülük hâline getirmektedir. Bu, artı ürünün yalnızca birikim değil dayanışma aracı da olabileceğini ve dinin bu yeniden dağıtımı meşrulaştırdığını ortaya koymaktadır."
    },
    {
        soru: "<i>\"Mezopotamya tarihini inceleyen akademisyen Guillermo Algaze, şu ilginç tespiti yapar: MÖ 4. binyılda Uruk kenti, çevresindeki köylerden 40-60 kat daha kalabalıktı. Bu yoğunluk, tarımsal artı ürünün uzak bölgelerden Uruk'a aktarılmasıyla mümkün oldu; kentteki zanaat üretimi ve ticaret ağı köylerin tahılına bağımlıydı.\" (Kaynak: Guillermo Algaze, Ancient Mesopotamia at the Dawn of Civilization, 2008, s. 34 – uyarlanmıştır)</i><br><br><b>Bu tespit, ilk kentlerin nasıl ortaya çıktığı sorusuna nasıl bir yanıt önerir?</b>",
        secenekler: [
            "A) Kentler, tarımla değil madencilikle büyümüştür",
            "B) İlk kentler, tarımsal artı ürünün merkeze aktarılmasını mümkün kılan ekonomik ağlar sayesinde ortaya çıkmıştır",
            "C) Uruk büyüklüğünü askeri gücüne borçludur",
            "D) Köyler, kentlerden daha büyük nüfus barındırıyordu",
            "E) Kentleşme Mezopotamya'da tarımdan önce başlamıştır"
        ],
        cevap: "B) İlk kentler, tarımsal artı ürünün merkeze aktarılmasını mümkün kılan ekonomik ağlar sayesinde ortaya çıkmıştır",
        aciklama: "Algaze’nin analizi, Uruk’un büyümesini uzak köylerden gelen tarımsal artı ürüne bağlamaktadır. Bu, ilk kentlerin tarım artığını merkeze çeken ekonomik ağların ürünü olduğu tezini desteklemektedir. Askeri güç veya madencilik bu metinde kentleşmenin nedeni olarak sunulmamaktadır."
    },
    {
        soru: "<i>\"Bir Sümer ilahisi şöyle yazar: Ey Nisaba, tahılın tanrıçası, eliyle kalemi tutan, levhalara yazıları kazıyan, sen hesapçılığın ve yazının efendisisin. Sana tahıl sayısını ve ambar kayıtlarını borçluyuz. Sümerlerde yazının koruyucusu olarak bir tahıl tanrıçasının seçilmesi tesadüf değildir; ilk yazı sistemleri ambar ve tahıl kayıtlarından doğmuştur.\" (Kaynak: Denise Schmandt-Besserat, Before Writing, 1992, s. 201 – uyarlanmıştır)</i><br><br><b>Bu metin, Tarım Devrimi ile yazının ortaya çıkışı arasındaki ilişki hakkında ne söylemektedir?</b>",
        secenekler: [
            "A) Yazı, dini metinleri kaydetmek amacıyla icat edilmiştir",
            "B) Yazının kökeni tarımsal ürün kayıtlarına dayanmakta; tahıl yönetimi yazıyı zorunlu kılmıştır",
            "C) Tahıl tanrıçası Nisaba, yazıyı Mezopotamya’ya getirmiştir",
            "D) Sümerler yazıyı Mısır’dan almıştır",
            "E) Ambar kayıtları yazıyı değil matematiği doğurmuştur"
        ],
        cevap: "B) Yazının kökeni tarımsal ürün kayıtlarına dayanmakta; tahıl yönetimi yazıyı zorunlu kılmıştır",
        aciklama: "Nisaba’nın hem tahıl hem yazının tanrıçası olması ve ambar kayıtlarının yazıyı borçlu olduğumuz şey olarak sunulması, yazının tarımsal muhasebe ihtiyacından doğduğunu göstermektedir. Araştırmacı Schmandt-Besserat da ilk yazılı belgelerin tahıl ve hayvan sayımı olduğunu kanıtlamıştır."
    },
    {
        soru: "<i>\"Hindistan'ın Deccan platosu çiftçileri, MÖ 3000-1500 arasında kuru tarım yöntemiyle darı ve sorgum yetiştirdi. Bu tahıllar az su ile yetiştirilebildiğinden sulama altyapısı gerektirmiyordu. Araştırmacılar bu bölgede geniş tapınak kompleksleri ya da büyük kent merkezleri yerine dağınık köy yapısının sürdüğünü saptamıştır.\" (Kaynak: Dorian Fuller, Agricultural Origins and Frontiers in South Asia, Journal of World Prehistory, 2006)</i><br><br><b>Bu bulgular, sulama bağımlılığı ile siyasi örgütlenme arasındaki ilişki hakkında hangi hipotezi destekler?</b>",
        secenekler: [
            "A) Her tarım tipi büyük kentler ve merkezi devletler doğurur",
            "B) Sulama bağımlısı tarım merkezi örgütlenmeyi teşvik ederken sulamaya gerek duymayan tarım dağınık köy yapısını sürdürebilir",
            "C) Darı ve sorgum hiçbir zaman önemli bir ekonomik ürün olamaz",
            "D) Hindistan’da kentleşme tarımdan önce gerçekleşmiştir",
            "E) Deccan platosu tarım teknikleri Mezopotamya’dan aktarılmıştır"
        ],
        cevap: "B) Sulama bağımlısı tarım merkezi örgütlenmeyi teşvik ederken sulamaya gerek duymayan tarım dağınık köy yapısını sürdürebilir",
        aciklama: "Deccan’da sulama gerektirmeyen kuru tarım büyük kent ve tapınak komplekslerini doğurmamıştır. Bu, sulama altyapısının koordinasyon ihtiyacıyla merkezi siyasi yapıyı zorunlu kıldığını, ancak sulama olmadan bu baskının ortadan kalktığını göstermektedir. Wittfogel’in hidrolik hipotezini dolaylı olarak destekler."
    },
    {
        soru: "<i>\"Çin'de Han hanedanı tarihçisi Sima Qian şöyle yazmıştır: İmparator Shennong insanlara tahta saban ve çapa yapmayı öğretti; onlara toprağı nasıl süreceklerini, tohumları nasıl ekeceklerini gösterdi. Böylece insanlar tembel vahşi hayvanlar gibi yaşamaktan kurtuldu ve medeniyete adım attı.\" (Kaynak: Sima Qian, Shiji (Tarih Kayıtları), MÖ 1. yüzyıl – uyarlanmış çeviri)</i><br><br><b>Sima Qian’ın bu anlatısı, tarım ile uygarlık arasında nasıl bir ilişki kurduğunu göstermekte; bu ilişki hangi açıdan sorgulanabilir?</b>",
        secenekler: [
            "A) Tarım, doğadan kopuşu temsil ettiğinden medeniyetle ilişkisi yoktur; Sima Qian yanılmaktadır",
            "B) Sima Qian tarımı medeniyetin başlangıcı saymaktadır; ancak bu yaklaşım avcı-toplayıcıları 'vahşi hayvan' gibi niteleyen bir önyargı taşımaktadır",
            "C) Tarım medeniyeti değil, yalnızca nüfus artışını sağlamıştır",
            "D) Sima Qian'nın anlatısı tamamen efsanedir ve hiçbir tarihsel değeri yoktur",
            "E) Han hanedanı tarımı desteklememiştir"
        ],
        cevap: "B) Sima Qian tarımı medeniyetin başlangıcı saymaktadır; ancak bu yaklaşım avcı-toplayıcıları 'vahşi hayvan' gibi niteleyen bir önyargı taşımaktadır",
        aciklama: "Sima Qian açıkça tarımı medenileşmenin başlangıcı olarak konumlandırmaktadır. Ancak bu anlatı, avcı-toplayıcıları 'tembel vahşi hayvan' olarak niteleyen kültürel bir önyargı barındırmaktadır. Bu önyargıyı fark etmek, tarihin nasıl yazıldığını ve kimin bakış açısını yansıttığını anlamak için kritik bir okuma gerektirmektedir."
    },
    {
        soru: "<i>\"Arkeolog Vere Gordon Childe, uygarlığın doğuşunu anlattığı Tarihte Ne Oldu? (1936) adlı eserinde şunu savunur: Tarım Devrimi, insanlığın ilk büyük ekonomik devrimiydi. Bu devrimin sağladığı artı ürün, kentleri, sınıfları ve devletleri mümkün kıldı. Tarım olmadan ne piramitler, ne zigguratlar, ne de Parthenon inşa edilebilirdi.\" (Kaynak: V.G. Childe, What Happened in History, 1942, s. 66 – uyarlanmıştır)</i><br><br><b>Childe’ın bu tezi hangi nedensellik zincirini öne sürmektedir?</b>",
        secenekler: [
            "A) Kentler → Tarım → Artı ürün → Devlet",
            "B) Tarım → Artı ürün → Kentler, sınıflar ve devletler → Anıtsal mimari",
            "C) Devlet → Tarım → Kentler → Artı ürün",
            "D) Anıtsal mimari → Devlet → Tarım",
            "E) Sınıflar → Tarım devrimi → Artı ürün"
        ],
        cevap: "B) Tarım → Artı ürün → Kentler, sınıflar ve devletler → Anıtsal mimari",
        aciklama: "Childe açık bir nedensellik zinciri kurmaktadır: Tarım → Artı ürün → Kentler, sınıflar, devletler → Piramitler/Zigguratlar gibi anıtsal yapılar. Bu zinciri doğru sıralayabilmek metnin analitik okunmasını gerektirmektedir."
    },
    {
        soru: "<i>\"Tarih boyunca en az 24 bağımsız kültürde, birbirinden habersiz olarak, tahıl tarımının keşfedildiği saptanmıştır. Güneybatı Asya'da buğday-arpa, Çin'de pirinç-darı, Mezoamerika'da mısır, Afrika'da sorgum bunların başında gelir. Bu bağımsız buluşlar, tarım için ortak bir köken aramak yerine paralel gelişim süreçlerini araştırmayı zorunlu kılmaktadır.\" (Kaynak: Jack Harlan, Crops and Man, 1975, s. 62 – uyarlanmıştır)</i><br><br><b>Bu bulgular, tarih yazımı açısından hangi metodolojik sonucu doğurmaktadır?</b>",
        secenekler: [
            "A) Tarımın tek bir kaynaktan yayıldığı tezi doğrulanmaktadır",
            "B) Tarımın paralel ve bağımsız gelişimi, 'yayılmacı' modelin yetersiz olduğunu ve çok merkezli gelişim modelinin benimsenmesi gerektiğini göstermektedir",
            "C) Bağımsız buluşlar yalnızca tesadüfle açıklanabilir",
            "D) Tarım yalnızca Yakın Doğu’da icat edilmiş ve oradan yayılmıştır",
            "E) Tüm tahıl türleri aynı bölgede kültüre alınmıştır"
        ],
        cevap: "B) Tarımın paralel ve bağımsız gelişimi, 'yayılmacı' modelin yetersiz olduğunu ve çok merkezli gelişim modelinin benimsenmesi gerektiğini göstermektedir",
        aciklama: "24 bağımsız tarım merkezinin varlığı, tek kökenli yayılma teorisini çürütmekte ve farklı coğrafyalarda birbirinden bağımsız gelişim süreçlerinin incelenmesini gerektiren çok merkezli modeli zorunlu kılmaktadır. Bu, tarih metodolojisi açısından önemli bir kavrayıştır."
    },
    {
        soru: "<i>\"Arkeolog Brian Hayden, \"prestige goods\" (prestij malları) hipotezinde şunu öne sürer: Tarım, yiyecek sıkıntısı çeken toplulukların değil, ziyafet verip prestij kazanmak isteyen güçlü bireylerin girişimiyle başladı. İlk kültüre alınan bitkiler arasında tahıldan çok meyve, fındık ve fermente içki hammaddeleri öne çıkmaktadır. Bu hypothesis, tarımı açlığın değil, sosyal statünün itici gücü saydığı için geleneksel açıklamalardan radikal biçimde ayrılmaktadır.\" (Kaynak: Brian Hayden, Nimrods, Piscators, Pluckers and Planters, Journal of Anthropological Archaeology, 1990)</i><br><br><b>Hayden’ın hipotezi kabul edilirse, Tarım Devrimi’nin başlangıcına ilişkin standart 'açlık-zorunluluk' açıklaması nasıl değerlendirilmelidir?</b>",
        secenekler: [
            "A) Standart açıklama tamamen geçerliliğini korumakta; Hayden’ın hipotezinin kanıtsal dayanağı yoktur",
            "B) Hayden’ın tezi, tarımın başlangıcının ekonomik zorunluluk değil sosyal rekabet ve prestij güdüsüyle de açıklanabileceğini göstererek standart açıklamayı alternatif bir model olarak tamamlamaktadır",
            "C) İki açıklama birbiriyle tamamen çelişmektedir ve biri kesinlikle doğru diğeri yanlıştır",
            "D) Hayden, tarımın hiçbir zaman besin üretimine katkı yapmadığını ileri sürmektedir",
            "E) Standart açıklama, sosyal prestij faktörünü zaten içermektedir"
        ],
        cevap: "B) Hayden’ın tezi, tarımın başlangıcının ekonomik zorunluluk değil sosyal rekabet ve prestij güdüsüyle de açıklanabileceğini göstererek standart açıklamayı alternatif bir model olarak tamamlamaktadır",
        aciklama: "Hayden’ın hipotezi, standart açıklamayı çürütmekten ziyade tamamlayan alternatif bir model sunar. İki model farklı topluluklar, dönemler veya bölgeler için geçerli olabilir; bu nedenle 'hangisi doğru?' sorusu yerine 'hangi koşullarda hangi model geçerli?' sorusu sorulmalıdır. Bu soru, rakip hipotezleri birlikte değerlendirme yeteneğini test etmektedir."
    },
    {
        soru: "<i>\"Britanyalı tarihçi E.P. Thompson, Customs in Common (1991) adlı eserinde köylü direnişini incelerken şunu saptadı: Tarım toplumlarında köylüler, tahıllarının bir kısmını devlete ya da toprak sahibine vermek zorunda kaldığında ürününü gizlemek, kalitesizini teslim etmek ve takvimi geciktirmek gibi sessiz direnç biçimleri geliştirdi. Bu, tahılın hem bir iktidar aracı hem de bir direniş nesnesi olduğunu ortaya koymaktadır.\" (Kaynak: E.P. Thompson, Customs in Common, 1991, s. 188 – uyarlanmıştır)</i><br><br><b>Thompson’ın bu gözlemi, erken tarım toplumlarındaki güç ilişkileri hakkında hangi karmaşık tabloyu ortaya koymaktadır?</b>",
        secenekler: [
            "A) Köylüler tarım toplumlarında tamamen pasif ve boyun eğen bir sınıftı",
            "B) Tahıl, yalnızca iktidarın elindeki bir araçtı; toplumun alt tabakalarının buna erişimi yoktu",
            "C) Tahıl hem sömürünün hem de ona karşı sessiz direncin nesnesi olarak çift anlamlı bir toplumsal rol üstlendi",
            "D) Erken tarım toplumlarında sınıf çatışması hiç yaşanmadı",
            "E) Thompson'ın gözlemleri yalnızca modern dönem için geçerlidir"
        ],
        cevap: "C) Tahıl hem sömürünün hem de ona karşı sessiz direncin nesnesi olarak çift anlamlı bir toplumsal rol üstlendi",
        aciklama: "Thompson, tahılın hem yönetici sınıfın denetim aracı hem de köylünün gizleyerek direndiği bir nesne olduğunu göstermektedir. Bu çift anlam, erken tarım toplumlarındaki güç ilişkilerini tek boyutlu bir sömürü anlatısından çok daha karmaşık bir müzakere ve direniş alanı olarak okumayı gerektirir."
    },
    {
        soru: "<i>\"Paleobotanikçi Dolores Piperno, güneybatı Meksika'da yapılan araştırmada MÖ 9000 yıllarına tarihlenen mısır atası teosinte bitkisinin mikrofosil kalıntılarını saptadı. Bu bulgular, mısırın kültüre alınmasının çok daha uzun ve aşamalı bir süreç olduğunu; ani bir \"devrim\" yerine yüzyıllar boyu süren seçici hasat ve iyileştirme pratiklerini kapsadığını ortaya koymaktadır.\" (Kaynak: Dolores Piperno et al., Starch Grain and Phytolith Evidence for Early Ninth Millennium Maize Use in Mexico, Nature, 2009)</i><br><br><b>Piperno’nun bulguları, 'Tarım Devrimi' kavramının kendisini nasıl sorunsallaştırmaktadır?</b>",
        secenekler: [
            "A) Tarım Meksika’da değil Mezopotamya’da başladığını kanıtlamaktadır",
            "B) 'Devrim' metaforu ani ve keskin bir değişimi çağrıştırırken, arkeolojik kanıtlar tarımın yüzyıllar süren kademeli bir dönüşüm olduğunu göstermekte; bu nedenle kavramın kendisi tartışmalıdır",
            "C) Mısır kültürü, seçici hasat değil tesadüfle başlamıştır",
            "D) MÖ 9000 tarihi, tarımın Mezopotamya’daki başlangıcıyla aynı döneme denk düşmektedir",
            "E) Mikrofosil yöntemi tarihsel araştırmalarda güvenilir değildir"
        ],
        cevap: "B) 'Devrim' metaforu ani ve keskin bir değişimi çağrıştırırken, arkeolojik kanıtlar tarımın yüzyıllar süren kademeli bir dönüşüm olduğunu göstermekte; bu nedenle kavramın kendisi tartışmalıdır",
        aciklama: "'Devrim' sözcüğü ani bir kırılmayı çağrıştırır. Oysa Piperno’nun bulguları, kültüre alma sürecinin binlerce yıla yayıldığını göstermektedir. Bu, kavramsal bir sorundur: tarihçilerin kullandığı 'devrim' etiketinin gerçeği ne ölçüde yansıttığı sorgulanmalıdır. Bu düzeyde kavramsal öz-eleştiri ileri analiz becerisi gerektirmektedir."
    },
    {
        soru: "<i>\"Arkeolog David Graeber ve David Wengrow, The Dawn of Everything (2021) adlı eserlerinde şöyle yazar: Tarih boyunca tarım yapan topluluklarda siyasi hiyerarşi kaçınılmaz değildi. Bazı Kuzey Amerika yerli toplulukları tarım yapıyor, ancak yönetici sınıf oluşturmuyordu; şefler savaş dönemlerinde seçilir, barış döneminde yetkileri sınırlandırılır, hatta görevden alınırdı.\" (Kaynak: David Graeber & David Wengrow, The Dawn of Everything, 2021, s. 146 – uyarlanmıştır)</i><br><br><b>Graeber ve Wengrow’un bu tezi, 'tarım zorunlu olarak devlet ve hiyerarşi doğurur' varsayımına karşı nasıl bir argüman oluşturmaktadır?</b>",
        secenekler: [
            "A) Tarım yapmayan tüm topluluklar eşitlikçidir; bu nedenle tarım hiyerarşiyle özdeştir",
            "B) Tarım, hiyerarşiyi engelleyen bir ekonomik yapı üretir",
            "C) Tarımla hiyerarşi arasındaki bağ tarihsel bir zorunluluk değil, insan tercihlerinin şekillendirdiği koşullara bağlı bir olgudur",
            "D) Graeber ve Wengrow, tarıma karşı argüman öne sürmektedir",
            "E) Kuzey Amerika tarım toplulukları merkezi devlet kurmuştur"
        ],
        cevap: "C) Tarımla hiyerarşi arasındaki bağ tarihsel bir zorunluluk değil, insan tercihlerinin şekillendirdiği koşullara bağlı bir olgudur",
        aciklama: "Tarım yapan ama hiyerarşi kurmayan toplulukların varlığı, 'tarım → hiyerarşi' ilişkisinin evrensel bir yasadan ziyade belirli koşullara bağlı tarihsel bir olgu olduğunu kanıtlamaktadır. Bu, determinist açıklamaları reddeden ve insan iradesini tarihin yapıcısı olarak öne çıkaran önemli bir karşı-argümandır."
    },
    {
        soru: "<i>\"Nörobiyolog Suzana Herculano-Houzel, insan beyninin büyük enerji talebini karşılamak için günde yaklaşık 2000 kaloriye ihtiyaç duyduğunu hesaplamıştır. Pişirme ve tahıl işleme, bu kalorik yükü sindirim sistemine bindirmeden karşılamayı mümkün kıldı. Herculano-Houzel'e göre tahıl tarımı ve ateşin birleşimi, beyin evriminin son aşamasını besleyen kritik teknolojiydi.\" (Kaynak: Suzana Herculano-Houzel, The Human Advantage, 2016, s. 89 – uyarlanmıştır)</i><br><br><b>Bu nörobiyolojik argüman, Tarım Devrimi’nin önemi konusunda hangi disiplinlerarası çerçeveyi açmaktadır?</b>",
        secenekler: [
            "A) Tarım yalnızca ekonomik bir devrim olup biyolojik etkisi yoktur",
            "B) Tarımsal tahıl üretimi ile pişirme teknolojisinin birleşimi, beynin yüksek enerji talebini sürdürülebilir kılarak insan bilişsel kapasitesinin korunmasını ve gelişmesini biyolojik düzeyde desteklemiştir",
            "C) Büyük beyin, tahıl tarımından önce de mevcut enerjiyle beslenebiliyordu",
            "D) Nörobiyoloji tarihsel açıklama için güvenilir bir kaynak değildir",
            "E) Pişirme teknolojisi tarımdan önce gelişmiş ve tarımı gereksiz kılmıştır"
        ],
        cevap: "B) Tarımsal tahıl üretimi ile pişirme teknolojisinin birleşimi, beynin yüksek enerji talebini sürdürülebilir kılarak insan bilişsel kapasitesinin korunmasını ve gelişmesini biyolojik düzeyde desteklemiştir",
        aciklama: "Herculano-Houzel, tarımı nörobiyolojik bir perspektiften ele alarak tahılın 2000 kalorilik beyin talebini karşılamayı mümkün kıldığını öne sürmektedir. Bu argüman, tarihsel açıklamayı biyolojik evrim bulgularıyla ilişkilendiren disiplinlerarası bir çerçeve açmaktadır. Bu soruyu yanıtlamak hem metni hem de disiplinlerarası bütünleşmeyi anlamayı gerektirmektedir."
    },
    {
        soru: "<i>\"Çevre tarihçisi William Cronon, Changes in the Land (1983) adlı eserinde şunu saptar: Avrupa'lı kolonizatörler Kuzey Amerika'ya ulaştığında, yerlilerin \"boş\" saydıkları toprakların aslında avcı-toplayıcı ve bahçecilik pratikleriyle dikkatlice yönetilen alanlar olduğunu görmediler. Avrupa tarım modeli toprağı ekili-ekilmez; ormanı işlenmiş-işlenmemiş olarak sınıflandırıyordu; bu ikili sınıflandırma toprak gaspını meşrulaştırdı.\" (Kaynak: William Cronon, Changes in the Land, 1983, s. 57 – uyarlanmıştır)</i><br><br><b>Cronon’ın analizi, tarım kavramının siyasi boyutu açısından nasıl okunabilir?</b>",
        secenekler: [
            "A) Cronon, tarımın icat edilmemesi gerektiğini savunmaktadır",
            "B) Tarımın nasıl tanımlandığı, kimin toprağı ne amaçla kullandığını meşru ya da gayri meşru ilan etme gücüne sahiptir; tarım kavramı ideolojik bir araç olarak işleyebilir",
            "C) Avrupa tarım modeli her koşulda kuzey Amerika topraklarına uygun bir sistemdir",
            "D) Yerli toplulukların toprak yönetimi, tarımsal üretimi hiç içermiyordu",
            "E) Cronon'ın analizi yalnızca ekonomik bir perspektif sunmaktadır"
        ],
        cevap: "B) Tarımın nasıl tanımlandığı, kimin toprağı ne amaçla kullandığını meşru ya da gayri meşru ilan etme gücüne sahiptir; tarım kavramı ideolojik bir araç olarak işleyebilir",
        aciklama: "Cronon, tarımın tanımının siyasi bir araç olduğunu göstermektedir: 'Ekilmiş toprak meşru mülkiyet, ekilmemiş toprak sahipsiz' ikiliği, toprak gaspını hukuken meşrulaştırmıştır. Bu, kavramların nasıl iktidar ilişkilerinin hizmetine girdiğini gösterdiğinden ileri düzey eleştirel düşünme gerektirmektedir."
    },
    {
        soru: "<i>\"Arkeolog Steven Mithen, After the Ice (2003) adlı eserinde şöyle sorar: Tarım çok daha az efor gerektiren avcı-toplayıcılık yerine neden seçildi? Mithen'in yanıtı şudur: Tarıma geçiş, özgür bir tercih değil, Genç Dryas iklim krizi sırasında artan nüfus baskısı, kaynakların daralması ve avcı-toplayıcılığın artık yeterli olmamasının bileşik etkisiyle ortaya çıkan zorunlu bir uyum stratejisiydi.\" (Kaynak: Steven Mithen, After the Ice: A Global Human History 20,000–5000 BC, 2003, s. 504 – uyarlanmıştır)</i><br><br><b>Mithen’in argümanı, Tarım Devrimi’nin genel yorumuna nasıl bir katkı sağlamaktadır? Bu argümanın zayıf yönü nedir?</b>",
        secenekler: [
            "A) Mithen tarımın bilinçli ve özgür bir tercih olduğunu savunur; bu yorumu destekleyen kanıtlar güçlüdür",
            "B) Mithen tarımı bir zorunluluk stratejisi olarak konumlandırmaktadır; bu güçlü bir argüman olmakla birlikte, Hayden’ın prestij odaklı tezi gibi farklı bölgelerdeki tarımın başlangıcını açıklamakta yetersiz kalabilmesi onun sınırlılığıdır",
            "C) Mithen'in iklim krizi argümanı, Genç Dryas'ın tarımla zaman olarak örtüşmediğinden geçersizdir",
            "D) Nüfus baskısı, tarım başlamadan önce ortadan kalkmıştır",
            "E) Mithen, Hayden ile tamamen aynı modeli savunmaktadır"
        ],
        cevap: "B) Mithen tarımı bir zorunluluk stratejisi olarak konumlandırmaktadır; bu güçlü bir argüman olmakla birlikte, Hayden’ın prestij odaklı tezi gibi farklı bölgelerdeki tarımın başlangıcını açıklamakta yetersiz kalabilmesi onun sınırlılığıdır",
        aciklama: "Mithen, tarımı çevre baskısına verilen zorunlu bir yanıt olarak konumlandırmaktadır; bu açıklama iklim verileriyle tutarlıdır. Ancak bu model, Güneydoğu Türkiye gibi kaynak bakımından zengin bölgelerdeki erken tarım merkezlerini ya da Hayden’ın prestij güdümlü tarım başlangıcını tam olarak açıklayamaz. Bu soruyu yanıtlamak hem bir argümanın güçlü yönlerini hem de sınırlılıklarını aynı anda değerlendirmeyi gerektirdiğinden zordur."
    }
];
window.allTests = window.allTests || {};

// --- 2. ÜNİTE: TARIM DEVRİMİNİN ESKİ ÇAĞ'A ETKİLERİ - TEST 3 ---
window.allTests["test_u2_tarim_3"] = [
    {
        soru: "<i>\"Tarihöncesi insanların beslenme alışkanlıklarını inceleyen bilim insanları, MÖ 10.000 öncesinde insanların yüzde doksanından fazlasının av hayvanları, yabani meyveler, kökler ve tahıllarla geçindiğini saptamıştır. Tarımın başlamasıyla birlikte bu oran dramatik biçimde değişti; kısa süre içinde nüfusun büyük çoğunluğu kendi yetiştirdiği yiyeceklerle beslenir oldu.\" (Kaynak: Richard Wrangham, Catching Fire: How Cooking Made Us Human, 2009, s. 14 – uyarlanmıştır)</i><br><br><b>Bu metne göre Tarım Devrimi’nin beslenme düzeni üzerindeki en temel etkisi nedir?</b>",
        secenekler: [
            "A) İnsanları yalnızca et tüketimine yönlendirmesi",
            "B) Avlanma ve toplayıcılığın tamamen yok olması",
            "C) İnsanların büyük ölçüde kendi ürettikleri besinlerle beslenmeye başlaması",
            "D) Nüfusun azalarak küçük gruplara bölünmesi",
            "E) Tahıl dışındaki besin kaynaklarının tüketilmesinin yasaklanması"
        ],
        cevap: "C) İnsanların büyük ölçüde kendi ürettikleri besinlerle beslenmeye başlaması",
        aciklama: "Doğru cevap C’dir. Metin, tarımın nüfusun büyük çoğunluğunu kendi yetiştirdiği besinlerle geçinir hâle getirdiğini belirtmektedir. Bu, beslenme düzeninin üretim eksenli bir dönüşüm geçirdiğini ifade eder. Avlanmanın tamamen yok olması veya tek tip beslenme metinde desteklenmemektedir."
    },
    {
        soru: "<i>\"Kazılarda bulunan en eski tarım aletleri arasında çakmaktaşından yapılmış oraklar ve tahıl öğütme taşları yer almaktadır. Bu aletler ilk kez Verimli Hilal bölgesinde MÖ 10.000-9000 yıllarına ait katmanlarda yoğun biçimde ortaya çıkmaktadır. Araştırmacılar bu bulguları tarımın mekânsal başlangıcına dair önemli kanıtlar olarak değerlendirmektedir.\" (Kaynak: Ofer Bar-Yosef, The Natufian Culture in the Levant, Evolutionary Anthropology, 1998 – uyarlanmıştır)</i><br><br><b>Bu arkeolojik bulgu, tarım tarihinin araştırılmasında hangi yönteme örnek oluşturmaktadır?</b>",
        secenekler: [
            "A) Yazılı belgelerin incelenmesiyle tarihin aydınlatılması",
            "B) Materyal kalıntılar (aletler) aracılığıyla geçmiş faaliyetlerin belirlenmesi",
            "C) Sözlü geleneklerin kaydedilerek tarihsel kaynak olarak kullanılması",
            "D) İklim verilerinden uygarlık süreçlerinin yeniden oluşturulması",
            "E) Genetik analizlerle bitki türlerinin izlenmesi"
        ],
        cevap: "B) Materyal kalıntılar (aletler) aracılığıyla geçmiş faaliyetlerin belirlenmesi",
        aciklama: "Doğru cevap B’dir. Metin, orak ve öğütme taşı gibi materyal kalıntıların tarımın ne zaman ve nerede başladığını belirlemeye yarayan arkeolojik kanıtlar olduğunu vurgulamaktadır. Bu, arkeolojinin materyel kalıntılar yoluyla geçmişi aydınlatma yöntemine örnektir."
    },
    {
        soru: "<i>\"Mısır'da Firavun Tutmosis III dönemine ait bir tapınak yazıtı şöyle der: Kral, tahılı toplar; depoyu doldurur; yoksulu doyurur; ülkeyi besler. Anbarlar taştıkça halk sevinir; firavunun eli her zaman açıktır.\" (Kaynak: Karnak Tapınağı yazıtı, MÖ yaklaşık 1450 – uyarlanmış çeviri)</i><br><br><b>Bu yazıta göre Mısır’da firavunun tahıl yönetimiyle ilişkisi nasıl kurulmaktadır?</b>",
        secenekler: [
            "A) Firavun tahılı yalnızca dini törenler için saklamaktaydı",
            "B) Firavunun otoritesi kısmen tahıl depolama ve dağıtımını kontrol etme üzerine inşa edilmişti",
            "C) Tahıl yönetimi yalnızca din adamlarına aitti",
            "D) Yazıt, firavunun tarım yapmadığını kanıtlamaktadır",
            "E) Tahıl ambarları halkın ortak mülkiyetindeydi"
        ],
        cevap: "B) Firavunun otoritesi kısmen tahıl depolama ve dağıtımını kontrol etme üzerine inşa edilmişti",
        aciklama: "Doğru cevap B’dir. Yazıt, firavunu tahılı toplayıp depolayan ve halkı doyuran kişi olarak tanımlamaktadır. Bu, siyasi meşruiyetin tarımsal kaynak yönetimiyle iç içe geçtiğini göstermektedir. Din adamı rolü ya da ortak mülkiyet metinde geçmez."
    },
    {
        soru: "<i>\"Mezopotamya'da tahıl üretimine bağlı olarak ortaya çıkan ölçüm sistemleri son derece çeşitlidir: Arpa ölçeği olan \"gur\", tahıl ağırlık birimi \"mina\" ve arazi ölçüm birimi \"iku\" bu sistemin temel unsurlarıdır. Tüm bu birimler önce ambar ve arazi yönetiminde kullanılmış; daha sonra genel ekonomik işlemlere uyarlanmıştır.\" (Kaynak: Denise Schmandt-Besserat, From Tokens to Tablets, Visible Language, 1981 – uyarlanmıştır)</i><br><br><b>Bu metne göre Mezopotamya’da standart ölçüm sistemlerinin kaynağı nedir?</b>",
        secenekler: [
            "A) Dini törenlerde yapılan sunuların ölçülmesi ihtiyacı",
            "B) Askeri malzeme tespitinin gerektirdiği düzenleme",
            "C) Tahıl ve arazi yönetiminin doğurduğu pratik ölçüm gereksinimleri",
            "D) Yabancı tüccarlardan ithal edilen ölçüm sistemi",
            "E) Matematik öğretimi için geliştirilen eğitim araçları"
        ],
        cevap: "C) Tahıl ve arazi yönetiminin doğurduğu pratik ölçüm gereksinimleri",
        aciklama: "Doğru cevap C’dir. Metin açıkça tüm ölçüm birimlerinin önce ambar ve arazi yönetiminde kullanıldığını, sonra genel ekonomiye yayıldığını belirtmektedir. Tahıl ve arazi yönetimi, standart ölçüm sisteminin doğrudan kaynağıdır."
    },
    {
        soru: "<i>\"Neolitik dönemin ünlü Anadolu yerleşimi Aşıklı Höyük'te yapılan kazılarda araştırmacılar, tahıl tohumlarının depolandığı özel odalar saptadı. Bu odaların duvarları kalın çamurla sıvanmış, içleri havadar tutulmuştu. Bilim insanları bu bulguyu, toplulukların artık günlük tüketime değil ileriye dönük planlara göre depolama yaptığının kanıtı olarak yorumladı.\" (Kaynak: Mihriban Özbaşaran, Aşıklı Höyük: A Steppingstone in the Anatolian Neolithic, NEO-LITHICS, 2012 – uyarlanmıştır)</i><br><br><b>Bu bulgu, erken tarım toplumlarının davranışsal dönüşümü hakkında ne söylemektedir?</b>",
        secenekler: [
            "A) İnsanlar tarımla birlikte tahılı yalnızca dini amaçla depolamaya başlamıştır",
            "B) Tarım, toplulukları anlık tüketimden geleceği planlayan bir düşünce biçimine yöneltmiştir",
            "C) Depolama teknolojisi tarımdan önce gelişmiştir",
            "D) Aşıklı Höyük'te tarım yerine yalnızca hayvancılık yapılmıştır",
            "E) Kalın duvarlı odalar yalnızca savunma amaçlıydı"
        ],
        cevap: "B) Tarım, toplulukları anlık tüketimden geleceği planlayan bir düşünce biçimine yöneltmiştir",
        aciklama: "Doğru cevap B’dir. Depolama odalarının özel olarak inşa edilmesi, toplulukların günlük tüketime değil geleceğe yönelik planlamaya göre davrandığını göstermektedir. Bu, tarımın zamansal düşünceyi ve öngörülü davranışı teşvik ettiğini ortaya koymaktadır."
    },
    {
        soru: "<i>\"Eski Mısır'da \"şaduf\" adı verilen basit kaldıraç sistemi, nehir suyunu tarım arazilerine aktarmak için kullanılıyordu. Tek bir köylünün bir günde sulayabileceği arazi miktarı şaduf sayesinde birkaç katına çıkıyordu. Bu araç, Nil'in uzağındaki arazileri de tarıma açarak Mısır'ın ekilebilir toprak alanını önemli ölçüde genişletti.\" (Kaynak: MEB 9. Sınıf Tarih Ders Kitabı, 2023, s. 42 – uyarlanmıştır)</i><br><br><b>Bu metne göre şadufun tarımsal önemi nereden kaynaklanmaktadır?</b>",
        secenekler: [
            "A) Tarım aletlerinin taşınmasını kolaylaştırmasından",
            "B) Nehre uzak arazilerin sulanmasını mümkün kılarak ekilebilir toprak alanını genişletmesinden",
            "C) Tahılın öğütülmesini hızlandırmasından",
            "D) Hayvanları sulama işinden kurtarmasından",
            "E) Depolama kapasitesini artırmasından"
        ],
        cevap: "B) Nehre uzak arazilerin sulanmasını mümkün kılarak ekilebilir toprak alanını genişletmesinden",
        aciklama: "Doğru cevap B’dir. Metin, şadufun Nil uzağındaki arazileri sulamayı mümkün kılarak ekilebilir alanı genişlettiğini açıkça ifade etmektedir. Bu, teknolojik bir buluşun tarımsal üretim kapasitesini nasıl artırdığının somut bir örneğidir."
    },
    {
        soru: "<i>\"Sümer şiiri \"Çiftçi Almanağı\"nda bir baba, oğluna tarla işlerini öğretir: Kanallarını temiz tut, sabanını hazırla; düvenini hazır et; mülkünü koru. Tarlana hayvanların çiğnemesine izin verme; ekeceksen bugün ek; yarına bırakma. Bir çiftçi tembelse tarla onu cezalandırır; ama çalışkanı ödüllendirir.\" (Kaynak: Thorkild Jacobsen (çev.), The Farmer's Almanac, MÖ yaklaşık 1700 – uyarlanmıştır)</i><br><br><b>Bu Sümer şiiri, tarım toplumunun değer yargıları hakkında ne ortaya koymaktadır?</b>",
        secenekler: [
            "A) Sümer çiftçileri tarım yerine ticareti tercih etmiştir",
            "B) Çalışkanlık, öngörü ve mülkün korunması tarım toplumunun temel erdemleri hâline gelmiştir",
            "C) Tarım almanağı yalnızca eğitim amaçlı değil dini bir metin olarak yazılmıştır",
            "D) Sümer'de tarım tamamen devlet tarafından yönetilmiştir",
            "E) Tembel çiftçiler Sümer'de cezalandırılmamıştır"
        ],
        cevap: "B) Çalışkanlık, öngörü ve mülkün korunması tarım toplumunun temel erdemleri hâline gelmiştir",
        aciklama: "Doğru cevap B’dir. Şiir, iyi bir çiftçiyi tanımlarken çalışkanlık (gecikmeden ek), öngörü (aleti hazırla), mülk koruma (hayvanları uzak tut) değerlerini öne çıkarmaktadır. Bu değerler tarım toplumunun öngörü ve emek etiğini yansıtmaktadır."
    },
    {
        soru: "<i>\"Anadolu'da Neolitik dönem köylerinde uygulanan bir mimari özellik dikkat çekmektedir: Evler birbirinden bağımsız değil, ortak duvar paylaşan ve avlu çevresinde kümelenen bir düzende inşa edilmiştir. Arkeologlar bu düzeni, toplu tahıl işleme ve depolama pratiklerinin fiziksel mekâna yansıması olarak yorumlamaktadır.\" (Kaynak: Bleda During, The Prehistory of Asia Minor, 2011, s. 88 – uyarlanmıştır)</i><br><br><b>Bu mimari düzenin tarımsal ekonomiyle ilişkisi nasıl kurulabilir?</b>",
        secenekler: [
            "A) Ortak duvar paylaşımı, toplulukların savunmayı ön planda tutuğunu göstermektedir",
            "B) Mimari düzen, tahıl işleme ve depolama gibi kolektif tarımsal pratiklerin yaşam alanını nasıl biçimlendirdiğini ortaya koymaktadır",
            "C) Bu düzen, Neolitik toplulukların tarım yapmadığını kanıtlamaktadır",
            "D) Avlu merkezli yapılar, dinî törenler için özel olarak tasarlanmıştır",
            "E) Bağımsız konutlar tarım öncesinde de görülmektedir"
        ],
        cevap: "B) Mimari düzen, tahıl işleme ve depolama gibi kolektif tarımsal pratiklerin yaşam alanını nasıl biçimlendirdiğini ortaya koymaktadır",
        aciklama: "Doğru cevap B’dir. Araştırmacılar ortak avlu ve paylaşımlı duvar düzenini kolektif tahıl işleme ve depolama pratikleriyle ilişkilendirmektedir. Bu, tarımsal ekonominin yalnızca üretim biçimini değil, fiziksel yaşam alanının organizasyonunu da dönüştürdüğünü göstermektedir."
    },
    {
        soru: "<i>\"MÖ 3. binyılda Mezopotamya'da \"ub\" adı verilen yazıcılar, her gün tapınak ambarına giren ve çıkan tahıl miktarını kil tabletlere kaydediyordu. Bu tabletler bugün bilinen en eski muhasebe kayıtlarıdır. Tahılın miktarını takip eden bu sistem aynı zamanda, kimin ne kadar çalıştıığını ve kime ne kadar ödeneceğini de düzenliyordu.\" (Kaynak: Robert Englund, Hard Work: Where Will It Get You? Journal of Near Eastern Studies, 1991 – uyarlanmıştır)</i><br><br><b>Bu muhasebe sisteminin tarihsel önemi hangi çerçevede değerlendirilebilir?</b>",
        secenekler: [
            "A) Yazıcılar yalnızca dini metinleri kopyalamak için eğitilmiştir",
            "B) Tahıl muhasebesinin gerekliliği, hem yazı hem de emek yönetimi sistemlerinin birlikte gelişmesini tetiklemiştir",
            "C) Bu kayıtlar, Mezopotamya'da özel mülkiyetin hiç olmadığını kanıtlamaktadır",
            "D) Muhasebe sistemi tahıl ticaretiyle değil yalnızca vergi toplamakla ilgilidir",
            "E) Kil tablet kayıtları ekonomik değil yalnızca siyasi bilgi içermektedir"
        ],
        cevap: "B) Tahıl muhasebesinin gerekliliği, hem yazı hem de emek yönetimi sistemlerinin birlikte gelişmesini tetiklemiştir",
        aciklama: "Doğru cevap B’dir. Tahıl ambarı kayıtları hem yazı sistemini hem de emek örgütlenmesini (kimin ne kadar çalıştığı, kime ne ödeneceği) aynı anda düzenlemiştir. Bu, tarımsal üretimin muhasebe ihtiyacının birden fazla kurumsal yapıyı eş zamanlı olarak doğurduğunu göstermektedir."
    },
    {
        soru: "<i>\"Antik Mısır tıp papirüsü Ebers Papirüsü'nde (MÖ 1550) buğday tohumları ve arpa ununun çeşitli hastalıkların tedavisinde kullanıldığı yazılmaktadır. Araştırmacılar bu durumu yalnızca tıbbi bilgiyle değil, aynı zamanda tahılın toplumda ne denli merkezi bir kaynak olduğuyla açıklamaktadır: Her zaman bulunan tahıl, tıpta da başvurulan ilk malzeme oldu.\" (Kaynak: John Nunn, Ancient Egyptian Medicine, 1996, s. 136 – uyarlanmıştır)</i><br><br><b>Bu bulgu, tarımsal ürünlerin Eski Mısır toplumundaki işlevi hakkında nasıl yorumlanabilir?</b>",
        secenekler: [
            "A) Tahıl yalnızca besin değil, toplumun her alanına nüfuz eden temel bir kaynak hâline gelmiştir",
            "B) Eski Mısır’da tıp bilimi tarımdan tamamen bağımsız gelişmiştir",
            "C) Tahıl, Mısır'da yalnızca tıbbi amaçlarla yetiştirilmiştir",
            "D) Ebers Papirüsü tarımsal değil dini bir kaynaktır",
            "E) Buğday ve arpa Mısır’da tıbbi bitki değil zehirli bitki olarak tanınmıştır"
        ],
        cevap: "A) Tahıl yalnızca besin değil, toplumun her alanına nüfuz eden temel bir kaynak hâline gelmiştir",
        aciklama: "Doğru cevap A’dır. Tahılın tıpta da kullanılması, onun yalnızca besin değil toplumsal varlığın her boyutunu şekillendiren bir temel kaynak olduğunu göstermektedir. Araştırmacılar da bunu tahılın her zaman erişilebilir olmasıyla açıklamaktadır; bu da tarımın toplumsal yaşamı ne kadar derinden etkilediğinin kanıtıdır."
    },
    {
        soru: "<i>\"MÖ 2000 yıllarında Mezopotamya'da Ur III hanedanı döneminde devlet, büyük çaplı sulama projelerini yönetmek için binlerce işçiyi görevlendirdi. Bu işçilere üretim karşılığında tahıl verildi. İşçi listeleri ve tahıl dağıtım kayıtları, Ur III dönemi arşivlerinin büyük bölümünü oluşturmaktadır. Devlet, büyük bir işveren olarak tahıl ekonomisinin merkezine yerleşmişti.\" (Kaynak: Piotr Steinkeller, Money-Lending Practices in Ur III Babylonia, Debt and Economic Renewal, 2002 – uyarlanmıştır)</i><br><br><b>Bu arşiv bulguları, erken devlet yapısıyla tarımsal ekonomi arasındaki ilişki hakkında ne söylemektedir?</b>",
        secenekler: [
            "A) Ur III devleti yalnızca askeri amaçlarla tahıl toplamıştır",
            "B) Devlet, sulama altyapısını yöneterek ve tahılı emek karşılığı ödeyerek tarımsal ekonominin baş aktörü hâline gelmiştir",
            "C) İşçiler Ur III'te gönüllü olarak çalışmış ve herhangi bir ücret almamıştır",
            "D) Tahıl arşivleri devletin ticaret politikasını değil dini harcamaları yansıtmaktadır",
            "E) Ur III'te devlet tarımsal faaliyetlerden tamamen uzak durmuştur"
        ],
        cevap: "B) Devlet, sulama altyapısını yöneterek ve tahılı emek karşılığı ödeyerek tarımsal ekonominin baş aktörü hâline gelmiştir",
        aciklama: "Doğru cevap B’dir. Devlet sulama projesini organize etmiş, işçileri tahılla ödemiş ve bu sürecin tamamını arşivlemiştir. Bu, devletin tarımsal ekonominin yalnızca düzenleyicisi değil, doğrudan baş aktörü olduğunu kanıtlamaktadır. Arşivlerin büyük bölümünün bu kayıtlardan oluşması, devlet ile tarım arasındaki organik bağı somutlaştırmaktadır."
    },
    {
        soru: "<i>\"Hintli yazar Amitav Ghosh, tarihsel romanı Sea of Poppies'de (2008) şöyle yazar: Tahıl, toprağın hafızasıdır; tohumun içinde o toprağın tüm geçmişi, o nehrin tüm taşkınları, o çiftçinin tüm alın teri saklanmaktadır. Bir toplumu anlayacaksan, hangi tohumu ektiğine bak.\" (Kaynak: Amitav Ghosh, Sea of Poppies, 2008 – uyarlanmış Türkçe çeviri)</i><br><br><b>Ghosh’un bu edebi metaforu, tarih araştırmacıları için nasıl bir metodolojik öneri içermektedir?</b>",
        secenekler: [
            "A) Tahılın kimyasal bileşimini inceleyerek toplumları anlamak gerekir",
            "B) Bir toplumun temel tarım ürününü incelemek, o toplumun coğrafyası, ekonomisi ve kültürü hakkında kapsamlı ipuçları sunabilir",
            "C) Edebî metinler tarih araştırmasında kullanılamaz",
            "D) Ghosh'un metaforu yalnızca Güney Asya toplumları için geçerlidir",
            "E) Tohum incelemesi jeolojik değil yalnızca biyolojik bir yöntemdir"
        ],
        cevap: "B) Bir toplumun temel tarım ürününü incelemek, o toplumun coğrafyası, ekonomisi ve kültürü hakkında kapsamlı ipuçları sunabilir",
        aciklama: "Doğru cevap B’dir. Ghosh’un 'Hangi tohumu ektiğine bak' metaforu, temel tarım ürününün o toplumun coğrafyasını (taşkın, nehir), ekonomisini (alın teri) ve tarihini (toprağın hafızası) yansıttığını ileri sürmektedir. Bu, tarım ürününü bir toplumsal analiz penceresi olarak kullanan bir metodolojik tutuma işaret eder."
    },
    {
        soru: "<i>\"Arkeolog Kent Flannery, Oaxaca vadisinde (Meksika) yaptığı kazılarda ilginç bir düzen saptadı: İlk köylerde tüm ailelerin evi benzer büyüklükte ve benzer malzemeyle yapılmıştı; tahıl depolama alanları da eşit biçimde dağıtılmıştı. Sonraki yüzyıllarda bazı evler büyürken diğerleri küçük kaldı; bazı ambarlar büyüdü, diğerleri kayboldu.\" (Kaynak: Kent Flannery, The Early Mesoamerican Village, 1976, s. 162 – uyarlanmıştır)</i><br><br><b>Bu arkeolojik değişim, toplumsal yapı açısından nasıl yorumlanabilir?</b>",
        secenekler: [
            "A) Köy nüfusu zamanla azaldığından evler küçülmüştür",
            "B) Tahıl depolama kapasitesindeki farklılaşma, eşitlikçi yapıdan hiyerarşik sınıflaşmaya geçişin arkeolojik izini oluşturmaktadır",
            "C) Büyük evler din adamlarına aitti; bu durum ekonomik farklılıkla ilgisizdir",
            "D) Ambar farkları yalnızca ailelerin büyüklüğüyle açıklanabilir",
            "E) İlk dönem köyleri hiçbir zaman eşitlikçi değildi"
        ],
        cevap: "B) Tahıl depolama kapasitesindeki farklılaşma, eşitlikçi yapıdan hiyerarşik sınıflaşmaya geçişin arkeolojik izini oluşturmaktadır",
        aciklama: "Doğru cevap B’dir. İlk dönemde eşit dağılımın görülmesi, zamanla bazı evlerin ve ambarların büyümesi, eşitlikçi bir başlangıçtan sınıfsal farklılaşmaya geçişi yansıtmaktadır. Tahıl depolama kapasitesindeki fark, ekonomik eşitsizliğin maddî göstergesidir; bu ilişkiyi kurmak analitik düşünce gerektirir."
    },
    {
        soru: "<i>\"Zerdüşt kutsal metni Avesta'da tarım şu sözlerle yüceltilmektedir: Kim buğday eker, o iyiyi eker; dini yaşatır ve Ahura Mazda'yı besler. Tarım yapan ellerin en kutsal ellere yakın olduğunu bil. Tohumu toprağa gömmek, kötülüğün köklerini sökmek gibidir.\" (Kaynak: Avesta, Vendidad Bölümü, 3. Fargard – uyarlanmış çeviri)</i><br><br><b>Bu kutsal metin, tarımın antik İran toplumundaki konumunu nasıl ortaya koymaktadır?</b>",
        secenekler: [
            "A) Zerdüştlükte tarım ekonomik değil yalnızca simgesel bir etkinliktir",
            "B) Tarım, dinî bir yükümlülük ve ahlaki bir erdem olarak kutsallaştırılmıştır; bu da tarımın toplumsal meşruiyet sistemine entegre edildiğini gösterir",
            "C) Avesta, tarımı kötü bir eylem olarak nitelendirmiştir",
            "D) Bu metin, Zerdüştlüğün tarıma karşı çıktığının kanıtıdır",
            "E) Tarım yalnızca din adamlarına ayrılmış kutsal bir meslektir"
        ],
        cevap: "B) Tarım, dinî bir yükümlülük ve ahlaki bir erdem olarak kutsallaştırılmıştır; bu da tarımın toplumsal meşruiyet sistemine entegre edildiğini gösterir",
        aciklama: "Doğru cevap B’dir. Avesta, tarımı Ahura Mazda’yı besleme ve kötülüğü yenme metaforuyla dinî bir erdem olarak sunmaktadır. Bu, tarımın salt ekonomik değil dinî-ahlaki bir anlam kazandığını göstermektedir. Tarımın meşruiyet sistemine entegre edilmesi, tarımsal toplumların ideolojik yapısını anlamak için kritik bir örnektir."
    },
    {
        soru: "<i>\"Paleobiyolog Eitan Tchernov, Yakın Doğu'daki erken köy yerleşimlerinde fare, serçe ve böcek türlerinin kemik ve izlerini inceledi. İnsan tahıl depolayan yerlere taşındıkça bu türler de insanın peşinden geldi. Tahıl ambarları, insanların kasıtsız olarak yarattığı yeni bir ekolojik niş oluşturdu; bu niş beraberinde yeni parazit ve hastalık vektörlerini de getirdi.\" (Kaynak: Eitan Tchernov, The Impact of Early Animal Domestication on the Urban Landscape, 1991 – uyarlanmıştır)</i><br><br><b>Bu ekolojik bulgu, tarımın beklenmedik sonuçları açısından ne söylemektedir?</b>",
        secenekler: [
            "A) Tahıl depolama, doğayı tamamen insan kontrolüne almıştır",
            "B) Tarım, kasıtsız olarak yeni hayvan türleri, parazitler ve hastalık vektörlerini çeken ekolojik nişler yaratmıştır",
            "C) Farelerin insan yerleşimlerine yaklaşması tahılın azalmasına yol açmamıştır",
            "D) Erken köy sakinleri fare ve böcekleri kasıtlı olarak yerleşime çekmiştir",
            "E) Parazitler tarım toplumlarını hiçbir zaman etkilememiştir"
        ],
        cevap: "B) Tarım, kasıtsız olarak yeni hayvan türleri, parazitler ve hastalık vektörlerini çeken ekolojik nişler yaratmıştır",
        aciklama: "Doğru cevap B’dir. Tahıl depoları, insanın planlamadığı yeni ekolojik ortamlar yarattı. Bu ortamlara fare ve böcekler gibi türler taşındı; bunlar da hastalık vektörü işlevi gördü. Tarımın hem üretim hem de ekolojik yıkım açısından çift yönlü bir süreç olduğunu kavramak analitik düşünce gerektirir."
    },
    {
        soru: "<i>\"Eski Ahit'in Rut kitabında, Moablu Rut'un kaynanası Naomi ile Beytlehem'e geldiği ve kalan başakları toplamak için tarlalara gittiği anlatılır. Tarla sahibi Boaz ona şöyle der: Diğer tarlalara gitme; işçilerimin peşinden git; suya ihtiyacın olunca testilerden iç. Rut, yabancı olmasına rağmen bu gelenek sayesinde topluma dahil oldu.\" (Kaynak: Rut Kitabı 2:8-9, Eski Ahit – uyarlanmıştır)</i><br><br><b>Bu hikâye, tarım toplumlarında artı ürünün toplumsal entegrasyon işleviyle ilgili hangi yorum için kanıt oluşturur?</b>",
        secenekler: [
            "A) Tarım toplumlarında yabancılar her zaman dışlanmıştır",
            "B) Tarımsal artı ürünün paylaşım gelenekleri, yabancıların topluma entegrasyonunu mümkün kılan sosyal mekanizmalar işlevi görmüştür",
            "C) Tarla sahipleri yalnızca kendi ailesini beslemekle yükümlüydü",
            "D) Rut Kitabı, tarımın ekonomik değil yalnızca dini boyutunu yansıtmaktadır",
            "E) Leket geleneği Eski Ahit'te yasaklanan bir pratiktir"
        ],
        cevap: "B) Tarımsal artı ürünün paylaşım gelenekleri, yabancıların topluma entegrasyonunu mümkün kılan sosyal mekanizmalar işlevi görmüştür",
        aciklama: "Doğru cevap B’dir. Rut’un yabancı olmasına rağmen başak toplama geleneği sayesinde hem geçimini sağlaması hem de Boaz’ın topluluğuna dahil olması, tarımsal artı ürün paylaşımının sosyal bütünleşmeye katkısını somutlaştırmaktadır. Bu hikâye, tarımın salt ekonomik değil sosyal bir mekanizma olarak işleyebileceğini göstermektedir."
    },
    {
        soru: "<i>\"Tarihçi Pierre Briant, Pers İmparatorluğu'nun yönetim biçimini incelerken şunu saptar: Büyük Pers Kralları, fethettikleri topraklarda önce sulamayı restore eder, ardından vergi sistemini kurardı. Tahıl üretiminin yeniden başladığı yerde imparatorluk iddiası da güçlenirdi. Pers yönetimi tarımsal üretimi hem refah hem de egemenlik göstergesi sayıyordu.\" (Kaynak: Pierre Briant, From Cyrus to Alexander: A History of the Persian Empire, 2002, s. 417 – uyarlanmıştır)</i><br><br><b>Bu gözlem, tarımsal altyapının imparatorluk yönetimiyle ilişkisini nasıl açıklamaktadır?</b>",
        secenekler: [
            "A) Pers Kralarının tarımsal altyapıyı restore etmesi yalnızca insani amaçlıydı",
            "B) Tarımsal altyapının yeniden işletilmesi hem ekonomik kaynak hem de siyasi egemenliğin meşruiyet aracı olarak işlev gördü",
            "C) Pers İmparatorluğu tarımı değil ticareti önceliklendirdi",
            "D) Sulama restorasyonu yalnızca askeri lojistik amaçlarla yapıldı",
            "E) Büyük Pers Kralları fethedilen topraklarda tarımı yasakladı"
        ],
        cevap: "B) Tarımsal altyapının yeniden işletilmesi hem ekonomik kaynak hem de siyasi egemenliğin meşruiyet aracı olarak işlev gördü",
        aciklama: "Doğru cevap B’dir. Briant, tarımsal üretimin yeniden başlatılmasını Pers egemenliğinin hem ekonomik kaynağı hem de meşruiyet göstergesi olarak sunmaktadır. Bu çift işlev (kaynak + meşruiyet), tarımsal altyapının siyasi iktidarla nasıl iç içe geçtiğini göstermektedir."
    },
    {
        soru: "<i>\"Japonya'da Yayoi döneminde (MÖ 300 - MS 300) pirinç tarımının Kore'den Japon adalarına aktarılmasıyla birlikte toplumda köklü dönüşümler yaşandı. Nüfus artışı hızlandı; köyler genişledi; pirinç tarlalarını sulamak için su hakları üzerinde anlaşmazlıklar baş gösterdi. Arkeologlar Yayoi'de hendek ve palisatlarla çevrili ilk korunaklı köyleri bu döneme tarihlendirmektedir.\" (Kaynak: Gina Barnes, State Formation in Japan, 2007, s. 74 – uyarlanmıştır)</i><br><br><b>Bu süreç, tarımın toplumsal çatışma ve güvenlik dinamikleriyle ilişkisi açısından ne göstermektedir?</b>",
        secenekler: [
            "A) Pirinç tarımı Japonya'da her zaman barışçıl bir süreç olarak gelişti",
            "B) Tarımsal kaynaklar (su hakları, verimli arazi) üzerindeki rekabet, savunma altyapısını ve örgütlü çatışmayı beraberinde getirdi",
            "C) Korunaklı köyler tarımdan önce de Japonya'da yaygındı",
            "D) Su hakları anlaşmazlıkları Yayoi döneminde devlet tarafından çözüldü",
            "E) Nüfus artışı savunma yapılarının inşasını gereksiz kıldı"
        ],
        cevap: "B) Tarımsal kaynaklar (su hakları, verimli arazi) üzerindeki rekabet, savunma altyapısını ve örgütlü çatışmayı beraberinde getirdi",
        aciklama: "Doğru cevap B’dir. Pirinç tarımı nüfusu artırdı ve su kaynakları üzerinde rekabeti kızıştırdı; bu rekabet korunaklı köylerin inşasını zorunlu kıldı. Bu zincir (tarım → kaynak rekabeti → savunma ihtiyacı), tarımın hem nüfus hem de çatışma dinamikleri üzerindeki etkisini bütünlüklü biçimde kavramayı gerektirmektedir."
    },
    {
        soru: "<i>\"Hitit İmparatorluğu'nda Kral Hattusili I'nin bir yazıtı şöyle der: Savaştan döndükten sonra ilk işim, sulama kanallarını tamir ettirmek oldu. Halkım acıkmış, tarlaları harap olmuştu. Kanallar akmadan ne asker beslenir ne de vergi toplanır. Savaşan kral aynı zamanda çiftçilerin efendisidir.\" (Kaynak: Hattusili I yazıtı, MÖ yaklaşık 1650 – uyarlanmış çeviri)</i><br><br><b>Bu yazıt, Hitit yönetiminde tarımsal altyapının işlevi hakkında ne söylemektedir?</b>",
        secenekler: [
            "A) Hattusili I tarım yerine ticareti önceliklendirmiştir",
            "B) Sulama altyapısı hem askeri hem de mali kapasiteyi besleyen stratejik bir temel olarak görülmüştür",
            "C) Hitit ordusunun bakımı yalnızca dış yardımlarla sağlanmıştır",
            "D) Tarla tamiri, savaştan daha az önemli bir öncelikti",
            "E) Hitit Krallığı tarım yerine hayvancılığa dayanmaktaydı"
        ],
        cevap: "B) Sulama altyapısı hem askeri hem de mali kapasiteyi besleyen stratejik bir temel olarak görülmüştür",
        aciklama: "Doğru cevap B’dir. Kral, savaştan döner dönmez sulama kanallarını tamir ettirmiştir; çünkü 'kanallar akmadan ne asker beslenir ne de vergi toplanır.' Bu ifade, tarımsal altyapının hem ordunun iaşesini hem de devlet gelirini (vergi) doğrudan beslediğini göstermektedir. Tarım burada stratejik bir ulusal güvenlik meselesidir."
    },
    {
        soru: "<i>\"Sosyolog Max Weber, Antik Yahudiliği incelerken bir paradoks saptar: İsrail peygamberleri hem tarımsal bolluğu tanrının lütfu hem de tarımsal zenginliği ahlaki çöküşün kaynağı olarak tanımlar. Baal gibi bereket tanrılarına tapınmak şiddetle eleştirilirken Yahve'ye sunulan ilk hasat sunusu bir yükümlülüktü.\" (Kaynak: Max Weber, Ancient Judaism, 1952, s. 187 – uyarlanmıştır)</i><br><br><b>Weber’in bu paradoksu, tarım ile din arasındaki ilişki açısından nasıl yorumlanabilir?</b>",
        secenekler: [
            "A) İsrail’de tarım ve din tamamen birbirinden bağımsız gelişmiştir",
            "B) Tarımsal bereket hem dinî şükranın hem de ahlaki tehlikenin kaynağı olarak kurgulanmıştır; bu gerilim, din ile tarım arasındaki bağın ne kadar karmaşık olduğunu göstermektedir",
            "C) Yahve dini bereket tanrısı olduğundan Baal ile çelişki yoktur",
            "D) İsrail peygamberleri tarımı tamamen reddetmiştir",
            "E) Hasat sunusu ekonomik bir vergi uygulamasından başka bir şey değildir"
        ],
        cevap: "B) Tarımsal bereket hem dinî şükranın hem de ahlaki tehlikenin kaynağı olarak kurgulanmıştır; bu gerilim, din ile tarım arasındaki bağın ne kadar karmaşık olduğunu göstermektedir",
        aciklama: "Doğru cevap B’dir. Weber’in paradoksu, tarımsal zenginliğin hem Tanrı’nın lütfu (şükür gerektiren nimet) hem de ahlaki tehlike (Baal gibi yanlış tanrılara yönelme riski) olarak çerçevelendiğini göstermektedir. Bu gerilim, tarım ile din arasındaki ilişkinin basit bir kutsamadan ibaret olmadığını ortaya koymaktadır."
    },
    {
        soru: "<i>\"Günümüz Etiyopyası'nda hâlâ yetiştirilen teff bitkisinin kültüre alınması MÖ 4000-3000 yıllarına dayanmaktadır. Güney Arabistan'da sorgum, Batı Afrika'da yaban darısı farklı dönemlerde bağımsız olarak kültüre alındı. Bu bölgelerin hiçbiri Yakın Doğu tarım merkezlerinden doğrudan etkilenmemişti; her biri kendi coğrafyasının sunduğu bitkilerle bağımsız çözümler geliştirdi.\" (Kaynak: Ann Butler & Andrew Whitfield, Africa's Agricultural Revolution, African Archaeological Review, 2007 – uyarlanmıştır)</i><br><br><b>Bu veriler, Afrika’da tarımın başlangıcına ilişkin standart 'tek merkez–yayılma' modeliyle nasıl bir çelişki oluşturmaktadır?</b>",
        secenekler: [
            "A) Afrika'da tarım başlamamış, Yakın Doğu'dan ithal edilmiştir",
            "B) Farklı bölgelerde bağımsız kültüre alma örnekleri, tarımın tek bir merkezden yayıldığı modelini geçersiz kılmakta; çok merkezli bağımsız gelişim modelini desteklemektedir",
            "C) Teff ve sorgum Yakın Doğu kökenlidir",
            "D) Afrika'da tarım yalnızca ticaret yolları üzerinden yayılmıştır",
            "E) Bağımsız kültüre alma örnekleri yalnızca tesadüf eseridir ve model oluşturmaz"
        ],
        cevap: "B) Farklı bölgelerde bağımsız kültüre alma örnekleri, tarımın tek bir merkezden yayıldığı modelini geçersiz kılmakta; çok merkezli bağımsız gelişim modelini desteklemektedir",
        aciklama: "Doğru cevap B’dir. Yakın Doğu’dan bağımsız olarak farklı Afrika bölgelerinde birbirinden habersiz kültüre alma örnekleri, tek merkezli yayılma modelini çürütmektedir. Her coğrafya kendi bitkilerini ve çözümlerini üretmiştir; bu da tarımın evrensel bir zorunluluk karşısında paralel olarak geliştiğini göstermektedir."
    },
    {
        soru: "<i>\"Paleoepidemiolog Charlotte Roberts, İngiltere'deki Neolitik iskelet koleksiyonunu inceledi. Mezarlıklarda tahıl tarımına geçişin ardından çocukların yüzde otuzunda C vitamini yetersizliğine bağlı skorbüt izleri saptandı. Araştırmacı, karbonhidrat ağırlıklı tek düze tarım diyetinin demir ve C vitamini yetersizliğini artırdığını ileri sürdü.\" (Kaynak: Charlotte Roberts & Keith Manchester, The Archaeology of Disease, 2005, s. 214 – uyarlanmıştır)</i><br><br><b>Bu paleoepidemiojik bulgular, 'Tarım Devrimi bir ilerleme miydi?' sorusuna nasıl katkıda bulunur?</b>",
        secenekler: [
            "A) Tarım kesinlikle beslenme kalitesini artırmıştır; bu bulgular bir istisnadır",
            "B) Artan kalori ve nüfus büyümesine rağmen tek düze diyetin vitamin eksikliklerine yol açması, tarımın bireysel beslenme sağlığı açısından karmaşık ve çelişkili sonuçlar ürettiğini göstermektedir",
            "C) Skorbüt yalnızca yetişkinlerde görülür; çocuk iskeleti verileri geçersizdir",
            "D) Tarım öncesi avcı-toplayıcılarda C vitamini eksikliği daha yaygındı",
            "E) Bu bulgular tarımın nüfusu azalttığını kanıtlamaktadır"
        ],
        cevap: "B) Artan kalori ve nüfus büyümesine rağmen tek düze diyetin vitamin eksikliklerine yol açması, tarımın bireysel beslenme sağlığı açısından karmaşık ve çelişkili sonuçlar ürettiğini göstermektedir",
        aciklama: "Doğru cevap B’dir. Tarım hem kaloriyi artırmış hem de nüfusu büyütmüştür; ama tek düze diyet vitamin eksikliklerini artırmıştır. Bu paradoks, 'ilerleme' kavramının hangi ölçüte göre değerlendirildiğine bağlı olduğunu ve tarımın çok boyutlu etkilerini tek bir çerçeveye sığdırmanın güçlüğünü ortaya koymaktadır."
    },
    {
        soru: "<i>\"Roma tarihçisi Columella, MÖ 1. yüzyılda kaleme aldığı De Re Rustica adlı tarım el kitabında şöyle yazar: İyi bir çiftçi toprağını baba gibi sever, düşman gibi işler. Tarlayı dinlendirmeli, gübre eklemeli ve suyu yönetmelisin. Toprak sana ne verirse, bir sonraki yıl için onu geri ödemelisin; aksi takdirde toprak seni cezalandırır.\" (Kaynak: Columella, De Re Rustica, MÖ 1. yüzyıl – uyarlanmış çeviri)</i><br><br><b>Columella’nın bu ifadesi, erken tarım toplumlarının toprak yönetimine yaklaşımı hakkında nasıl yorumlanabilir?</b>",
        secenekler: [
            "A) Columella, toprağın sınırsız biçimde sömürülebileceğini savunmaktadır",
            "B) Erken tarım toplumlarında sürdürülebilir toprak yönetimi anlayışı gelişmiş; tarlanın korunması uzun vadeli bir strateji olarak benimsenmiştir",
            "C) Roma’da tarım yalnızca kısa vadeli kâr hedefiyle yapılmaktaydı",
            "D) Columella'nın metni yalnızca felsefi bir analoji içermekte, pratik tarım rehberi değildir",
            "E) Toprağı dinlendirme fikri Roma'da hiçbir zaman uygulanmadı"
        ],
        cevap: "B) Erken tarım toplumlarında sürdürülebilir toprak yönetimi anlayışı gelişmiş; tarlanın korunması uzun vadeli bir strateji olarak benimsenmiştir",
        aciklama: "Doğru cevap B’dir. Columella, nadas (dinlendirme), gübreleme ve su yönetimini 'toprağa geri ödeme' metaforuyla çerçeveler. Bu, toprağın sınırsız kaynak olmadığını ve uzun vadeli verimlilik için korunması gerektiğini vurgulayan sürdürülebilir tarım anlayışının erken bir ifadesidir."
    },
    {
        soru: "<i>\"Arkeolog Robert Braidwood, 1950'lerde Zawi Chemi kazılarından sonra şunu öne sürdü: İnsanlar tarıma geçmek için ne iklim baskısına ne de açlığa ihtiyaç duydu. İnsanların yeterli bir beyin kapasitesine ve ilgili bitkilerin yaygın olduğu bir ortama kavuştukları anda tarımı keşfettiler. Ona göre tarım bir \"hazır oluş anı\"nın ürünüydü. Ancak Lewis Binford (1968) buna itiraz etti: Tarım en verimli bölgelerde değil, nüfus baskısının hissedildiği sınır bölgelerde başladı.\" (Kaynak: R. Braidwood, Prehistoric Investigations in Iraqi Kurdistan, 1960; L. Binford, Post-Pleistocene Adaptations, 1968 – uyarlanmıştır)</i><br><br><b>Braidwood ile Binford arasındaki bu tartışma, tarih ve arkeoloji metodolojisi açısından hangi temel sorunu örneklemektedir?</b>",
        secenekler: [
            "A) İki araştırmacı da aynı hipotezi farklı terimlerle ifade etmektedir",
            "B) Bu tartışma, tarihsel süreçlerin nedenselliği konusunda 'iç kapasite–dış baskı' (cognitive vs. demographic) açıklama modellerinin çatışmasını ve kanıt yorumundaki metodolojik farklılıkları örneklemektedir",
            "C) Braidwood'un tezi arkeolojik kanıtlardan yoksundur; Binford'un tezi kesin doğrudur",
            "D) Her iki araştırmacı da tarımın tek bir merkezde başladığını kabul etmektedir",
            "E) Bu tartışma yalnızca Irak arkeolojisiyle ilgilidir ve genel bir metodolojik derse konu olamaz"
        ],
        cevap: "B) Bu tartışma, tarihsel süreçlerin nedenselliği konusunda 'iç kapasite–dış baskı' (cognitive vs. demographic) açıklama modellerinin çatışmasını ve kanıt yorumundaki metodolojik farklılıkları örneklemektedir",
        aciklama: "Doğru cevap B’dir. Braidwood iç kapasiteyi (bilişsel hazırlık + çevre uyumu), Binford dış baskıyı (demografik sınır koşulları) öne çıkarmaktadır. Bu iki model, tarihsel açıklamanın 'nedensellik' sorununu ele alırken hangi tür kanıtın öncelikli sayılacağı sorusunu gündeme getirmektedir. Bu metodolojik çatışmayı kavramak ileri analitik yetkinlik gerektirir."
    },
    {
        soru: "<i>\"Tarih felsefecisi Oswald Spengler, Batı'nın Çöküşü (1918) adlı eserinde şöyle yazmıştır: Köylü tarihin yarattığı değil, tarihin dışında durandır. O toprağa bağlıdır; siyasi ve kültürel yaratımların nesnesidir, öznesi değil. Kent inşa eden ve devlet kuran çiftçi değil, artı ürünü ele geçiren savaşçı ve zanaatkâr sınıfıdır.\" (Kaynak: Oswald Spengler, Der Untergang des Abendlandes, 1918 – uyarlanmış çeviri)</i><br><br><b>Spengler’in bu argümanına karşı, tarihsel kanıtları kullanan en güçlü itiraz hangisidir?</b>",
        secenekler: [
            "A) Spengler haklıdır; köylüler gerçekten tarihsel özne olmamıştır",
            "B) Sulama örgütlenmesi, tarım takvimi ve köy meclisleri gibi örnekler, köylülerin hem tarımsal bilgi üretiminde hem de toplumsal kurumların oluşmasında etkin özne olduğunu göstermektedir",
            "C) Spengler'in argümanı Batı Avrupa için doğrudur ancak Doğu uygarlıkları için geçersizdir",
            "D) Spengler'in tezi felsefi bir düşünce oyunu olduğundan tarihsel kanıtlarla test edilemez",
            "E) Savaşçı sınıfın üretimle ilişkisi Spengler'in tezini desteklemektedir"
        ],
        cevap: "B) Sulama örgütlenmesi, tarım takvimi ve köy meclisleri gibi örnekler, köylülerin hem tarımsal bilgi üretiminde hem de toplumsal kurumların oluşmasında etkin özne olduğunu göstermektedir",
        aciklama: "Doğru cevap B’dir. Spengler köylüyü pasif bir nesne olarak sunmaktadır. Oysa sulama kanallarının örgütlenmesi, Sümer köy meclisleri (asgar), tarım takvimi geliştirme ve bitki ıslahı gibi pratikler köylülerin toplumsal bilgi ve kurumları aktif olarak inşa ettiğini kanıtlamaktadır. Bu itirazı formüle edebilmek için hem Spengler’in argümanını hem de tarihsel kanıtları birlikte değerlendirmek gerekmektedir."
    },
    {
        soru: "<i>\"Genetikçi Luigi Luca Cavalli-Sforza, 1990'larda Avrupa'da gerçekleştirdiği kapsamlı gen haritası çalışmasında, tarım genlerinin Yakın Doğu'dan Avrupa'ya yayılışının harita üzerinde \"dalgalı cephe\" (wave of advance) biçiminde ilerlediğini saptadı. Ancak sonraki aDNA (antik DNA) çalışmaları, bu yayılımın hem göçmen çiftçilerin taşıdığı hem de yerli avcı-toplayıcıların benimsediği karma bir süreç olduğunu ortaya koydu.\" (Kaynak: L.L. Cavalli-Sforza, Genes, Peoples and Languages, 2000; D. Reich, Who We Are, 2018 – uyarlanmıştır)</i><br><br><b>Bu iki araştırmanın birlikte değerlendirilmesi, tarımın yayılmasını açıklayan model hakkında hangi metodolojik dersi vermektedir?</b>",
        secenekler: [
            "A) Gen haritası yöntemi tarih araştırmalarında kullanılamaz",
            "B) İlk model (salt göç dalgası) doğruydu; aDNA çalışmaları gereksizdir",
            "C) Tarımın yayılması, hem biyolojik göç hem de kültürel benimsemeyi birleştiren karma bir süreçtir; tek değişkenli modeller bu karmaşıklığı yakalayamaz",
            "D) Avcı-toplayıcılar tarımı hiçbir zaman kendi iradesiyle benimsememiştir",
            "E) aDNA verileri Cavalli-Sforza'nın tüm bulgularını geçersiz kılmıştır"
        ],
        cevap: "C) Tarımın yayılması, hem biyolojik göç hem de kültürel benimsemeyi birleştiren karma bir süreçtir; tek değişkenli modeller bu karmaşıklığı yakalayamaz",
        aciklama: "Doğru cevap C’dir. Cavalli-Sforza’nın gen haritası salt göç modelini destekliyordu; aDNA çalışmaları buna yerli benimseme boyutunu ekledi. Bu, tek değişkenli modellerin (yalnızca göç veya yalnızca kültür aktarımı) karmaşık tarihsel süreçleri açıklamada yetersiz kaldığını göstermektedir. İki araştırmayı sentezlemek ileri düzey metodolojik anlayış gerektirir."
    },
    {
        soru: "<i>\"Fransız tarihçi Paul Bairoch, tarımsal devrimi kapitalizmin doğuşuyla ilişkilendiren standart Avrupa merkezli anlatılara itiraz ederek şunu yazar: Tarımsal artı ürün ve sermaye birikimi, Avrupa'dan önce Çin, Hindistan ve Osmanlı topraklarında çok daha büyük ölçeğe ulaşmıştı. Asya'nın bu birikimi, sanayi devrimine neden orada değil Avrupa'da başladığı sorusunu açıklamaz; aksine bu soruyu derinleştirir.\" (Kaynak: Paul Bairoch, Economics and World History, 1993, s. 31 – uyarlanmıştır)</i><br><br><b>Bairoch’un bu argümanı, tarımsal artı ürün ile tarihsel gelişim arasındaki ilişkinin yorumlanmasına nasıl bir eleştiri getirmektedir?</b>",
        secenekler: [
            "A) Tarımsal artı ürün, tarihsel gelişimi her koşulda belirleyen tek etkendir",
            "B) Tarımsal birikim tek başına yeterli bir açıklama değildir; aynı koşullara sahip farklı toplumların neden farklı tarihsel yollar izlediği sorusu, ek değişkenlere ve bağlamsal analizlere ihtiyaç duyar",
            "C) Avrupa, tarımsal artı ürün birikiminde Asya'yı geçmiş olduğu için sanayi devrimini gerçekleştirdi",
            "D) Bairoch, tarımın tarihsel önemi olmadığını savunmaktadır",
            "E) Osmanlı ve Çin'de tarımsal birikim gerçekleşmemiştir"
        ],
        cevap: "B) Tarımsal birikim tek başına yeterli bir açıklama değildir; aynı koşullara sahip farklı toplumların neden farklı tarihsel yollar izlediği sorusu, ek değişkenlere ve bağlamsal analizlere ihtiyaç duyar",
        aciklama: "Doğru cevap B’dir. Bairoch, Asya’nın çok daha büyük tarımsal birikime sahip olduğunu ama sanayi devriminin Avrupa’da başladığını göstererek 'artı ürün → gelişme' ilişkisinin tek başına açıklayıcı olmadığını ortaya koymaktadır. Bu, tarihsel nedensellik analizinin tek değişkenle yapılamayacağını ve bağlamsal çok değişkenli analiz gerektirdiğini vurgulayan ileri düzey bir eleştiridir."
    },
    {
        soru: "<i>\"Ekofeminist tarihçi Carolyn Merchant, The Death of Nature (1980) adlı eserinde Tarım Devrimi'ni şöyle değerlendirir: Tarım, toprağı edilgen ve itaatkâr kılan bir dili meşrulaştırdı: toprak sürülür, açılır, döllendirilir. Bu dil, toprağı kadın bedeniyle özdeşleştiren ataerkil bir metafor sistemini güçlendirdi; hem doğa hem de kadın üzerinde hâkimiyet kurulmasını ideolojik açıdan normalleştirdi.\" (Kaynak: Carolyn Merchant, The Death of Nature, 1980, s. 2 – uyarlanmıştır)</i><br><br><b>Merchant’ın bu analizi, tarih araştırmasına hangi yeni çerçeveyi açmakta ve hangi eleştiriye maruz kalmaktadır?</b>",
        secenekler: [
            "A) Merchant yalnızca çevre tarihi alanında özgün bir tez sunmaktadır; feminist perspektifin tarihle ilgisi yoktur",
            "B) Merchant, tarımsal dilin toplumsal cinsiyet ve doğa üzerindeki iktidar söylemini nasıl pekiştirdiğini sorgulayan dil-ideoloji-iktidar analizini tarih araştırmasına taşımaktadır; ancak tarımsal dilin her toplumda aynı anlam yapısını üretip üretmediği sorgulanabilir",
            "C) Merchant'ın argümanı yalnızca modern dönem için geçerlidir; Eski Çağ tarımıyla ilgisi yoktur",
            "D) Tarımsal dil toprak tasvirlerinde hiçbir zaman cinsiyetçi metaforlar kullanmamıştır",
            "E) Feminist tarih yorumu arkeolojik kanıtlara dayanmadığından bilimsel değildir"
        ],
        cevap: "B) Merchant, tarımsal dilin toplumsal cinsiyet ve doğa üzerindeki iktidar söylemini nasıl pekiştirdiğini sorgulayan dil-ideoloji-iktidar analizini tarih araştırmasına taşımaktadır; ancak tarımsal dilin her toplumda aynı anlam yapısını üretip üretmediği sorgulanabilir",
        aciklama: "Doğru cevap B’dir. Merchant, tarımsal dilin (toprağı sürme, açma, dölleme metaforları) hem doğa hem de kadın üzerindeki ataerkil hâkimiyeti ideolojik olarak normalleştirdiğini savunur. Bu çerçeve, tarihçilerin dilin toplumsal cinsiyet ve iktidar ilişkilerini nasıl şekillendirdiğini sorgulamasına olanak tanır. Ancak bu metafor yapısının her kültürde aynı biçimde işleyip işlemediği sorusu metodolojik bir sınırlılık oluşturur. Bu soruyu yanıtlamak hem Merchant’ı hem de olası eleştiriyi birlikte değerlendirmeyi gerektirdiğinden zordur."
    },
    {
        soru: "<i>\"Ekonomist Ester Boserup, 1965 yılında yayımladığı The Conditions of Agricultural Growth adlı eserinde Malthus'un meşhur tezini tersine çevirdi. Malthus'a göre nüfus gıda arzından hızlı artar ve kıtlık kaçınılmazdır. Boserup'a göre ise nüfus artışı tarımsal inovasyonu zorlar: Daha fazla ağız beslemek zorunda kalan topluluklar, nadası kısaltır, sulama geliştirir, yeni aletler icat eder.\" (Kaynak: Ester Boserup, The Conditions of Agricultural Growth, 1965, s. 14 – uyarlanmıştır)</i><br><br><b>Boserup’un 'nüfus → inovasyon' tezi ile Malthus’un 'gıda → nüfus' tezinin birlikte değerlendirilmesi, Tarım Devrimi tarih yazımı için nasıl bir analitik çerçeve sunar?</b>",
        secenekler: [
            "A) İki tez birbirine tamamen zıt olduğundan biri kesinlikle yanlıştır",
            "B) Her iki model de farklı koşullar ve dönemler için geçerli olabilir; nedensellik ilişkisinin yönü (nüfus mu tarımı yoksa tarım mı nüfusu tetikler) bağlam bağımlıdır ve tek yönlü determinist açıklama yetersiz kalır",
            "C) Boserup'un tezi yalnızca modern tarım toplumları için geçerlidir; Eski Çağ için Malthus doğrudur",
            "D) Tarım Devrimi'nin başlangıcı nüfus değil iklim faktörleriyle açıklandığından her iki tez de geçersizdir",
            "E) Boserup, Malthus'un tezini tamamen kabul etmiş ve onu geliştirmiştir"
        ],
        cevap: "B) Her iki model de farklı koşullar ve dönemler için geçerli olabilir; nedensellik ilişkisinin yönü (nüfus mu tarımı yoksa tarım mı nüfusu tetikler) bağlam bağımlıdır ve tek yönlü determinist açıklama yetersiz kalır",
        aciklama: "Doğru cevap B’dir. Malthus’a göre gıda nüfusu belirler; Boserup’a göre nüfus gıda üretimini belirler. Her iki tez de belirli koşullarda geçerliliğini koruyabilir (örneğin Neolitik dönemde Boserup, kıtlık dönemlerinde Malthus daha açıklayıcı olabilir). Nedensellik ilişkisinin yönünün tek bir modele kilitlenemeyeceğini kavramak ve iki modeli sentezlemek ileri düzey analitik düşünme gerektirir."
    },
    {
        soru: "<i>\"Sosyal antropolog Jack Goody, Pişirme, Mutfak ve Sınıf (1982) adlı eserinde şöyle yazar: Tarımın yarattığı artı ürün, yalnızca depolama ve ticaret için değil, sofra kültürü ve mutfak farklılaşması için de kullanıldı. Saraylar ve tapınaklar kendine özgü yemek repertuvarları geliştirdi; köylü ve elit yemekleri birbirinden ayrıştı. Bu farklılaşma, sınıfsal kimliğin sembolik olarak üretildiği alanlardan biri oldu.\" (Kaynak: Jack Goody, Cooking, Cuisine and Class, 1982, s. 97 – uyarlanmıştır)</i><br><br><b>Goody’nin bu analizi, tarımsal artı ürünün toplumsal sınıf oluşumundaki işlevi hakkında hangi özgün perspektifi açmaktadır ve bu perspektifin sınırlılığı nedir?</b>",
        secenekler: [
            "A) Goody, tarımın mutfak üzerindeki etkisini ekonomik değil salt kültürel bir olgu olarak ele almaktadır; bu yaklaşım ekonomik tarih için değersizdir",
            "B) Goody, tarımsal artı ürünün yalnızca maddi sınıf farkını değil, yemek kültürü aracılığıyla sembolik kimlik farklılaşmasını da ürettiğini ortaya koymaktadır; ancak sofra farklılaşmasının sınıf ilişkilerine mi yoksa kültürel tercih özerkliğine mi bağlandığı ayrışması, tezin tartışmalı boyutunu oluşturmaktadır",
            "C) Goody'nin tezi, tarımsal artı ürünün her toplumda aynı mutfak farklılaşmasını doğurduğunu savunmaktadır",
            "D) Elit ve köylü mutfakları arasındaki fark ekonomik eşitsizliğin değil yalnızca coğrafi farklılıkların sonucudur",
            "E) Goody, tarımın sınıf oluşumu üzerinde hiçbir etkisi olmadığını kanıtlamaktadır"
        ],
        cevap: "B) Goody, tarımsal artı ürünün yalnızca maddi sınıf farkını değil, yemek kültürü aracılığıyla sembolik kimlik farklılaşmasını da ürettiğini ortaya koymaktadır; ancak sofra farklılaşmasının sınıf ilişkilerine mi yoksa kültürel tercih özerkliğine mi bağlandığı ayrışması, tezin tartışmalı boyutunu oluşturmaktadır",
        aciklama: "Doğru cevap B’dir. Goody, tarımsal artı ürünün sembolik boyutunu (mutfak kültürü aracılığıyla kimlik farklılaşması) gündeme taşıyarak salt ekonomik analizin ötesine geçen özgün bir perspektif sunmaktadır. Ancak sofra farklılaşmasının zorunlu olarak sınıf hiyerarşisini mi yansıttığı yoksa kültürel tercih özerkliğinin bir ürünü mü olduğu sorusu, tezin metodolojik sınırlılığıdır. Bu soruyu yanıtlamak hem tezi kavramayı hem de olası zayıf noktasını belirlemeyi gerektirdiğinden zor düzeydedir."
    }
];

// --- 2. ÜNİTE: TARIM DEVRİMİNİN ESKİ ÇAĞ'A ETKİLERİ - TEST 4 ---
window.allTests["test_u2_tarim_4"] = [
    {
        soru: "<i>\"Tarımcılığa geçiş, insanların daha iyi bir yaşam için bilinçli olarak verdikleri bir karar değildi. Aksine, nüfus baskısı ve iklim değişiklikleri insanları adım adım bu yola sürükledi. Avcı-toplayıcılar, günde ortalama dört saat çalışarak geçimlerini sağlarken, ilk çiftçiler çok daha uzun çalışma süreleriyle daha az çeşitli bir beslenme düzenine mahkûm oldular.\" (Kaynak: Jared Diamond, Tüfek, Mikrop ve Çelik, 1997 – uyarlanmıştır)</i><br><br><b>Bu metne göre, insanların tarıma geçmesini açıklamak için aşağıdaki yorumlardan hangisi en uygun sonucu çıkarmaktadır?</b>",
        secenekler: [
            "A) Tarımcılığa geçiş, insanların bilinçli ve planlı kararlarının bir sonucudur.",
            "B) Tarımcılığa geçiş, yaşam kalitesini doğrudan ve hızla artırmıştır.",
            "C) İnsan toplulukları, dış baskılar nedeniyle farkında olmadan tarıma yönelmiş olabilir.",
            "D) Avcı-toplayıcılar, çiftçilere göre daha çok çalışmak zorunda kalmıştır.",
            "E) İklim değişiklikleri, tarım toplumlarının ortaya çıkmasını tamamen engellemiştir."
        ],
        cevap: "C) İnsan toplulukları, dış baskılar nedeniyle farkında olmadan tarıma yönelmiş olabilir.",
        aciklama: "Doğru yanıt C'dir. Diamond'ın metninde tarıma geçişin \"bilinçli bir karar olmadığı\" ve \"nüfus baskısı ile iklim değişikliklerinin insanları sürüklediği\" vurgulanmaktadır. Bu durum, insanların dış koşullar karşısında farkında olmadan bu sürece dahil olduğuna işaret eder. A seçeneği metne doğrudan ters düşer; B seçeneği yanlıştır çünkü metin çiftçilerin daha az çeşitli beslenme ve daha uzun çalışma sürelerine mahkûm olduğunu söyler; D seçeneği tam tersidir (avcı-toplayıcılar daha az çalışıyordu); E seçeneği ise tarımın ortaya çıktığı gerçeğiyle çelişir."
    },
    {
        soru: "<i>\"MÖ 7500–5700 yılları arasında faaliyet gösteren Çatalhöyük, kapısı olmayan evlerden oluşmaktaydı; insanlar çatıdaki deliklerden içeri girip çıkıyordu. Evler birbirine sıkıca yapışık inşa edilmiş, herhangi bir cadde ya da genel kamusal alan bırakılmamıştı. Ölüler ise doğrudan ev tabanlarının altına gömülüyordu.\" (Kaynak: Ian Hodder, The Leopard's Tale, 2006 – uyarlanmıştır)</i><br><br><b>Bu metinden yola çıkarak Çatalhöyük'teki yerleşik yaşam hakkında hangi çıkarım yapılabilir?</b>",
        secenekler: [
            "A) Çatalhöyük halkı, kamusal alanları gündelik hayatın merkezi olarak kullanmıştır.",
            "B) Ölü gömme geleneği, ata kültü ve aile bağlarının fiziksel mekânla iç içe geçtiğine işaret eder.",
            "C) Kapısız ev tasarımı, dışarıdan gelen tehlikelere karşı tamamen savunmasız bir toplumu yansıtır.",
            "D) Şehir planlaması, bu dönemde çok gelişmiş bir merkezi otorite varlığını kanıtlar.",
            "E) Çatalhöyük halkının tarımla herhangi bir ilgisi olmadığı anlaşılmaktadır."
        ],
        cevap: "B) Ölü gömme geleneği, ata kültü ve aile bağlarının fiziksel mekânla iç içe geçtiğine işaret eder.",
        aciklama: "Doğru yanıt B'dir. Ölülerin ev tabanlarına gömülmesi, ata kültü ve aile bağlarının fiziksel yaşam alanıyla birleştiğini gösterir; bu da yerleşik düzende dini ve sosyal ilişkilerin mekânla nasıl bütünleştiğini ortaya koyar. A seçeneği yanlıştır; çünkü metinde kamusal alan olmadığı belirtilmektedir. C seçeneği, çatı girişlerinin savunma amacıyla yapıldığı ihtimalini tek yönlü yorumlar; D'de ise bir merkezi otorite kanıtı yoktur. E seçeneği metnin kapsamı dışındadır."
    },
    {
        soru: "<i>\"Tarımla birlikte insanlar, yiyeceklerini mevsimlik olarak üretip yıl boyunca tüketebilmek için depolama yöntemleri geliştirdiler. Buğday ambarları ve küplerde saklanan tahıllar, topluluğun kışın ya da kıtlık döneminde hayatta kalmasını sağladı. Zamanla bu depoların yönetimi, belirli kişilerin elinde toplandı.\" (Kaynak: Türk Tarih Kurumu, 9. Sınıf Tarih Ders Kitabı, 2023 – uyarlanmıştır)</i><br><br><b>Metindeki bilgilere göre, besin fazlasının depolanmasının toplumsal yapıya yansıması hangi şekilde gerçekleşmiştir?</b>",
        secenekler: [
            "A) Depolama, topluluktaki her bireyin eşit kaynağa sahip olmasını kalıcı biçimde sağlamıştır.",
            "B) Depoların yönetiminin tek elde toplanması, toplumsal güç farklılıklarına zemin hazırlamıştır.",
            "C) Kış döneminde hayatta kalma sorununun çözülmesi, nüfusun hızla azalmasına neden olmuştur.",
            "D) Tahıl depoları, ticaretin tamamen ortadan kalkmasına yol açmıştır.",
            "E) Besin fazlası, topluluğun her dönem göçebe yaşamasını kolaylaştırmıştır."
        ],
        cevap: "B) Depoların yönetiminin tek elde toplanması, toplumsal güç farklılıklarına zemin hazırlamıştır.",
        aciklama: "Doğru yanıt B'dir. Metinde \"depoların yönetiminin belirli kişilerin elinde toplandığı\" açıkça ifade edilmektedir. Bu durum, kaynakların kontrolü aracılığıyla toplumsal hiyerarşinin ve güç farklılıklarının doğuşuna zemin hazırladığını gösterir. A seçeneği eşitlikçi bir sonucu ima eder ancak metin tam tersi bir eğilime dikkat çekmektedir. C'de nüfus azalması iddia edilmekte, bu da olgusal açıdan yanlıştır. D ve E seçenekleri metinle hiçbir ilişki kurmamaktadır."
    },
    {
        soru: "<i>\"Avcı-toplayıcı topluluklar, doğanın sunduklarıyla yetindikleri için 'orijinal zengin toplumlar'dır; kıt kaynaklarla uzlaşmayı bildikleri için sınırsız ihtiyaç kavramından habersizdirler. Tarıma geçen toplumlar ise artık üretim zorunluluğuyla birlikte 'eksiklik' kavramını da icat etmişlerdir.\" (Kaynak: Marshall Sahlins, Stone Age Economics, 1972 – uyarlanmıştır)</i><br><br><b>Sahlins'in bu değerlendirmesinden yola çıkarak tarıma geçişin insanın zihniyet dünyasına ne tür bir katkı yaptığı söylenebilir?</b>",
        secenekler: [
            "A) Tarım, insanın doğayla uyumlu ve ihtiyacı kadar tüketen bir anlayış geliştirmesini kalıcı kılmıştır.",
            "B) Tarım, 'daha fazlasına sahip olma' ve 'eksiklik' duygusunu beraberinde getirerek yeni bir ekonomik zihniyetin kapısını aralamıştır.",
            "C) Avcı-toplayıcılar, tarım toplumlarına göre her zaman daha fazla kaynak sıkıntısı çekmiştir.",
            "D) Tarım, insanların ihtiyaç duyduklarından daha az üretmesine yol açmıştır.",
            "E) Sahlins, tarım toplumlarını avcı-toplayıcılardan ekonomik açıdan daha başarılı bulmaktadır."
        ],
        cevap: "B) Tarım, 'daha fazlasına sahip olma' ve 'eksiklik' duygusunu beraberinde getirerek yeni bir ekonomik zihniyetin kapısını aralamıştır.",
        aciklama: "Doğru yanıt B'dir. Sahlins'e göre tarıma geçiş, \"artık üretim\" kavramını ve dolayısıyla \"eksiklik\" duygusunu ortaya çıkarmıştır. Bu, insanın zihniyet dünyasında büyük bir kırılmaya, yani \"daha fazlasına sahip olma\" güdüsünün doğmasına yol açmıştır. A seçeneği avcı-toplayıcıların zihniyetini tanımlar ama tarımın katkısını yanlış yorumlar. C seçeneği metnin tam tersini iddia eder. D ve E seçenekleri de metnin içeriğiyle çelişmektedir."
    },
    {
        soru: "<i>\"İnsanlık tarihinde ilk evcilleştirilen hayvan köpek olmuş, onu koyun, keçi, sığır ve domuz izlemiştir. Evcil hayvanlar; et, süt ve yün gibi besin ve hammadde kaynağı işlevi görmüş, aynı zamanda tarla sürmek ve yük taşımak amacıyla da kullanılmıştır. Bu durum, insanın üretim kapasitesini önemli ölçüde artırmıştır.\" (Kaynak: MEB 9. Sınıf Tarih Ders Kitabı, 2023 – uyarlanmıştır)</i><br><br><b>Metne göre hayvan evcilleştirmesinin tarım toplumuna katkısını değerlendirdiğimizde, aşağıdaki yargılardan hangisi doğrudan desteklenmektedir?</b>",
        secenekler: [
            "A) Hayvanların evcilleştirilmesi yalnızca beslenme sorununu çözmüş, üretim süreçleriyle ilgisi olmamıştır.",
            "B) Evcilleştirme, insanın hem besin hem de iş gücü kaynaklarını çeşitlendirerek üretim kapasitesini artırmıştır.",
            "C) İlk evcilleştirilen hayvan, tarla işlerinde kullanılmak üzere sığır olmuştur.",
            "D) Hayvan evcilleştirmesi, insan nüfusunu olumsuz etkilemiştir.",
            "E) Yük taşımada kullanılan hayvanlar ticaret ağlarının gelişmesini engellemiştir."
        ],
        cevap: "B) Evcilleştirme, insanın hem besin hem de iş gücü kaynaklarını çeşitlendirerek üretim kapasitesini artırmıştır.",
        aciklama: "Doğru yanıt B'dir. Metin, hayvanların hem besin/hammadde (et, süt, yün) hem de iş gücü (tarla sürme, yük taşıma) kaynağı olduğunu belirtmekte ve üretim kapasitesinin arttığını vurgulamaktadır. A seçeneği metnin yalnızca bir kısmını alıyor ve iş gücü boyutunu yok sayıyor. C seçeneğinde ilk evcilleştirilen hayvanın köpek olduğu belirtilmiştir, sığır değil. D ve E seçenekleri metinle desteklenmemektedir."
    },
    {
        soru: "<i>\"İlk çiftçiler hayvanları yalnızca kesip eti için kullanırken, MÖ 4. binyıldan itibaren süt, yün ve hayvan gücü gibi 'ikincil ürünler' sistematik biçimde kullanılmaya başlandı. Bu gelişme, hayvan sürülerinin değerini artırdı ve servetin bir göstergesi hâline getirdi.\" (Kaynak: Andrew Sherratt, The Secondary Products Revolution, 1981 – uyarlanmıştır)</i><br><br><b>Sherratt'ın bu tespitine göre, ikincil ürün devriminin toplumsal sonuçları hakkında hangi yorum yapılabilir?</b>",
        secenekler: [
            "A) Hayvan sürülerine sahip olmak, toplumsal statü ve servetin yeni bir göstergesi hâline gelmiştir.",
            "B) İkincil ürünler, hayvanların ekonomik değerini tamamen ortadan kaldırmıştır.",
            "C) Hayvan sürülerinin değer kazanması, eşitsizlikleri azaltarak toplumsal dengeyi sağlamıştır.",
            "D) Hayvan gücünün kullanılması, çiftçilerin tamamen göçebe yaşama geçmesine neden olmuştur.",
            "E) Süt ve yün üretimi yalnızca köylerin içindeki tüketime yönelik olmuş, ticarette kullanılmamıştır."
        ],
        cevap: "A) Hayvan sürülerine sahip olmak, toplumsal statü ve servetin yeni bir göstergesi hâline gelmiştir.",
        aciklama: "Doğru yanıt A'dır. Metin, sürülerin \"servetin bir göstergesi hâline geldiğini\" açıkça ifade etmektedir. Bu, hayvan sahipliğinin toplumsal statü ve servet eşitsizliğiyle doğrudan bağlantılı hale geldiğini gösterir. B seçeneği ekonomik değerin ortadan kalktığını iddia eder, bu yanlıştır. C seçeneğinde ise eşitsizliklerin azaldığı öne sürülmektedir; ancak metin tam aksine servet farklılaşmasına dikkat çekmektedir. D ve E seçenekleri metnin içeriğiyle desteklenmemektedir."
    },
    {
        soru: "<i>\"Tarım, besin üretiminde sürekliliği sağladı; bu da çocukların daha güvenli koşullarda büyümesine olanak tanıdı. Yerleşik topluluklar, avcı-toplayıcılara kıyasla daha kısa süreli emzirme uyguladı ve böylece doğurganlık aralıkları azaldı. Sonuç olarak nüfus artış hızı belirgin şekilde yükseldi.\" (Kaynak: V. Gordon Childe, Man Makes Himself, 1936 – uyarlanmıştır)</i><br><br><b>Childe'ın bu açıklamasına göre, tarımın nüfus üzerindeki etkisini sağlayan temel zincir aşağıdakilerin hangisinde doğru sıralanmıştır?</b>",
        secenekler: [
            "A) Göç → emzirme süresinin uzaması → doğurganlığın azalması → nüfus düşüşü",
            "B) Besin sürekliliği → daha kısa emzirme → doğurganlık aralıklarının kısalması → nüfus artışı",
            "C) Göçebe yaşam → besin fazlası → nüfus artışı → yerleşik düzen",
            "D) Nüfus artışı → besin sürekliliği → tarımın başlaması → göç",
            "E) Tarım → daha uzun emzirme → nüfus azalması → yerleşik düzen"
        ],
        cevap: "B) Besin sürekliliği → daha kısa emzirme → doğurganlık aralıklarının kısalması → nüfus artışı",
        aciklama: "Doğru yanıt B'dir. Metin, \"besin sürekliliği → çocukların güvenli büyümesi → daha kısa emzirme → doğurganlık aralıklarının kısalması → nüfus artışı\" zincirini net biçimde ortaya koymaktadır. A seçeneğinde göç ve olumsuz sonuçlar yanlış sıralanmıştır. C seçeneği göçebe yaşamdan başlatmaktadır, bu ise metnin mantığıyla çelişir. D seçeneği sıralama ilişkisini tersine çevirmektedir. E seçeneğinde daha uzun emzirme ve nüfus azalması gibi metinden desteklenmeyen unsurlar yer almaktadır."
    },
    {
        soru: "<i>\"Avcı-toplayıcı topluluklarda servet birikimi, hareket kısıtlamaları nedeniyle neredeyse imkânsızdı; herkes aşağı yukarı eşit miktarda mala sahipti. Tarımsal yerleşimle birlikte arazi, hayvan ve tahıl gibi birikebilen değerler ortaya çıktı. Bu değerlerin farklı miktarlarda birikimiyle birlikte bazı aileler diğerlerinin üzerinde kalıcı bir ekonomik ve sosyal konum elde etti.\" (Kaynak: Gerhard Lenski, Power and Privilege, 1966 – uyarlanmıştır)</i><br><br><b>Bu metinden yola çıkarak tarım öncesi ve sonrası toplumsal yapı arasındaki farkı en iyi hangi yargı açıklar?</b>",
        secenekler: [
            "A) Her iki toplumda da servet birikimi aynı hızda gerçekleşmiş ve eşitsizlik değişmemiştir.",
            "B) Avcı-toplayıcı topluluklar, tarım toplumlarına göre daha katı bir sınıf yapısına sahipti.",
            "C) Tarımın sağladığı birikebilen değerler, eşit dağılımı bozarak kalıcı toplumsal hiyerarşinin temelini atmıştır.",
            "D) Tarım öncesinde arazi mülkiyeti toplumsal statünün tek belirleyicisiydı.",
            "E) Avcı-toplayıcılarda servetin paylaşılması, tarım toplumlarına göre daha adaletsizdi."
        ],
        cevap: "C) Tarımın sağladığı birikebilen değerler, eşit dağılımı bozarak kalıcı toplumsal hiyerarşinin temelini atmıştır.",
        aciklama: "Doğru yanıt C'dir. Lenski'nin temel argümanı, tarımla birlikte arazi, hayvan ve tahıl gibi \"birikebilen değerlerin\" ortaya çıkmasının eşit dağılımı bozduğu ve kalıcı hiyerarşinin temelini attığıdır. A seçeneği iki toplum arasındaki farkı yok sayar. B seçeneği metnin tam tersini söyler. D seçeneği, tarım öncesinde arazi mülkiyetinin belirleyici olduğunu öne sürer; oysa metin bunun tarımla başladığını anlatmaktadır. E seçeneği de mantıksal açıdan metnin içeriğiyle çelişmektedir."
    },
    {
        soru: "<i>\"Tarımsal toplumlarda hasat zamanını öngörmek, yağmur duaları düzenlemek ve bereket ritüelleri icra etmek giderek uzmanlaşmış bir bilgi gerektirdi. Bu bilgiyi elinde bulunduran şamanlar ve din adamları, toplulukların doğaüstü güçlerle aracıları olarak tanındı. Zamanla bu aracılık rolü, onlara ekonomik ve siyasi bir güç de kazandırdı.\" (Kaynak: Bruce Trigger, A History of Archaeological Thought, 1989 – uyarlanmıştır)</i><br><br><b>Metne göre din adamlarının toplumsal güç kazanmasındaki temel mekanizma nedir?</b>",
        secenekler: [
            "A) Din adamları, fiziksel güçleri sayesinde toplumda lider konumuna yükselmiştir.",
            "B) Tarım takviminin ve doğaüstü bilginin tekelleştirilmesi, din adamlarına çok boyutlu bir güç sağlamıştır.",
            "C) Ritüellerin icra edilmesi, topluluğun doğayla ilgisini tamamen kesmiş ve din adamlarını işlevsiz kılmıştır.",
            "D) Yağmur ve bereket ritüelleri, yalnızca ekonomik amaçlarla düzenlenmiştir.",
            "E) Din adamları, toplumsal güç elde etmek için siyasi kurumları ortadan kaldırmıştır."
        ],
        cevap: "B) Tarım takviminin ve doğaüstü bilginin tekelleştirilmesi, din adamlarına çok boyutlu bir güç sağlamıştır.",
        aciklama: "Doğru yanıt B'dir. Metin, din adamlarının hasat takvimi ve doğaüstü bilgiyi tekelleştirerek önce sembolik aracı konumuna yükseldiklerini, ardından bu konumun onlara ekonomik ve siyasi güç kazandırdığını açıklamaktadır. A seçeneğinde fiziksel güç vurgusu metinde yer almaz. C seçeneği din adamlarının işlevsizleştiğini iddia eder, bu ise metnin tam tersine aykırıdır. D seçeneği ritüelleri yalnızca ekonomik çerçeveye indirger. E seçeneği ise siyasi kurumların ortadan kaldırılmasına dair metinde hiçbir ipucu bulunmamaktadır."
    },
    {
        soru: "<i>\"MÖ 4. binyılda Mezopotamya'daki kentsel merkezler, çevrelerindeki kırsal köylerle karmaşık bir değiş tokuş ilişkisine girmişti. Kentler el sanatları ürünleri ve örgütlü iş gücü sunarken köyler tahıl ve hayvansal ürünler sağlıyordu. Bu karşılıklı bağımlılık, birbirinden farklı ekolojik bölgeler arasında uzun mesafeli ticaret güzergâhlarının oluşmasının önünü açtı.\" (Kaynak: William McNeill, The Rise of the West, 1963 – uyarlanmıştır)</i><br><br><b>Bu metne göre Mezopotamya'daki erken ticaret ağlarının oluşmasında belirleyici olan temel unsur nedir?</b>",
        secenekler: [
            "A) Her topluluk kendi ihtiyacını karşılayabildiğinden, ticaret ağları tamamen gereksiz kalmıştır.",
            "B) Kent ve kırsal arasındaki üretim farklılıkları ve karşılıklı bağımlılık, ticaretin itici gücü olmuştur.",
            "C) Uzun mesafeli ticaret, yalnızca siyasi birlik sağlandıktan sonra mümkün olmuştur.",
            "D) Köyler, kentlere el sanatları ve zanaat ürünleri tedarik etmiştir.",
            "E) Ticaret ağları yalnızca tahıl ve hayvansal ürünler üzerine kurulmuş, el sanatları dahil edilmemiştir."
        ],
        cevap: "B) Kent ve kırsal arasındaki üretim farklılıkları ve karşılıklı bağımlılık, ticaretin itici gücü olmuştur.",
        aciklama: "Doğru yanıt B'dir. McNeill, kent-kır arasındaki farklı üretim kapasiteleri ve bunun yarattığı karşılıklı bağımlılığın ticaret ağlarını ortaya çıkardığını vurgulamaktadır. A seçeneği ticaret ağlarının gereksiz olduğunu söyler; bu metnin tam tersidir. C seçeneğinde \"siyasi birlik\" koşulu metinde yer almaz. D seçeneği, köylerin ve kentlerin rollerini yer değiştirmiştir; metin kentlerin el sanatları sağladığını belirtir. E seçeneği el sanatlarını dışarıda bırakır, bu da metne aykırıdır."
    },
    {
        soru: "<i>\"Büyük sulama kanallarının yapımı ve bakımı, binlerce kişinin koordineli çalışmasını zorunlu kılıyordu. Bu koordinasyonu sağlamak için merkezi bir otoriteye, yani geniş idari aygıta ihtiyaç duyuluyordu. Dolayısıyla sulama, despotik devlet yapılarının ortaya çıkmasında belirleyici bir etken olmuştur.\" (Kaynak: Karl Wittfogel, Oriental Despotism, 1957 – uyarlanmıştır)</i><br><br><b>Wittfogel'in tezini sınayan bir tarihçi, hangi soruyu sormak zorundadır?</b>",
        secenekler: [
            "A) Sulama kanallarının yalnızca şehirlere yakın yerlerde inşa edilip edilmediği",
            "B) Büyük sulama projelerinin merkezi otorite olmadan da küçük topluluklar tarafından yönetilip yönetilemeyeceği",
            "C) Despotik yöneticilerin kanalları ne kadar sürede inşa ettirdiği",
            "D) Sulama sularının hangi mahsullere öncelikle tahsis edildiği",
            "E) Kanal işçilerinin ücretlerinin altın mı yoksa tahıl cinsinden mi ödendiği"
        ],
        cevap: "B) Büyük sulama projelerinin merkezi otorite olmadan da küçük topluluklar tarafından yönetilip yönetilemeyeceği",
        aciklama: "Doğru yanıt B'dir. Wittfogel, büyük sulamanın merkezi despotik otoriteyi zorunlu kıldığını savunmaktadır. Bu tezi test etmenin en kritik yolu, büyük sulama projelerinin merkezi otorite olmadan da yönetilip yönetilemeyeceğini araştırmaktır; çünkü bu durumun var olduğu kanıtlanırsa tez zayıflar. Diğer seçenekler (A, C, D, E) Wittfogel'in temel nedensellik zincirini doğrudan sorgulamaz; bunlar yardımcı ya da bağımsız sorulardır."
    },
    {
        soru: "<i>\"Mezopotamya'da yazının ilk nüveleri, MÖ 8000'lerden itibaren kullanılan kil tokenlar (küçük nesneler) olarak karşımıza çıkmaktadır. Bu tokenlar tahıl, yağ veya hayvan miktarlarını temsil ediyor; depolama ve takas işlemlerini kaydetmek için kullanılıyordu. MÖ 3100'e gelindiğinde bu tokenlar düzleşerek kil tabletlere baskı yapılan sembollere dönüştü: çivi yazısı böyle doğdu.\" (Kaynak: Denise Schmandt-Besserat, Before Writing, 1992 – uyarlanmıştır)</i><br><br><b>Bu metne göre yazının kökenine ilişkin hangi yorum en destekli çıkarımdır?</b>",
        secenekler: [
            "A) Yazı, öncelikle dinî metinleri kayıt altına almak amacıyla icat edilmiştir.",
            "B) Yazı, ekonomik kayıt tutma ihtiyacından doğmuş ve tarımsal ticaretle doğrudan bağlantılıdır.",
            "C) Çivi yazısı, tarihte ilk kez MÖ 8000'lerde kullanılmaya başlanmıştır.",
            "D) Tokenlar; sanat, edebiyat ve mitoloji kayıtları için geliştirilmiştir.",
            "E) Yazının icadı, sulama sistemlerinin geliştirilmesinden sonra gerçekleşmiştir ve bu iki gelişme birbirinden tamamen bağımsızdır."
        ],
        cevap: "B) Yazı, ekonomik kayıt tutma ihtiyacından doğmuş ve tarımsal ticaretle doğrudan bağlantılıdır.",
        aciklama: "Doğru yanıt B'dir. Schmandt-Besserat'ın araştırması, yazının köklerinin tahıl, yağ ve hayvan miktarlarını kayıt altına almak için kullanılan kil tokenlara dayandığını ortaya koymaktadır. Bu, yazının ekonomik ve ticari ihtiyaçtan doğduğunu kanıtlar. A seçeneğinde dinî amaç ön plana çıkarılmış; ancak metinde bunun kanıtı yoktur. C seçeneğinde çivi yazısının MÖ 8000'de kullanıldığı söylenmektedir; oysa metin bu tarihi tokenlar için vermiş, çivi yazısını MÖ 3100'e bağlamıştır. D seçeneği edebiyat ve sanat kayıtlarını öne çıkarır, bu da metinle çelişir. E seçeneği iki gelişmenin bağımsız olduğunu öne sürer; metin ise bir ilişkiyi ima etmektedir."
    },
    {
        soru: "<i>\"Tarımsal yerleşim, toprağı soyut bir değere dönüştürdü. İnsanlar artık belirli bir arazinin sürekliliğine yatırım yapıyor, onu sulayıp gübreliyor ve yıllar içinde verimliliğini artırmak için emek harcıyordu. Bu birikim ve yatırım, 'benim toprağım' duygusunun ve miras hukukunun temelini attı.\" (Kaynak: Max Weber, Economy and Society, 1922 – uyarlanmıştır)</i><br><br><b>Weber'in bu çözümlemesine göre, tarımın ortaya çıkardığı en köklü zihinsel/hukuki dönüşüm aşağıdakilerden hangisidir?</b>",
        secenekler: [
            "A) İnsanların toprağı ortak mülk saydığı geleneksel düzenin güçlendirilmesi",
            "B) Toprağa yapılan uzun vadeli yatırımın, özel mülkiyet ve miras hukuku kavramlarının doğuşunu tetiklemesi",
            "C) Her köylünün eşit miktarda arazi sahibi olmasını güvence altına alan hukuk sistemlerinin gelişmesi",
            "D) Toprağın soyut bir değer kazanması sürecinin yalnızca ticari amaçlarla ortaya çıkması",
            "E) Miras hukukunun, tarımın başlamasından yüzyıllar sonra ve ondan tamamen bağımsız olarak gelişmesi"
        ],
        cevap: "B) Toprağa yapılan uzun vadeli yatırımın, özel mülkiyet ve miras hukuku kavramlarının doğuşunu tetiklemesi",
        aciklama: "Doğru yanıt B'dir. Weber'in argümanının özü, toprağa yapılan uzun vadeli emek ve yatırımın \"benim toprağım\" duygusunu ve miras hukukunu doğurduğudur. Bu, özel mülkiyet kavramının tarımla birlikte ortaya çıktığını gösterir. A seçeneği ortak mülk geleneğini güçlendirme söz eder; bu metnin aksine bir iddiadır. C seçeneği eşit arazi dağılımından bahseder; metinde böyle bir güvenceden söz edilmez. D seçeneği yalnızca ticari amacı öne çıkarır; Weber'in metninde ise yatırım ve birikim boyutu belirleyicidir. E seçeneği tarım ve miras hukukunu birbirinden koparır; metin ise bu iki olguyu nedensellik bağı içinde sunar."
    },
    {
        soru: "<i>\"İlk köylerde herkes hem çiftçilik hem de basit araç yapımı gibi birden fazla işi yapıyordu. Ancak nüfus arttıkça ve besin fazlası oluştukça, bazı bireyler tarımsal üretimden çekilip tüm zamanlarını çanak çömlek, dokuma ya da maden işleme gibi alanlara ayırabildi. Bu uzmanlaşma, zanaatları bilim ve sanat boyutuna taşıdı.\" (Kaynak: Colin Renfrew, Archaeology and Language, 1987 – uyarlanmıştır)</i><br><br><b>Renfrew'ün bu aktarımına göre uzmanlaşmanın önkoşulu nedir ve uzmanlaşma topluma ne katar?</b>",
        secenekler: [
            "A) Uzmanlaşma, nüfusun azalması durumunda ortaya çıkar ve toplumu basitleştirir.",
            "B) Besin fazlası ve nüfus artışı, bazı bireylerin tarım dışı alanlara odaklanmasına olanak tanır ve bu durum zanaat bilgisini derinleştirir.",
            "C) Uzmanlaşma, herkesin aynı işi yapmasını zorunlu kılarak toplumsal farklılıkları azaltır.",
            "D) İş bölümü, besin fazlasından tamamen bağımsız olarak yalnızca kişisel yeteneklere göre ortaya çıkar.",
            "E) Uzmanlaşma, her bireyin tarım ve zanaat işlerini aynı anda daha iyi yapmasını sağlamıştır."
        ],
        cevap: "B) Besin fazlası ve nüfus artışı, bazı bireylerin tarım dışı alanlara odaklanmasına olanak tanır ve bu durum zanaat bilgisini derinleştirir.",
        aciklama: "Doğru yanıt B'dir. Renfrew'e göre besin fazlası ve nüfus artışı, bazı bireylerin tarımdan çekilip zanaata odaklanmasını mümkün kılmıştır; bu da zanaat bilgisini derinleştirmiştir. A seçeneğinde nüfus azalması ve toplumun basitleşmesi söz konusu edilmekte; bu metnin içeriğiyle çelişmektedir. C seçeneği uzmanlaşmanın eşitlik yarattığını ima eder; bu da yanlıştır. D seçeneği besin fazlasından bağımsız bir nedeni öne sürer; metinde ise açıkça korelasyon kurulmaktadır. E seçeneği, uzmanlaşmanın her bireyi çok yönlü kıldığını söyler; bu ise metindeki \"tarımdan çekilme\" ifadesiyle doğrudan çelişir."
    },
    {
        soru: "<i>\"MÖ 3500 civarında Güney Mezopotamya'da ortaya çıkan Uruk kenti, dünya tarihinin ilk gerçek şehri olarak kabul edilebilir. Surlarla çevrili bu kentte tapınak, depo, pazar ve idari bina gibi işlevsel bölgeler ayrışmıştı. Kentte yaşayan insanların yarısından fazlası doğrudan tarımla uğraşmıyor, başka hizmet ve meslekleri icra ediyordu.\" (Kaynak: Samuel Noah Kramer, History Begins at Sumer, 1956/1981 – uyarlanmıştır)</i><br><br><b>Kramer'in aktardığı bilgilerden yola çıkarak Uruk'un 'ilk gerçek şehir' sayılmasının gerekçesi ne olabilir?</b>",
        secenekler: [
            "A) Uruk, tarihte ilk kez surlarla korunan bir yerleşim yeri olduğu için şehir sayılmaktadır.",
            "B) Tarım dışı mesleklerin varlığı ve işlevsel bölgelere ayrışma, toplumsal karmaşıklık ve uzmanlaşmanın geliştiğini gösterir; bu özellikler Uruk'u bir şehir yapar.",
            "C) Uruk'u şehir yapan yegâne unsur, tapınağın varlığıdır.",
            "D) Nüfusunun tamamı tarımla geçimini sağladığı için Uruk gerçek bir tarım kenti olarak öne çıkmaktadır.",
            "E) İdari bina ve depoların varlığı yalnızca askeri amaçlara hizmet ettiğinden şehri benzersiz kılmıştır."
        ],
        cevap: "B) Tarım dışı mesleklerin varlığı ve işlevsel bölgelere ayrışma, toplumsal karmaşıklık ve uzmanlaşmanın geliştiğini gösterir; bu özellikler Uruk'u bir şehir yapar.",
        aciklama: "Doğru yanıt B'dir. Kramer'in betimlemesinde birden fazla kriter dikkat çekmektedir: işlevsel bölgelere ayrışma ve nüfusun yarısından fazlasının tarım dışı mesleklerle geçimini sağlaması. Bu iki unsur, uzmanlaşmış ve karmaşık bir toplumsal örgütlenmeye, yani kentsel yaşamın temel özelliklerine işaret eder. A seçeneği tek bir kriteri (surlar) öne çıkarır; oysa metin birden fazla unsur sunmaktadır. C seçeneği tapınağı yegâne kriter olarak gösterir, bu da metnin bütünüyle çelişir. D seçeneği, metnin tam tersini söyler. E seçeneği idari yapıları yalnızca askeri amaçlara bağlar; metin ise bunları idari ve ekonomik işlevlere bağlamaktadır."
    },
    {
        soru: "<i>\"Sümer tapınak ekonomisinde tahıl ve diğer ürünler, büyük tapınak depolarında toplanıyor; ardından işçilere, din adamlarına ve askerlere dağıtılıyordu. Bu sistem, fiilî bir yeniden dağıtım ekonomisi yaratmıştı. Tapınak yönetimi; kayıtları tutmak, işçi listelerini güncellemek ve tahsis miktarlarını belirlemek için bürokrasi geliştirdi.\" (Kaynak: Mario Liverani, Uruk: The First City, 2006 – uyarlanmıştır)</i><br><br><b>Liverani'nin aktardığı tapınak ekonomisi modeline göre, bu sistemin en önemli siyasi ve idari sonucu nedir?</b>",
        secenekler: [
            "A) Tapınak ekonomisi, bireysel mülkiyeti güçlendirerek eşitsizlikleri kalıcı biçimde çözmüştür.",
            "B) Kaynakların toplanıp dağıtılması, kayıt tutma ve bürokrasiye olan ihtiyacı artırarak merkezi idari yapıyı güçlendirmiştir.",
            "C) Tapınak depoları, yalnızca din adamlarının kişisel zenginleşmesi amacıyla kullanılmıştır.",
            "D) Tahıl dağıtım sistemi, yazının gereksiz hâle gelmesine yol açmıştır.",
            "E) Tapınak ekonomisi, tarım dışı mesleklerin tamamen yok olmasına neden olmuştur."
        ],
        cevap: "B) Kaynakların toplanıp dağıtılması, kayıt tutma ve bürokrasiye olan ihtiyacı artırarak merkezi idari yapıyı güçlendirmiştir.",
        aciklama: "Doğru yanıt B'dir. Liverani'nin metninde tapınak ekonomisinin kayıt tutma, liste güncelleme ve bürokrasi gerektirdiği açıkça belirtilmektedir. Bu durum, merkezi idari yapının güçlendiğine işaret etmektedir. A seçeneği eşitsizliklerin çözıldüğünü iddia eder; metin bunun kanıtını vermemektedir. C seçeneği yalnızca din adamlarının çıkarını öne çıkarır; ancak metinde işçi ve askerlere de dağıtım yapıldığı belirtilmektedir. D seçeneği yazının gereksiz hale geldiğini söyler; bu ise tam tersi bir sonuçtur. E seçeneğinde tarım dışı mesleklerin yok olduğu iddia edilmekte, bu da metnin ruhuna aykırıdır."
    },
    {
        soru: "<i>\"Avcı-toplayıcı topluluklarda çatışmalar genellikle anlık ve bireysel düzeydeydi. Tarımsal yerleşimle birlikte arazi, su kaynakları ve depolanmış besinler kalıcı ve savunulabilir değerlere dönüştü. Bu değerlerin korunması ya da ele geçirilmesi, örgütlü ve sürekli bir savaş kapasitesinin gelişmesini zorunlu kıldı.\" (Kaynak: Azar Gat, War in Human Civilization, 2006 – uyarlanmıştır)</i><br><br><b>Gat'ın bu analizine göre, tarımsal düzenin savaş biçimini dönüştürmesinin temel nedeni nedir?</b>",
        secenekler: [
            "A) Tarım toplumları, savaşı yalnızca dinî ritüel olarak benimsediğinden savaş kapasitesi gelişmiştir.",
            "B) Tarımla birlikte ortaya çıkan kalıcı ve savunulabilir değerler, örgütlü savaşın motivasyonunu ve gerekliliğini artırmıştır.",
            "C) Avcı-toplayıcı topluluklarda örgütlü savaş, tarım toplumlarından daha yaygındı.",
            "D) Savaş kapasitesi, tarımdan bağımsız olarak yalnızca nüfus artışının bir sonucudur.",
            "E) Tarım toplumları, kaynakları kolayca terk edebildiğinden savunma ihtiyacı duymamıştır."
        ],
        cevap: "B) Tarımla birlikte ortaya çıkan kalıcı ve savunulabilir değerler, örgütlü savaşın motivasyonunu ve gerekliliğini artırmıştır.",
        aciklama: "Doğru yanıt B'dir. Gat'ın temel argümanı, tarımla birlikte arazi, su ve depolanmış besin gibi \"kalıcı ve savunulabilir değerlerin\" ortaya çıkmasının savaşı örgütlü ve sürekli bir hale getirdiğidir. A seçeneğinde dinî ritüel gerekçesi metinde yer almaz. C seçeneği avcı-toplayıcılarda örgütlü savaşı daha yaygın gösterir; bu metnin tam tersidir. D seçeneği tarımdan bağımsız bir neden öne sürer; Gat ise değerlerle motivasyonu bağdaştırmaktadır. E seçeneği, tarım toplumlarının kaynakları terk edebildiğini söyler; bu ise \"savunulabilir değerler\" kavramıyla çelişir."
    },
    {
        soru: "<i>\"Avcı-toplayıcı topluluklarda kadın ve erkek, birbirini tamamlayan üretim rolleri üstleniyordu. Tarımsal yerleşimle birlikte pulluk ve büyükbaş hayvanlarla çalışma erkek işine dönüşürken ev içi üretim ve çocuk bakımı kadınlar için öncelikli alan hâline geldi. Mülk devrinin erkek soyundan geçmesi için gereken 'kontrol edilebilir' üreme, kadın bedeni üzerinde denetim kurulmasını beraberinde getirdi.\" (Kaynak: Gerda Lerner, The Creation of Patriarchy, 1986 – uyarlanmıştır)</i><br><br><b>Lerner'in bu çözümlemesine göre, tarımın toplumsal cinsiyet ilişkilerine etkisi nasıl özetlenebilir?</b>",
        secenekler: [
            "A) Tarım, kadın ve erkek arasındaki iş bölümünü daha eşit hâle getirmiştir.",
            "B) Pullukla ilişkili iş gücü ve mülk mirasına dayalı kaygılar, kadın bedeninin denetim altına alınmasını meşrulaştıran ataerkil bir yapının zeminini hazırlamıştır.",
            "C) Tarım öncesinde kadınlar, toplumsal yaşamda tamamen edilgen ve ikincil bir konumdaydı.",
            "D) Tarımsal üretimde kadın emeği yok sayılmış, tarih boyunca hiçbir katkıları olmamıştır.",
            "E) Lerner, ataerkilliğin yalnızca yazılı hukukun ortaya çıkmasıyla başladığını öne sürmektedir."
        ],
        cevap: "B) Pullukla ilişkili iş gücü ve mülk mirasına dayalı kaygılar, kadın bedeninin denetim altına alınmasını meşrulaştıran ataerkil bir yapının zeminini hazırlamıştır.",
        aciklama: "Doğru yanıt B'dir. Lerner'in argümanı iki sacayağına dayanır: (1) pullukla çalışmanın erkeğe özgü bir faaliyet hâline gelmesi ve (2) mülk devrinin erkek soyundan geçmesini güvence altına almak için kadın bedeninin denetlenmesi. Bu iki unsur ataerkil yapının zeminini oluşturmuştur. A seçeneği eşitlik arttığını söyler; metin ise tam tersini iddia eder. C seçeneği tarım öncesinde kadının zaten ikincil konumda olduğunu öne sürer; metin ise görevlerin tamamlayıcı olduğunu belirtir. D seçeneği kadın emeğini tamamen yok sayan aşırı bir yargıdır. E seçeneği ataerkilliği yalnızca hukuki sürece bağlar; Lerner ise ekonomik ve üreme dinamiklerini ön plana çıkarmaktadır."
    },
    {
        soru: "<i>\"Tarım öncesinde bir düşmanı öldürmek yerine onu tutsaklamanın ekonomik bir mantığı yoktu; çünkü taşınabilir fazla bir servet yoktu. Tarımsal artık ürünün ortaya çıkmasıyla birlikte tutsak insanların zorla çalıştırılması kârlı hâle geldi. Sulama kanalı kazımaktan tahıl ezmek, tahıl biçmekten inşaat yapmaya kadar uzanan ağır işlerde köle emeği giderek vazgeçilmez oldu.\" (Kaynak: Moses Finley, Ancient Slavery and Modern Ideology, 1980 – uyarlanmıştır)</i><br><br><b>Finley'in bu çözümlemesine göre, kölelik kurumunun ortaya çıkmasını mümkün kılan ekonomik koşul nedir?</b>",
        secenekler: [
            "A) Kölelik, tarımsal artığın ortaya çıkmasından çok önce avcı-toplayıcı dönemde yaygın bir pratik olarak zaten mevcuttu.",
            "B) Tarımsal artığın varlığı, zorla çalıştırmanın ekonomik olarak anlamlı ve kârlı hale gelmesini sağlamıştır.",
            "C) Kölelik, yalnızca savaş esirlerini mübadele aracı olarak kullanan ticaret ağlarından doğmuştur.",
            "D) Köle emeği, tarımsal toplumda yalnızca ev içi hizmetler için kullanılmıştır.",
            "E) Tarım öncesi topluluklarda tutsak almak, ekonomik olarak tarım dönemine göre çok daha kârlıydı."
        ],
        cevap: "B) Tarımsal artığın varlığı, zorla çalıştırmanın ekonomik olarak anlamlı ve kârlı hale gelmesini sağlamıştır.",
        aciklama: "Doğru yanıt B'dir. Finley'in argümanının özü şudur: Tarım öncesinde tutsaklamanın ekonomik bir mantığı yoktu; ancak tarımsal artık ortaya çıkınca zorla çalıştırma kârlı hale geldi. Bu nedenle tarımsal artık, kölelik kurumunun ekonomik temelini oluşturmuştur. A seçeneği köleliğin tarım öncesinde yaygın olduğunu iddia eder; metin bunun aksini söyler. C seçeneğinde ticaret ağları tek neden olarak gösterilmektedir; Finley'nin odak noktası ise ekonomik verimdir. D seçeneği köle emeğini yalnızca ev içi hizmetlere bağlar; metinde çok daha geniş bir işlev yelpazesi sayılmaktadır. E seçeneği tarihi olarak tutarsız ve metnin teriyle çelişen bir iddiadır."
    },
    {
        soru: "<i>\"Ağır demir sabanın kullanılmasıyla birlikte ağır kil topraklar da tarıma açılabildi. Bu gelişme, büyük öküz ekiplerini besleyebilecek, dolayısıyla altyapı yatırımı yapabilecek büyük arazi sahiplerine avantaj sağladı. Küçük çiftçiler ise zamanla büyük toprak sahiplerine bağımlı hale geldi.\" (Kaynak: Lynn White Jr., Medieval Technology and Social Change, 1962 – uyarlanmıştır)</i><br><br><b>White'ın bu analizine göre, demir sabanın yaygınlaşması hangi toplumsal sonucu doğurmuştur?</b>",
        secenekler: [
            "A) Demir saban, küçük çiftçilerin büyük toprak sahiplerine karşı ekonomik bağımsızlığını artırmıştır.",
            "B) Teknolojik gelişme, kaynakları zaten olan büyük mülk sahiplerine avantaj sağlayarak küçük çiftçiler üzerindeki ekonomik bağımlılığı derinleştirmiştir.",
            "C) Ağır kil toprakların tarıma açılması, toplumsal hiyerarşiyi tamamen ortadan kaldırmıştır.",
            "D) Demir sabanın yaygınlaşması, hayvan gücünün tarımdan çekilmesine yol açmıştır.",
            "E) Büyük öküz ekipleri yalnızca din adamları tarafından kontrol edilmiştir."
        ],
        cevap: "B) Teknolojik gelişme, kaynakları zaten olan büyük mülk sahiplerine avantaj sağlayarak küçük çiftçiler üzerindeki ekonomik bağımlılığı derinleştirmiştir.",
        aciklama: "Doğru yanıt B'dir. White'ın argümanı, teknolojik yeniliğin (demir saban) büyük arazi sahiplerine orantısız bir avantaj sunduğunu ve küçük çiftçileri bağımlı hale getirdiğini ortaya koymaktadır. Bu, teknolojik ilerlemenin otomatik olarak eşitlikçi sonuçlar doğurmadığını gösterir. A seçeneği teknolojinin küçük çiftçilere yarar sağladığını söyler; metin bunun aksini belirtmektedir. C seçeneğinde hiyerarşinin tamamen kalktığı iddia edilmektedir; metin ise güç dengesizliğini vurgular. D seçeneğinde hayvan gücünün tarımdan çekilmesi söz konusu edilmektedir; metin ise büyük öküz ekiplerinin kullanımının arttığını anlatmaktadır. E seçeneği din adamlarına dair bir iddia taşır; metinde bu bilgi yer almaz."
    },
    {
        soru: "<i>\"Eğer bir bahçıvan, birinin bahçesini kiralamak üzere alır ve sonunda bahçenin ürününü sahibine teslim etmezse; bahçe sahibi, o bahçenin komşu bahçelere göre verdiği ortalama ürünü hesaplayarak bahçıvandan alacaktır. Bahçıvan, toprağa bakım yapmamışsa tarlayı çevresindekilerle eşit hale getirinceye kadar kendisi işleyecektir.\" (Kaynak: Hammurabi Kanunları'ndan uyarlanmıştır, MÖ 1754)</i><br><br><b>Bu yasal düzenlemeyi okuyan bir öğrenci, toplumsal yapı hakkında hangi çıkarımı yapabilir?</b>",
        secenekler: [
            "A) Hammurabi Kanunları döneminde tarım tamamen devlet mülkiyetinde olup bireylerin arazi kiralaması yasaktı.",
            "B) Tarımsal ilişkilerin yasal çerçeveye oturtulması, kiracı-mal sahibi gibi toplumsal rollerin belirginleştiğini ve devletin üretimi düzenlemeye başladığını göstermektedir.",
            "C) Bu kanun maddesi, yalnızca kölelere yönelik yaptırımları düzenlemektedir.",
            "D) Komşu bahçelerle karşılaştırma yapılması, bireyselciliğin tarım toplumunda tamamen ortadan kalktığını kanıtlar.",
            "E) Hammurabi Kanunları, sözlü geleneklere dayandığından yazılı bir hukuk sisteminin varlığına kanıt sayılamaz."
        ],
        cevap: "B) Tarımsal ilişkilerin yasal çerçeveye oturtulması, kiracı-mal sahibi gibi toplumsal rollerin belirginleştiğini ve devletin üretimi düzenlemeye başladığını göstermektedir.",
        aciklama: "Doğru yanıt B'dir. Bu kanun maddesi, kiracı ve mal sahibi arasındaki anlaşmazlıkları çözmeye yönelik olup tarımsal ilişkilerin yazılı hukuk çerçevesine alındığını göstermektedir. Bu durum hem kiracı-mülk sahibi gibi toplumsal rollerin belirginleştiğini hem de devletin tarımsal üretimi düzenlemeye başladığını ortaya koymaktadır. A seçeneği devlet mülkiyetini ve bireysel kiralama yasağını öne sürer; metnin içeriği tam tersini göstermektedir. C seçeneği kölelere atıfta bulunmaktadır; oysa metin \"bahçıvan ve bahçe sahibinden\" söz etmektedir. D seçeneğinde toplumsal bireyselcilik ve komşu karşılaştırması arasında hatalı bir çıkarım yapılmaktadır. E seçeneğinde yazılı hukuk sistemi reddedilmektedir; oysa bu tableti bizatihi yazılı bir hukuk belgesidir."
    },
    {
        soru: "<i>\"Her yıl düzenli olarak gerçekleşen Nil taşkını, çevresindeki arazileri verimli çamurla kaplıyor ve sulama kanallarına gerek kalmaksızın doğal bir gübrelik sağlıyordu. Bu düzenli ve öngörülebilir döngü, Mısırlılara Mezopotamyalılara kıyasla çok daha az idari koordinasyon gerektiren bir tarım sistemi kurma olanağı tanıdı.\" (Kaynak: John Romer, A History of Ancient Egypt, 2012 – uyarlanmıştır)</i><br><br><b>Bu metni Mezopotamya ile karşılaştıran bir öğrenci, hangi analitik çıkarıma ulaşabilir?</b>",
        secenekler: [
            "A) Mısır ve Mezopotamya'da tarım tamamen aynı koşullar altında gelişmiş, ikisi arasında hiçbir fark bulunmamaktadır.",
            "B) Doğal koşulların farklılığı, iki medeniyetin idari ve siyasi örgütlenme biçimlerini de farklılaştırmış olabilir.",
            "C) Nil taşkınlarının düzenli olması, Mısır'da tarımın hiç gelişmemesine yol açmıştır.",
            "D) Mezopotamya, Mısır'a kıyasla daha az bürokrasi gerektirdiğinden daha güçlü bir devlet yapısı kurmuştur.",
            "E) Sulama kanallarının yokluğu, Mısır'da kentleşme sürecini tamamen engellemiştir."
        ],
        cevap: "B) Doğal koşulların farklılığı, iki medeniyetin idari ve siyasi örgütlenme biçimlerini de farklılaştırmış olabilir.",
        aciklama: "Doğru yanıt B'dir. Metin, Mısır'ın doğal Nil taşkınları sayesinde Mezopotamya'ya kıyasla daha az idari koordinasyona ihtiyaç duyduğunu belirtmektedir. Bu, coğrafi farklılıkların idari ve siyasi örgütlenmeye yansıdığı anlamına gelir; yani çevre ile kurumsal yapı arasında nedensellik ilişkisi kurulabilir. A seçeneği farkları yok sayar. C seçeneği Nil taşkınlarının tarımı engellediğini iddia eder; metin bunun aksini söyler. D seçeneği Mezopotamya ve Mısır'ın idari gereksinimlerini yanlış biçimde tersine çevirir. E seçeneği kentleşmenin engellendiğini öne sürer; metin kentleşmeden değil, sulama ihtiyacından söz etmektedir."
    },
    {
        soru: "<i>\"Obsidyen, bakır, değerli taşlar ve tuz gibi bölgeye özgü hammaddeler, binlerce kilometre ötedeki topluluklar tarafından talep ediliyordu. Bu talep, farklı ekolojik bölgeler arasında sistematik takas güzergâhlarının oluşmasını sağladı. Ticaret, yalnızca mal alışverişi olmaktan çıkıp kültürel, teknolojik ve dilsel bilginin de aktarım kanalına dönüştü.\" (Kaynak: Philip Curtin, Cross-Cultural Trade in World History, 1984 – uyarlanmıştır)</i><br><br><b>Curtin'in bu tespitine göre, erken ticaret ağlarının uygarlık tarihindeki rolü nasıl değerlendirilebilir?</b>",
        secenekler: [
            "A) Erken ticaret, yalnızca ekonomik işlev üstlenmiş; kültür veya teknoloji aktarımıyla hiçbir ilgisi olmamıştır.",
            "B) Ticaret ağları, farklı topluluklar arasında hem maddi hem de kültürel-teknolojik bilgi alışverişine aracılık ederek medeniyetlerin birbirini etkilemesini sağlamıştır.",
            "C) Bölgeye özgü hammaddelerin ticareti, ticaret güzergâhlarının ortadan kalkmasına yol açmıştır.",
            "D) Ticaret ağları, yalnızca komşu topluluklar arasında ve kısa mesafelerde işleyebilmiştir.",
            "E) Kültürel bilgi aktarımı, ticaret ağlarından tamamen bağımsız olarak gerçekleşmiştir."
        ],
        cevap: "B) Ticaret ağları, farklı topluluklar arasında hem maddi hem de kültürel-teknolojik bilgi alışverişine aracılık ederek medeniyetlerin birbirini etkilemesini sağlamıştır.",
        aciklama: "Doğru yanıt B'dir. Curtin, ticaretin hem mal alışverişi hem de kültürel, teknolojik ve dilsel bilgi aktarımının kanalı hâline geldiğini açıklamaktadır. Bu, ticaret ağlarının medeniyetlerarası etkileşimi mümkün kıldığına dair güçlü bir kanıttır. A seçeneği ticaretin kültürel boyutunu reddeder; metin ise tam tersi bir iddiayı içermektedir. C seçeneği ticaret güzergâhlarının ortadan kalktığını öne sürer; metin ise sistematik güzergâhların oluştuğunu belirtir. D seçeneği uzun mesafeli ticareti dışlar; metnin özünde ise uzak bölgeler arası değiş tokuş yer almaktadır. E seçeneği kültürel bilgi aktarımını ticaretten koparır; metin ise bu ikisini doğrudan ilişkilendirir."
    },
    {
        soru: "<i>\"Pişirme ve tarımın birlikte oluşturduğu besin artışı, hem nüfus patlamasına hem de artan işbölümüne zemin hazırladı. Ne var ki bu 'bolluk', herkese eşit dağılmadı; aksine depolayan, yöneten ve organize eden gruplar, yalnızca üretenlerden her zaman daha güçlü çıktı. Bunun paradoksu şudur: toplumun genel refahı artarken, bireylerin yaşam kalitesi ve sağlık düzeyi çoğunlukla geriledi.\" (Kaynak: Richard Wrangham, Catching Fire: How Cooking Made Us Human, 2009 – uyarlanmıştır)</i><br><br><b>Wrangham'ın 'paradoks' olarak nitelendirdiği durumu, tarih felsefesi açısından en doğru yorumlayan seçenek hangisidir?</b>",
        secenekler: [
            "A) Uygarlık, bireysel iyileşme olmaksızın da kolektif büyüme yaşayabilir; bu da ilerleme kavramının tek boyutlu değerlendirilemeyeceğini gösterir.",
            "B) Tarımın yarattığı bolluk, toplumun tüm kesimlerinde eşzamanlı ve eşit bir iyileşme sağlamıştır.",
            "C) Wrangham, uygarlığın her zaman bireysel refahı artırdığını tarih dışı bir kesinlikle ortaya koymaktadır.",
            "D) Toplumsal refahın artması, siyasi iktidar yapılarını otomatik olarak eşitlikçi hâle getirir.",
            "E) Tarım toplumlarında bireysel yaşam kalitesindeki gerileme, paradoksal olmaktan çok istisnai bir durumdur."
        ],
        cevap: "A) Uygarlık, bireysel iyileşme olmaksızın da kolektif büyüme yaşayabilir; bu da ilerleme kavramının tek boyutlu değerlendirilemeyeceğini gösterir.",
        aciklama: "Doğru yanıt A'dır. Wrangham'ın paradoksu, \"toplumsal refah artarken bireylerin sağlık ve yaşam kalitesinin gerileyebileceğini\" ortaya koyar. Bu, \"ilerleme\" kavramının kolektif ve bireysel boyutlarının birbirinden ayrışabileceğini, yani tarihsel ilerlemenin tek bir ölçütle değerlendirilemeyeceğini göstermektedir. B seçeneği eşit bir iyileşme olduğunu öne sürer; bu paradoksun tanımına aykırıdır. C seçeneği Wrangham'ın her koşulda iyileşme savunduğunu iddia eder; metin ise tam tersini içermektedir. D seçeneği refahın iktidar yapılarını otomatik eşitlikçileştirdiğini söyler; metin güç farklılıklarının derinleştiğini aktarmaktadır. E seçeneğinde yaşam kalitesindeki gerileme \"istisnai\" olarak küçümsenir; metin bunu genel bir eğilim olarak sunar."
    },
    {
        soru: "<i>\"İlk tarım toplulukları, ormansızlaşma, toprak erozyonu ve sulama tuzlanması gibi çevresel bozulmaya yol açtılar. Mezopotamya'da yoğun sulama, zamanla toprağı tuzlaştırdı ve bir dönem son derece verimli olan toprakları üretimsiz bıraktı. Sümer medeniyetinin çöküşünü açıklamak için bu ekolojik çöküşü göz ardı edemeyiz.\" (Kaynak: Clive Ponting, A Green History of the World, 1991 – uyarlanmıştır)</i><br><br><b>Ponting'in bu değerlendirmesini tarih metodolojisi açısından eleştirmek isteyen bir tarihçi, hangi argümanı öne sürebilir?</b>",
        secenekler: [
            "A) Ekolojik faktörler tarihsel açıklamada hiçbir zaman geçerli değildir; yalnızca siyasi nedenler kullanılmalıdır.",
            "B) Sümer'in çöküşünü tek bir etkenle (ekolojik bozulma) açıklamak, çok nedenli tarihsel olayları aşırı basitleştirebilir; başka faktörleri dışarıda bırakmak metodolojik bir sorun yaratır.",
            "C) Tuzlanma sorununun yalnızca modern dönemte ortaya çıktığını kanıtlamak, Ponting'i haklı çıkarır.",
            "D) Çevre tarihçilerinin tarihsel açıklamada yer almaması gerektiği ilkesi, Ponting'i geçersiz kılar.",
            "E) Ponting'in tezi, ancak Sümer'in çöküşünün MÖ 3000'den sonra gerçekleşmediği kanıtlanırsa çürütülmüş sayılır."
        ],
        cevap: "B) Sümer'in çöküşünü tek bir etkenle (ekolojik bozulma) açıklamak, çok nedenli tarihsel olayları aşırı basitleştirebilir; başka faktörleri dışarıda bırakmak metodolojik bir sorun yaratır.",
        aciklama: "Doğru yanıt B'dir. Tarih metodolojisinde tek bir etkenle karmaşık bir olayı açıklamak (monokauzalite) güçlü bir eleştiri konusudur. Ponting ekolojik bozulmayı öne çıkarmakta ancak siyasi çöküş, işgaller, ticaret yollarının değişmesi gibi faktörleri göz ardı edebilmektedir. Bu metodolojik zayıflık, \"çok nedenli açıklama\" ilkesini ihlal etmektedir. A seçeneği ekolojik açıklamanın geçersizliğini savunur; bu ise tarih felsefesinde kabul görmez. C seçeneği tuzlanmanın modern bir sorun olduğunu kanıtlamanın Ponting'i haklı çıkaracağını söyler; bu da mantıksal açıdan tutarsızdır. D seçeneği çevre tarihçilerini dışlar; bu ise tarih alanında kabul görmez. E seçeneği zaman koşuluna bağlı bir çürütme önerir; oysa asıl metodolojik sorun neden-sonuç bağının tek etkenle kurulmasıdır."
    },
    {
        soru: "<i>\"Evcilleştirilebilir bitki ve hayvan türlerinin dağılımı, hangi bölgelerin tarıma önce geçeceğini ve dolayısıyla kentleşme, uzmanlaşma ve teknoloji gibi 'sosyal kalkınma' göstergelerinde önde olacağını büyük ölçüde belirledi. Ancak bu coğrafi şans, tarihin geri kalanını tamamen deterministik biçimde belirlemiyor; sosyal kurumlar ve tarihsel krizler devreye girince sonuçlar değişebilmektedir.\" (Kaynak: Ian Morris, Why the West Rules—For Now, 2010 – uyarlanmıştır)</i><br><br><b>Morris'in bu yaklaşımını doğru yorumlayan ifade hangisidir?</b>",
        secenekler: [
            "A) Morris, tarihin tamamıyla coğrafya tarafından belirlendiğini ve insan iradesinin hiçbir rolü olmadığını savunmaktadır.",
            "B) Morris, coğrafyayı belirleyici bir başlangıç avantajı olarak görürken, sosyal kurumlar ve tarihsel krizlerin bu avantajı değiştirebileceğini kabul eder.",
            "C) Morris'e göre evcilleştirilebilir türlerin dağılımı, hangi toplumların her zaman galip geleceğini kesin olarak belirlemektedir.",
            "D) Sosyal kurumlar, coğrafyanın tarihsel etkisini tamamen ortadan kaldırmaktadır.",
            "E) Tarımın önce başladığı bölgeler, tarih boyunca hiçbir zaman güç kaybetmemiş ve daima dünyaya egemen olmuştur."
        ],
        cevap: "B) Morris, coğrafyayı belirleyici bir başlangıç avantajı olarak görürken, sosyal kurumlar ve tarihsel krizlerin bu avantajı değiştirebileceğini kabul eder.",
        aciklama: "Doğru yanıt B'dir. Morris'in yaklaşımı \"yumuşak determinizm\" olarak nitelendirilebilir: Coğrafya ve evcilleştirilebilir türlerin dağılımı güçlü bir başlangıç avantajı sunar; ancak bu avantaj sonuçları tamamen belirlemez. Sosyal kurumlar ve tarihsel krizler devreye girince tablolar değişebilir. A seçeneği tam determinist bir yorumdur; Morris bunu reddetmektedir. C seçeneği kesin bir üstünlük savunur; Morris ise \"tamamen deterministik değil\" demektedir. D seçeneği coğrafyanın etkisini sıfıra indirmektedir; bu da metinle çelişir. E seçeneği kalıcı hâkimiyeti savunur; tarih ise güç dengelerinin değiştiğini göstermektedir."
    },
    {
        soru: "<i>\"İlk devletler, tahıl tarımının etrafında örgütlendi; çünkü tahıl sayılabilir, taşınabilir ve depolanabilirdi—kısacası vergilendirilebilirdi. Devlet, vergilendirebildiği şeyin etrafında şekillendi. Kökleri yenilemeyen insanlar, taro (gölevez) yetiştirmeyen insanlar, kısmen de bu nedenle devlet dışında kaldılar.\" (Kaynak: James C. Scott, Against the Grain: A Deep History of the Earliest States, 2017 – uyarlanmıştır)</i><br><br><b>Scott'ın bu savına dayanarak, ilk devletlerin ortaya çıkmasında en belirleyici etkenin ne olduğu çıkarılabilir?</b>",
        secenekler: [
            "A) İlk devletler, tahılın vergilendirilebilir yapısından değil yalnızca askeri fetihlerden doğdu.",
            "B) Devletin varlığı ile tahıl tarımı arasında derin bir yapısal bağ bulunmaktadır; devlet, vergilendirip kayıt altına alabildiği artığın peşinden gitmiştir.",
            "C) Scott'a göre kök bitkileri yetiştiren topluluklar da aynı kolaylıkla devlet kurabilmiş ve devlet dışında kalmamıştır.",
            "D) Vergilendirme, devlet kurulmadan çok önce tahıl tarımından bağımsız biçimde gelişmiştir.",
            "E) Devletlerin örgütlenmesinde tahıl tarımının hiçbir rolü olmamış; yalnızca nüfus yoğunluğu belirleyici olmuştur."
        ],
        cevap: "B) Devletin varlığı ile tahıl tarımı arasında derin bir yapısal bağ bulunmaktadır; devlet, vergilendirip kayıt altına alabildiği artığın peşinden gitmiştir.",
        aciklama: "Doğru yanıt B'dir. Scott'ın temel iddiası, tahılın \"sayılabilir, taşınabilir ve depolanabilir\" özelliklerinin onu vergilendirilebilir kıldığı ve bu sayede devletin tahıl tarımının etrafında örgütlendiğidir. Bu, devlet ile tahıl tarımı arasında derin bir yapısal bağ olduğunu ortaya koymaktadır. A seçeneği askeri fetihleri tek neden olarak gösterir; metin ise ekonomik-yönetsel bir çerçeve sunar. C seçeneği kök bitkileri yetiştirenlerin devlet kurabileceğini söyler; Scott tam tersini ima etmektedir. D seçeneği vergilendirmeyi tarımdan bağımsız gösterir; metin bu iki olguyu birbirine bağlamaktadır. E seçeneği nüfus yoğunluğunu tek etken olarak öne çıkarır; Scott'ın odağı ise vergilendirilebilir artık kavramı etrafında şekillenmektedir."
    },
    {
        soru: "<i>\"Köprü üzerinde incelenen Neolitik dönem iskeletleri, avcı-toplayıcıların kemiklerine kıyasla daha düşük boylu, daha fazla diş çürüğüne ve kemik rahatsızlıklarına sahip bireyler olduğunu gösterdi. Kalabalık yaşam ve hayvanlarla temas, salgın hastalıkların yayılmasını kolaylaştırdı. Ancak paradoks şu: bu döneme ait toplulukların nüfusu yine de hızla artıyordu.\" (Kaynak: Spencer Wells, Pandora's Seed: The Unforeseen Cost of Civilization, 2010 – uyarlanmıştır)</i><br><br><b>Wells'in aktardığı bu paradoksu, Darwinci evrim kuramı çerçevesinde en tutarlı biçimde hangi seçenek açıklar?</b>",
        secenekler: [
            "A) Bireylerin sağlık düzeyinin düşmesi, toplumun çoğalma hızını daima olumsuz etkiler.",
            "B) Nüfus artışı için bireylerin optimal sağlığa sahip olması şart değildir; üreme başarısı arttığı sürece nüfus büyüyebilir, bu da bireysel sağlık ile demografik büyümenin her zaman paralel gitmediğini gösterir.",
            "C) Kalabalık yaşam koşulları, bağışıklık sistemini güçlendirerek nüfus artışına katkı sağlamıştır.",
            "D) Wells'in verileri yanlıştır; Neolitik döneme ait iskeletler avcı-toplayıcılara kıyasla daha sağlıklı bir yapı göstermektedir.",
            "E) Salgın hastalıkların yayılması, Neolitik topluluklarda genetik mutasyonları hızlandırarak boyu uzatmıştır."
        ],
        cevap: "B) Nüfus artışı için bireylerin optimal sağlığa sahip olması şart değildir; üreme başarısı arttığı sürece nüfus büyüyebilir, bu da bireysel sağlık ile demografik büyümenin her zaman paralel gitmediğini gösterir.",
        aciklama: "Doğru yanıt B'dir. Evrim kuramı açısından değerlendirildiğinde, \"uyum\" bireyin optimal sağlığı değil üreme başarısını ifade eder. Tarımsal yaşam bireylerin sağlığını olumsuz etkilese de düzenli besin temini ve kısa doğum aralıkları gibi etkenler üreme başarısını artırmış; bu da nüfus büyümesini sağlamıştır. Paradoks burada çözülmektedir: bireysel sağlık ile demografik başarı her zaman paralel seyretmez. A seçeneği sağlık düşüşünün nüfusu azaltacağını öne sürer; metin ise nüfusun arttığını göstermektedir. C seçeneği kalabalık yaşamın bağışıklığı güçlendirdiğini iddia eder; metin ise salgın hastalıkların kolaylaştığını söyler. D seçeneği Wells'in verilerini tersine çevirir. E seçeneği salgın hastalıkların boyu uzattığını iddia eder; bu biyolojik açıdan desteklenmez."
    },
    {
        soru: "<i>\"Avcı-toplayıcıların tanrıları çoğunlukla hayvan ruhları ve hareket eden doğa güçleriyle ilgiliydi. Yerleşik çiftçiler ise bereket, yağmur ve mevsimleri yöneten gök tanrıları ve toprak anaları geliştirdi. Tapınak, bu tanrılarla 'sözleşme' yapılan mekân hâline geldi; kurbanlar ve sunular, doğal döngülerin sürekliliğini güvence altına alan ritüel ekonomisi oluşturdu.\" (Kaynak: Karen Armstrong, A History of God, 1993 – uyarlanmıştır)</i><br><br><b>Armstrong'un çözümlemesine göre tarımla birlikte din anlayışındaki dönüşümü ve bu dönüşümün toplumsal işlevini en bütünlüklü açıklayan seçenek hangisidir?</b>",
        secenekler: [
            "A) Tarım toplumlarında dini düşünce tamamen ekonomik kaygılardan bağımsız bir gelişme göstermiştir.",
            "B) Tarımsal yaşamın düzenli, öngörülebilir bir doğa döngüsüne bağımlılığı; bereket ve mevsimleri yöneten tanrılar ile tapınak-sözleşme ritüellerini doğurmuş, din böylece tarımsal üretim riskini yönetme işlevi üstlenmiştir.",
            "C) Avcı-toplayıcıların dini inançları, tarım toplumlarından çok daha gelişmiş ve karmaşık bir yapıya sahipti.",
            "D) Tapınaklar yalnızca siyasi iktidarın merkezleri olarak tasarlanmış; doğa güçleriyle herhangi bir ilişki kurulmamıştır.",
            "E) Tarım toplumlarındaki ritüel ekonomi, din ve ekonominin birbirinden tamamen ayrılmasını sağlamıştır."
        ],
        cevap: "B) Tarımsal yaşamın düzenli, öngörülebilir bir doğa döngüsüne bağımlılığı; bereket ve mevsimleri yöneten tanrılar ile tapınak-sözleşme ritüellerini doğurmuş, din böylece tarımsal üretim riskini yönetme işlevi üstlenmiştir.",
        aciklama: "Doğru yanıt B'dir. Armstrong'un argümanı birbirini tamamlayan iki unsur içermektedir: (1) Tarımsal yaşamın doğa döngülerine bağımlılığı, bereket ve mevsimleri kontrol eden tanrıların gelişmesine yol açmıştır. (2) Tapınak ve kurban ritüelleri, bu tanrılarla \"sözleşme\" kurarak tarımsal riskleri yönetmenin sembolik bir aracına dönüşmüştür. Yani din, bu dönemde toplumsal bir risk yönetim mekanizması işlevi üstlenmiştir. A seçeneği dini ekonomik süreçlerden koparır; metin ise bu iki olguyu doğrudan ilişkilendirir. C seçeneği avcı-toplayıcıların daha gelişmiş bir dini yapısı olduğunu öne sürer; metin farklı bir karmaşıklıktan söz eder. D seçeneği tapınak ve doğa güçleri arasındaki bağı reddeder; metin ise tam tersini savunmaktadır. E seçeneği din ile ekonominin birbirinden ayrıldığını iddia eder; Armstrong'un \"ritüel ekonomisi\" kavramı bu ikisinin iç içe geçtiğini göstermektedir."
    },
    {
        soru: "<i>\"Toprak köylünün ruhunun temelidir; o toprağı kazarken uygarlığın tohumlarını da eker. Ama aynı toprak, ürettiği kentleri ve o kentlerin yarattığı 'para ekonomisi'ni besleyince, kendi ruhunu çürütecek bir güç doğurmuş olur.\" (Kaynak: Oswald Spengler, The Decline of the West, 1918-1922 – uyarlanmıştır)</i><br><br><b>Spengler'in bu metaforik ifadesinden yola çıkarak, tarımın uygarlık tarihi üzerindeki diyalektik etkisini en doğru yorumlayan seçenek hangisidir?</b>",
        secenekler: [
            "A) Spengler'e göre tarım, uygarlıkları güçlendiren tek etkendir ve herhangi bir olumsuz sonuç doğurmaz.",
            "B) Tarım, uygarlıkların hem kuruluşunu hem de içsel çöküşünü besleyen bir diyalektik güç olarak işlev görür; kentleşme ve para ekonomisi, tarımın doğurduğu ama köklü değerlerini aşındıran bir karşı güç oluşturur.",
            "C) Spengler, para ekonomisinin ortaya çıkmasını yalnızca köylünün ahlaki yozlaşmasına bağlamaktadır.",
            "D) Spengler'in metaforu, tarımın kentleşmeyi tamamen engellediği anlamına gelmektedir.",
            "E) Spengler, tarım ve ticaret arasındaki ilişkiyi incelemeksizin yalnızca politik çöküşü analiz etmektedir."
        ],
        cevap: "B) Tarım, uygarlıkların hem kuruluşunu hem de içsel çöküşünü besleyen bir diyalektik güç olarak işlev görür; kentleşme ve para ekonomisi, tarımın doğurduğu ama köklü değerlerini aşındıran bir karşı güç oluşturur.",
        aciklama: "Doğru yanıt B'dir. Spengler'in diyalektik mantığı şudur: Tarım, köylünün ruhu ve uygarlığın temeli olarak bir inşa gücüdür. Ancak tarım, kentleri ve para ekonomisini besleyerek bu köklü değerlerin aşınmasına zemin hazırlar. Bu, Hegelci \"tez-antitez\" mantığını tarih felsefesine uygulamaktadır: tarım hem inşa eden hem de kendi karşıtını doğuran bir güçtür. A seçeneği olumlu-olumsuz diyalektiği görmezden gelir. C seçeneği para ekonomisini yalnızca bireysel ahlaki yozlaşmaya bağlar; Spengler ise yapısal bir güç ilişkisinden söz eder. D seçeneği kentleşmenin engellendiğini öne sürer; metin tam tersini anlatmaktadır. E seçeneğinde politik çöküşe odaklanıldığı iddia edilir; metnin odağı ise kültürel-uygarlık diyalektiğidir."
    }
];
// --- 2. ÜNİTE: TARIM DEVRİMİNİN ESKİ ÇAĞ'A ETKİLERİ - TEST 5 ---
window.allTests["test_u2_tarim_5"] = [
    {
        soru: "<i>\"İnsanlığın uzun tarihine bakıldığında, avcı-toplayıcı dönemin yaklaşık 200.000 yıl sürdüğü görülmektedir. Tarımın başlamasından bu yana ise yalnızca yaklaşık 12.000 yıl geçmiştir. Bu kısa süreye rağmen tarım, dünya nüfusunu birkaç milyondan bugünkü seviyelere taşıyan en önemli dönüşümü gerçekleştirmiştir.\" (Kaynak: Felipe Fernández-Armesto, Food: A History, 2001, s. 22 – uyarlanmıştır)</i><br><br><b>Metne göre tarımın insanlık tarihi açısından en belirgin sonucu nedir?</b>",
        secenekler: [
            "A) Avcı-toplayıcılık döneminin sona ermesi",
            "B) Dünya nüfusunun dramatik biçimde artmasını mümkün kılması",
            "C) İnsanların hayvanlarla rekabet etmesinin önüne geçmesi",
            "D) Tarih öncesi dönemin başlaması",
            "E) İnsanların göç etmeyi bırakması"
        ],
        cevap: "B) Dünya nüfusunun dramatik biçimde artmasını mümkün kılması",
        aciklama: "Doğru cevap B’dir. Metin, 12.000 yıllık tarımın dünya nüfusunu birkaç milyondan günümüz düzeyine taşıdığını açıkça belirtmektedir. Bu, tarımın insan nüfusu üzerindeki en somut ve ölçülebilir etkisidir. Diğer seçenekler metinde bu kadar açık biçimde desteklenmemektedir."
    },
    {
        soru: "<i>\"Mezopotamya'da Uruk dönemine ait kil mühürler üzerinde yapılan analizde, mühürlerin genellikle ambar kapılarını, depolama kaplarını ve mal paketlerini kapatmak için kullanıldığı anlaşılmıştır. Her mühür, mal sahibini ya da sorumlu kişiyi temsil ediyordu. Araştırmacılar bu bulguları, özel ya da kurumsal mülkiyet kavramının erken bir göstergesi olarak yorumlamaktadır.\" (Kaynak: Denise Schmandt-Besserat, How Writing Came About, 1996, s. 41 – uyarlanmıştır)</i><br><br><b>Bu bulguya göre kil mühürlerin temel işlevi neydi?</b>",
        secenekler: [
            "A) Dini törenlerde tanrılara mesaj iletmek",
            "B) Sanatsal dekorasyon amacıyla kullanmak",
            "C) Depolanmış mallara sahiplik veya sorumluluk atfetmek",
            "D) Askeri birlikleri tanımlamak",
            "E) Coğrafi sınırları belirlemek"
        ],
        cevap: "C) Depolanmış mallara sahiplik veya sorumluluk atfetmek",
        aciklama: "Doğru cevap C’dir. Metin, mühürlerin ambar kapıları ve depolama kaplarını kapatmak, mal sahibini temsil etmek amacıyla kullanıldığını belirtmektedir. Bu, mülkiyet ve sorumluluk atfının bir aracıdır. Sanat, din veya askerlik bu metinde geçmemektedir."
    },
    {
        soru: "<i>\"Arpa ve buğday önce hayvanlar için yem olarak değil, doğrudan insan tüketimi için kültüre alındı. Ancak zamanla çiftçiler, kültüre alınmış tahıl artıklarını ve düşük kaliteli ürünü hayvanlarına yedirmeye başladı. Bu geri dönüşüm, tarım ve hayvancılığı birbirine bağlayan entegre bir ekonominin ilk biçimini oluşturdu.\" (Kaynak: Andrew Sherratt, The Secondary Exploitation of Animals in the Old World, World Archaeology, 1983 – uyarlanmıştır)</i><br><br><b>Bu metne göre tarım ve hayvancılık arasındaki ekonomik ilişki nasıl ortaya çıkmıştır?</b>",
        secenekler: [
            "A) Hayvancılık tarımı beslemek için organize edilmiştir",
            "B) Tarım artıklarının hayvanlara yedirilmesi iki faaliyeti birbirine bağlamıştır",
            "C) Tahıl kültürü, evcilleştirme tamamlanmadan başlayamıyordu",
            "D) Hayvanlar tarımda yalnızca tarla çekimi için kullanılmıştır",
            "E) Entegre ekonomi, devletin müdahalesiyle oluşmuştur"
        ],
        cevap: "B) Tarım artıklarının hayvanlara yedirilmesi iki faaliyeti birbirine bağlamıştır",
        aciklama: "Doğru cevap B’dir. Metin, düşük kaliteli tahıl ve artıkların hayvanlara verilmesiyle iki faaliyetin entegre bir ekonomiye dönüştüğünü açıkça ifade etmektedir. Bu, planlı bir politikanın değil, pratik bir geri dönüşümün ürünüdür."
    },
    {
        soru: "<i>\"Asur Ticaret Kolonileri döneminde (MÖ 1950-1750) Anadolu'daki Kaneş (Kültepe) kolonisinde bulunan kil tabletler, Asurlu tüccarların Mezopotamya'dan kalay ve kumaş getirip Anadolu'dan gümüş ve altın aldığını göstermektedir. Bu ticaretin temelinde Mezopotamya'nın tahıl fazlasıyla beslenen dokumacılık endüstrisi yatmaktadır; tahıl dokumacıyı, dokumacı ticaret ağını besliyordu.\" (Kaynak: Mogens Trolle Larsen, The Old Assyrian City-State and its Colonies, 1976, s. 89 – uyarlanmıştır)</i><br><br><b>Bu metne göre Asur ticaret ağının temelinde hangi zincir yatmaktadır?</b>",
        secenekler: [
            "A) Maden kaynakları → Ticaret → Dokumacılık → Tahıl",
            "B) Tahıl fazlası → Dokumacı beslenmesi → Kumaş üretimi → Uzak mesafe ticareti",
            "C) Altın → Kumaş → Tahıl → Ticaret kolonisi",
            "D) Devlet yatırımı → Ticaret kolonisi → Tahıl üretimi",
            "E) Kaneş kolonisi → Mezopotamya tahılı → Asur ordusu"
        ],
        cevap: "B) Tahıl fazlası → Dokumacı beslenmesi → Kumaş üretimi → Uzak mesafe ticareti",
        aciklama: "Doğru cevap B’dir. Metin açıkça şu zinciri kurmaktadır: Tahıl fazlası → Dokumacının beslenmesi → Kumaş üretimi → Uzak mesafe ticareti. Bu zincir doğru okunduğunda B seçeneği öne çıkmaktadır. Tarımsal artı ürün, ticaret ağının en temel halkasıdır."
    },
    {
        soru: "<i>\"Antik Mısır'da \"shabtiler\" adı verilen küçük figürinler, mezarlara konulurdu. Üzerlerindeki yazıtlarda şu ifade geçer: Öteki dünyada yapılacak tarım işleri için çağrıldığımda, buraya hazırım; tarlayı süreceğim, kanalları kazıyacağım, tahılı taşıyacağım. Bu ritüel nesneler, tarımın Mısır ölüm sonrası anlayışına ne kadar derin işlediğini göstermektedir.\" (Kaynak: John H. Taylor, Death and the Afterlife in Ancient Egypt, 2001, s. 114 – uyarlanmıştır)</i><br><br><b>Shabti figürinleri, Tarım Devrimi’nin Mısır dini inançları üzerindeki etkisini nasıl yansıtmaktadır?</b>",
        secenekler: [
            "A) Mısırlılar ölüm sonrası dünyayı tarımdan tamamen bağımsız bir cennet olarak tasarlamıştır",
            "B) Tarımsal faaliyetler, Mısırlılar için o denli temel bir yaşam pratiğiydi ki ölüm sonrası anlayışı da tarımsal imgelerle şekillenmiştir",
            "C) Shabtiler yalnızca sanatsal dekorasyon amacıyla üretilmiştir",
            "D) Mısır'da tarım yalnızca din adamı sınıfına ait bir etkinlikti",
            "E) Öteki dünyada tarım yapılacağı inancı, tarımı sıradan bir iş saymayan Mısırlıların protestosudur"
        ],
        cevap: "B) Tarımsal faaliyetler, Mısırlılar için o denli temel bir yaşam pratiğiydi ki ölüm sonrası anlayışı da tarımsal imgelerle şekillenmiştir",
        aciklama: "Doğru cevap B’dir. Tarla sürme, kanal kazma ve tahıl taşıma gibi tarımsal görevlerin öteki dünya anlayışına taşınması, tarımın Mısır toplumunda günlük yaşamın vazgeçilmez çekirdeğini oluşturduğunu ve bu önemi dini inançları da biçimlendirdiğini göstermektedir."
    },
    {
        soru: "<i>\"Sümer metinlerinde tanrı Enlil'e yönelik bir ilahide şöyle geçer: Sen tüm tohumları ve tahılları yarattın; sen meyvelerin ve bitkilerin efendisisin; Sümer'in tarlalarını senin nefesin sular, ve senin emrinle çiftçi sabanını kaldırır. Bu ilahi, bereket ve tarım tanrıları panteonunun merkezi figürü olarak Enlil'i konumlandırmaktadır.\" (Kaynak: Thorkild Jacobsen, The Treasures of Darkness, 1976, s. 101 – uyarlanmıştır)</i><br><br><b>Bu Sümer ilahisi, tarımsal toplumların dini inanç sistemleriyle ilişkisi hakkında ne söylemektedir?</b>",
        secenekler: [
            "A) Enlil, Sümer'de yalnızca savaş tanrısı olarak bilinmekteydi",
            "B) Tarıma bağımlı toplumlar, doğa ve tarım süreçlerini tanrısal bir güçle ilişkilendirerek kutsallaştırmıştır",
            "C) Tarım Sümerlerde dini pratiklerden tamamen ayrı tutulmuştur",
            "D) Bu ilahi, tarımın insan çabasına değil yalnızca doğaya bağlı olduğunu savunmaktadır",
            "E) Enlil kültü, tarımın çöküşüne yol açan bir inanç sistemidir"
        ],
        cevap: "B) Tarıma bağımlı toplumlar, doğa ve tarım süreçlerini tanrısal bir güçle ilişkilendirerek kutsallaştırmıştır",
        aciklama: "Doğru cevap B’dir. İlahi, tarımsal süreçlerin (tohum, meyve, sulama, saban) doğrudan tanrısal otoriteyle ilişkilendirildiğini göstermektedir. Tarımsal toplumların doğa güçlerini tanrısallaştırması, bereketli hasat için ilahi lütfa bağımlılığın bir yansımasıdır."
    },
    {
        soru: "<i>\"Erken Neolitik dönemde Orta Anadolu'da hayvanların evcilleştirilme süreci ele alındığında, keçi ve koyunun sığırdan önce evcilleştirildiği görülmektedir. Arkeologlar bu sıralamayı, küçük sürülerin yönetiminin daha kolay olmasına ve keçi-koyunun kısa sürede et, süt ve yün sağlamasına bağlamaktadır. Bu çok yönlü verimlilik, erken çiftçiler için en pratik tercih oldu.\" (Kaynak: Melinda Zeder, Central Questions in the Domestication of Plants and Animals, Evolutionary Anthropology, 2006 – uyarlanmıştır)</i><br><br><b>Bu metne göre keçi ve koyunun sığırdan önce evcilleştirilmesinin temel nedeni nedir?</b>",
        secenekler: [
            "A) Sığırların Anadolu'da doğal olarak bulunmaması",
            "B) Küçük sürü yönetiminin kolaylığı ve bu hayvanların çok yönlü ürün sunması",
            "C) Keçi ve koyunun tarla işlerinde sığırdan daha verimli olması",
            "D) Devletin büyük hayvan evcilleştirmesini yasaklaması",
            "E) Sığırların Neolitik dönemde Anadolu'ya ulaşmaması"
        ],
        cevap: "B) Küçük sürü yönetiminin kolaylığı ve bu hayvanların çok yönlü ürün sunması",
        aciklama: "Doğru cevap B’dir. Metin iki temel neden sunmaktadır: küçük sürülerin yönetimi daha kolaydır ve keçi-koyun kısa sürede et, süt ve yün gibi birden fazla ürün sağlamaktadır. Bu pratik çok yönlülük, erken çiftçiler için en rasyonel tercihi oluşturmuştur."
    },
    {
        soru: "<i>\"İngiliz arkeolog Kathleen Kenyon, Eriha (Jericho) kazılarında MÖ 8000'e tarihlendirilen bir kuleden oluşan sur sistemini ortaya çıkardı. Bu yapı dünyada bilinen en eski anıtsal mimari örneklerinden biridir. Kenyon, bu savunma yapısının inşa edilebilmesi için toplulukta emek koordinasyonunun ve artı ürünün var olması gerektiğini öne sürdü.\" (Kaynak: Kathleen Kenyon, Archaeology in the Holy Land, 1960, s. 41 – uyarlanmıştır)</i><br><br><b>Kenyon’ın yorumuna göre Eriha’daki bu anıtsal yapı, Neolitik topluluklar hakkında ne söylemektedir?</b>",
        secenekler: [
            "A) Eriha sakinleri tamamen barışçıl bir toplumdu ve sura hiç ihtiyaç duymadı",
            "B) Anıtsal yapı inşası, artı ürün birikimi ve örgütlü emek koordinasyonunun var olduğuna işaret etmektedir",
            "C) Kule yalnızca dini amaçlarla inşa edilmiştir ve savunmayla ilgisi yoktur",
            "D) Eriha, tarımsız bir toplumda büyük yapılar inşa edilebileceğini kanıtlamaktadır",
            "E) Savunma duvarı tarımın Eriha'da hiçbir zaman yapılmadığını göstermektedir"
        ],
        cevap: "B) Anıtsal yapı inşası, artı ürün birikimi ve örgütlü emek koordinasyonunun var olduğuna işaret etmektedir",
        aciklama: "Doğru cevap B’dir. Kenyon, anıtsal yapının inşasının iki ön koşulu gerektirdiğini vurgular: artı ürün (inşaat süresince işçileri besleyecek kaynak) ve koordinasyon kapasitesi. Bu, Eriha’da tarıma dayalı artı ürünün ve toplumsal örgütlenmenin var olduğunu göstermektedir."
    },
    {
        soru: "<i>\"Mezopotamya'nın büyük şehirlerinde, MÖ 3. binyılda tapınak görevlileri için hazırlanan \"sefer listesi\" tabletleri bulunmuştur. Bu listelerde her görevlinin ne kadar arpa, yağ ve bira alacağı yazılmıştır. Aylık tahsisatlar kişinin tapınaktaki statüsüne ve işine göre değişmektedir: Baş rahip en fazlasını, sıradan işçi en azını almaktaydı.\" (Kaynak: Johannes Renger, Institutional, Communal and Individual Ownership, Chicago-Kent Law Review, 1995 – uyarlanmıştır)</i><br><br><b>Bu tabletler, Mezopotamya tapınak ekonomisinde tahılın işlevi hakkında ne ortaya koymaktadır?</b>",
        secenekler: [
            "A) Tapınak tahılı yalnızca tanrılara sunmak için depoluyordu",
            "B) Tahıl, statüye dayalı hiyerarşik bir ücret ve tahsisat sistemi aracılığıyla kurumsal iktidarı pekiştiren bir para işlevi görüyordu",
            "C) Tüm tapınak görevlileri eşit miktarda tahıl alıyordu",
            "D) Tahıl tahsisatları rastgele dağıtılıyor, hiyerarşiyle ilişkisi yoktu",
            "E) Tapınaklar tahılı satın almak yerine üretmek zorundaydı"
        ],
        cevap: "B) Tahıl, statüye dayalı hiyerarşik bir ücret ve tahsisat sistemi aracılığıyla kurumsal iktidarı pekiştiren bir para işlevi görüyordu",
        aciklama: "Doğru cevap B’dir. Tahsisatların statüye göre değişmesi (baş rahibin en fazlayı, işçinin en azını alması), tahılın bir tür hiyerarşik ücret sistemi işlevi gördüğünü ortaya koymaktadır. Tahıl burada hem ödeme aracı hem de toplumsal konumu simgeleyen bir araçtır."
    },
    {
        soru: "<i>\"Nobel ödüllü ekonomist Amartya Sen, Poverty and Famines (1981) adlı eserinde kıtlıkların çoğunun gıda yokluğundan değil, gıdaya erişim hakkındaki eşitsizlikten kaynaklandığını ortaya koydu. Erken tarım toplumlarına bu çerçeveden bakıldığında, artı ürünün var olduğu ama dağıtımın eşitsiz olduğu dönemlerde bazı grupların açlıkla yüz yüze geldiği görülmektedir.\" (Kaynak: Amartya Sen, Poverty and Famines, 1981, s. 7 – tarih bağlamına uyarlanmıştır)</i><br><br><b>Sen’in çerçevesi, erken tarım toplumlarındaki açlık olgusunu nasıl yeniden yorumlatmaktadır?</b>",
        secenekler: [
            "A) Erken tarım toplumlarında açlık yalnızca kuraklık ve kötü hasattan kaynaklanmaktadır",
            "B) Artı ürünün varlığına rağmen dağıtım eşitsizliği, tarım toplumlarında açlığın siyasi ve sosyal bir sorun olduğunu göstermektedir",
            "C) Sen'in tezi yalnızca modern dönem için geçerlidir; Eski Çağ kıtlıklarını açıklayamaz",
            "D) Erken tarım toplumlarında tahıl dağıtımı her zaman adil biçimde yapılmıştır",
            "E) Kıtlık sorununun çözümü yalnızca üretimi artırmaktan geçmektedir"
        ],
        cevap: "B) Artı ürünün varlığına rağmen dağıtım eşitsizliği, tarım toplumlarında açlığın siyasi ve sosyal bir sorun olduğunu göstermektedir",
        aciklama: "Doğru cevap B’dir. Sen’in 'erişim hakkı' çerçevesi, üretimin var olduğu ama dağıtımın eşitsiz olduğu durumlarda açlığın siyasi bir sorun olduğunu göstermektedir. Bu, Eski Çağ tarım toplumlarına uygulandığında ambar sahipleri ile tarım işçileri arasındaki eşitsizliği analiz etmemizi sağlayan güçlü bir araçtır."
    },
    {
        soru: "<i>\"Eski Ahit'te Tekvin/Yaratılış kitabında Yusuf'un hikâyesi şöyle geçer: Firavun yedi yıl bolluk ve yedi yıl kıtlık rüyası gördü. Yusuf bu rüyayı yorumlayarak bolluk yıllarında tahılın depolanmasını, kıtlık yıllarında ise dağıtılmasını önerdi. Firavun, Yusuf'u tüm Mısır'ın tahıl yöneticisi olarak atadı.\" (Kaynak: Yaratılış 41:29-41, Eski Ahit – uyarlanmıştır)</i><br><br><b>Bu hikâye, erken devletlerde tahıl yönetiminin siyasi iktidarla ilişkisi açısından nasıl yorumlanabilir?</b>",
        secenekler: [
            "A) Hikâye, Yusuf'un tarımsal bilgisinin siyasi bir güç kaynağına dönüştüğünü sembolik olarak ifade etmektedir",
            "B) Firavun, tahıl yönetimini yalnızca dini nedenlerle Yusuf'a bırakmıştır",
            "C) Bu hikâye tarihsel gerçeği değil yalnızca ahlaki bir mesajı aktarmaktadır, tarih analizi için kullanılamaz",
            "D) Mısır'da tahıl yönetimi hiçbir zaman devletin elinde olmamıştır",
            "E) Tahıl depolama ve dağıtım planı, kıtlığın hiçbir zaman yaşanmadığını kanıtlamaktadır"
        ],
        cevap: "A) Hikâye, Yusuf'un tarımsal bilgisinin siyasi bir güç kaynağına dönüştüğünü sembolik olarak ifade etmektedir",
        aciklama: "Doğru cevap A’dır. Yusuf’un rüya yorumu ve tahıl yönetimi planı onu Mısır’ın en güçlü ikinci ismine dönüştürmüştür. Bu, tarımsal kaynakları planlama ve yönetme bilgisinin doğrudan siyasi iktidar biçimine dönüştüğünü sembolik olarak ifade etmektedir. Kutsal metinleri tarihsel çerçevede okumak, o dönemin toplumsal değerlerini anlamak için meşru bir yoldur."
    },
    {
        soru: "<i>\"Çin'de Han hanedanı döneminde \"çiftçi-asker\" (tuntian) sistemi uygulandı. Sınır bölgelerine yerleştirilen askerler savaş olmadığında tarla işliyordu. Bu sistemde her asker, işlediği arazinin bir bölümünden devlete vergi öderken geri kalanından geçimini sağlıyordu. Araştırmacılar bu sistemi \"tarımsal güç\" ile \"askeri güç\" arasındaki organik bağın en açık örneği olarak değerlendirmektedir.\" (Kaynak: Michael Loewe, Everyday Life in Early Imperial China, 1968, s. 72 – uyarlanmıştır)</i><br><br><b>Tuntian sistemi, tarım ile devlet gücü arasındaki ilişki hakkında ne söylemektedir?</b>",
        secenekler: [
            "A) Han hanedanı tarımı ve askeri gücü birbirinden kesinlikle ayrı tutmuştur",
            "B) Tarımsal üretim ve askeri güç, tek bir sistemde birleştirilerek devletin sınır güvenliği ile ekonomik sürekliliği aynı anda sağlanmıştır",
            "C) Tuntian sistemi yalnızca iç bölgelerde uygulanmıştır",
            "D) Askerler tarım yerine zanaat üretimini tercih etmiştir",
            "E) Bu sistem, devlet gelirlerini düşüren bir uygulama olarak kısa sürede terk edilmiştir"
        ],
        cevap: "B) Tarımsal üretim ve askeri güç, tek bir sistemde birleştirilerek devletin sınır güvenliği ile ekonomik sürekliliği aynı anda sağlanmıştır",
        aciklama: "Doğru cevap B’dir. Tuntian sistemi, aynı kişiyi hem çiftçi hem asker olarak konumlandırarak devletin tarımsal ve askeri güçlerini tek bir yapıda birleştirmiştir. Bu, tarım üretiminin devlet kapasitesiyle ne kadar iç içe geçebildiğinin somut bir örneğidir."
    },
    {
        soru: "<i>\"Kuzey Afrika'nın Sahara bölgesinde MÖ 5000-3000 yıllarına tarihlenen kaya resimleri, bugün çöl olan alanlarda sığır sürülerini ve çobanları göstermektedir. Paleoklimatologlar bu dönemde Sahara'nın yeşil ve sulak olduğunu saptamıştır. MÖ 3000'den sonra iklimin kuraklığa dönmesiyle, bölge halkı ya güneye ya da Nil vadisine göç etmek zorunda kaldı.\" (Kaynak: Nick Drake & Charlie Bristow, Shorelines in the Sahara, Geographical Journal, 2006 – uyarlanmıştır)</i><br><br><b>Bu veriler, Nil medeniyetinin ortaya çıkışını iklim tarihi açısından nasıl açıklamamıza yardımcı olur?</b>",
        secenekler: [
            "A) Nil medeniyeti, Sahara kuraklığından kaçan göçmenlerin katkısı olmadan tamamen bağımsız gelişmiştir",
            "B) Nil vadisine akın eden Sahara göçmenlerinin tarımsal bilgi ve deneyimi, Nil medeniyetinin oluşmasını hızlandıran etkenlerden biri olmuş olabilir",
            "C) Sahara kuraklığı tarımı imkânsız kılmış ve tüm Kuzey Afrika nüfusunu silmiştir",
            "D) Sahara'nın yeşil dönemi, Mısır'ın tarih öncesinde ticaret yollarını kontrol ettiğini kanıtlamaktadır",
            "E) İklim değişikliği, tarımın Nil'de başlamasını engellemiştir"
        ],
        cevap: "B) Nil vadisine akın eden Sahara göçmenlerinin tarımsal bilgi ve deneyimi, Nil medeniyetinin oluşmasını hızlandıran etkenlerden biri olmuş olabilir",
        aciklama: "Doğru cevap B’dir. Kuraklıkla birlikte Nil’e göç eden Sahara halkları, zaten hayvancılık ve tarımsal bilgiye sahipti. Bu nüfus akışı, Nil vadisinde tarımsal bilgi ve emek birikimini artırmış olabilir. Bu yorum, iklim tarihi ile uygarlık gelişimi arasında nedensellik ilişkisi kurma becerisini gerektirmektedir."
    },
    {
        soru: "<i>\"Eski Çağ felsefecisi Platon, Devlet adlı eserinde ideal şehrin ekonomisini anlatırken şöyle der: Önce buğday ekeni, ardından demirciyi, terziye, kunduraçıya ihtiyaç duyarız. Her kent bir çiftçiyle başlar; çiftçi olmadan ne zanaatkar beslenir ne de savaşan donanır.\" (Kaynak: Platon, Devlet (Politeia), Kitap II, MÖ 4. yüzyıl – uyarlanmıştır)</i><br><br><b>Platon’un bu pasajı, tarımın Antik Yunan’daki toplumsal örgütlenme anlayışındaki yerine dair ne söylemektedir?</b>",
        secenekler: [
            "A) Platon tarımı gereksiz bir uğraş olarak reddetmiştir",
            "B) Tarım, toplumun tüm diğer faaliyetlerini mümkün kılan temel ve vazgeçilmez ekonomik faaliyettir",
            "C) Antik Yunan'da zanaatkârlar çiftçilerden daha temel bir sınıf oluşturuyordu",
            "D) Platon, savaşanların üretimle ilgilenmemesi gerektiğini savunmaktadır",
            "E) İdeal kentte tarım devlet tekeline alınmalıydı"
        ],
        cevap: "B) Tarım, toplumun tüm diğer faaliyetlerini mümkün kılan temel ve vazgeçilmez ekonomik faaliyettir",
        aciklama: "Doğru cevap B’dir. Platon 'her kent bir çiftçiyle başlar' diyerek tarımı toplumsal örgütlenmenin zorunlu temeli olarak konumlandırmaktadır. Çiftçi olmadan ne zanaatkâr beslenebilir ne de savaşan donanabilir; bu, tarımın diğer tüm faaliyetlerin altyapısını oluşturduğunu açıkça ortaya koymaktadır."
    },
    {
        soru: "<i>\"Orta Asya'da MÖ 3000-2000 yılları arasında Yamna ve Afanasievo kültürleri, tahıl tarımı yerine pastoral göçebe ekonomisine dayanan topluluklar kurdu. Bu topluluklar at, sığır ve koyun sürülerini mevsimlik olarak göç ettirerek büyük alanlarda yaşayabildi; ancak büyük kentler ve yazılı bürokratik yapılar oluşturamadı. Arkeologlar bu durumu, yerleşik tarımın kentleşme için zorunlu ön koşul olduğunun kanıtı olarak yorumlamaktadır.\" (Kaynak: David Anthony, The Horse, the Wheel and Language, 2007, s. 219 – uyarlanmıştır)</i><br><br><b>Bu veriler, tarımla kentleşme arasındaki ilişkiye dair ne tür bir çıkarım yapmayı mümkün kılar?</b>",
        secenekler: [
            "A) Göçebe topluluklarda büyük kentlerin oluşması için yalnızca zaman gerekmekteydi",
            "B) Yazılı bürokrasi ve kalıcı kentleşme, yerleşik tarımsal artı üretim olmadan gelişememektedir",
            "C) Tahıl tarımı yapmayan topluluklar hiçbir zaman karmaşık toplumsal yapılar kuramaz",
            "D) At ve sığır yetiştiriciliği, tahıl tarımı kadar büyük nüfusları besleyebilmektedir",
            "E) Kentleşme yalnızca ticaret değil hayvancılıkla da mümkündür"
        ],
        cevap: "B) Yazılı bürokrasi ve kalıcı kentleşme, yerleşik tarımsal artı üretim olmadan gelişememektedir",
        aciklama: "Doğru cevap B’dir. Pastoral göçebe ekonomisinin büyük kentler ve yazılı bürokrasi üretememesi, bu yapıların yerleşik tarımsal artı üretime dayandığını güçlü biçimde desteklemektedir. Ancak bu sonuç, pastoral toplumların 'daha az gelişmiş' olduğu anlamına gelmez; farklı koşullara uygun farklı bir toplumsal model kurdukları anlamına gelir."
    },
    {
        soru: "<i>\"Tarihçi Michael Coe, Maya uygarlığını incelerken şunu saptar: Mayalar, mısır tarımını yalnızca bir besin kaynağı olarak değil, kozmolojik bir merkez olarak gördü. Maya yaratılış mitosu Popol Vuh'ta insanlar mısır hamurundan yaratılmıştır. Mısır tanrısı Hunab Ku, yaşamın kaynağı sayıldı. Tarım takvimi ile dini takvim tam olarak örtüşüyordu.\" (Kaynak: Michael Coe, The Maya, 8. baskı, 2011, s. 156 – uyarlanmıştır)</i><br><br><b>Bu örnekten hareketle, tahıl tarımı ile uygarlık kimliği arasında nasıl bir ilişki kurulabilir?</b>",
        secenekler: [
            "A) Maya uygarlığı mısırı tamamen ekonomik bir ürün olarak değerlendirmiştir",
            "B) Temel tarım ürünü, bir toplumun kozmolojisine ve kimlik anlatısına işleyerek o uygarlığın özüne dönüşebilir",
            "C) Maya yaratılış mitosunun tarımla bağlantısı bir tesadüftür",
            "D) Tarım takvimi ile dini takvimin örtüşmesi, tarımın dini törenlere zarar verdiğini göstermektedir",
            "E) Mısır tarımı Maya uygarlığında yalnızca seçkin sınıflar tarafından biliniyordu"
        ],
        cevap: "B) Temel tarım ürünü, bir toplumun kozmolojisine ve kimlik anlatısına işleyerek o uygarlığın özüne dönüşebilir",
        aciklama: "Doğru cevap B’dir. Mısırın insan yaratılışının hammaddesi olması, tarım tanrısının kozmolojinin merkezine yerleşmesi ve tarım takvimiyle dini takvimin örtüşmesi, temel tarım ürününün o toplumun kimlik anlatısına ve dünya görüşüne nasıl sindiğini göstermektedir. Bu örüntü pek çok antik uygarlıkta tekrarlanmaktadır."
    },
    {
        soru: "<i>\"Arkeolog Anna Belfer-Cohen, Natuf kültürü (MÖ 12.500-10.200) yerleşimlerini incelerken ilginç bir geçiş dönemini belgeledi: Bu topluluklar yabani tahılları yoğun biçimde topluyordu ama henüz ekmiyordu. Yabani tahılların bulunduğu alanlara mevsimlik değil kalıcı köyler kurdular. Araştırmacılar bu aşamayı \"tarım öncesi yerleşim\" ya da \"yoğunlaştırılmış toplayıcılık\" olarak adlandırmaktadır.\" (Kaynak: Anna Belfer-Cohen & Ofer Bar-Yosef, Early Sedentism in the Near East, 2000 – uyarlanmıştır)</i><br><br><b>Natuf kültürünün bu ara evresi, 'göçebelik → tarım' geçişi hakkında hangi yeniden değerlendirmeyi zorunlu kılar?</b>",
        secenekler: [
            "A) Göçebelikten tarıma geçiş, ani bir 'aydınlanma anı' değil birden fazla ara aşamayı kapsayan uzun bir süreçtir",
            "B) Natuf kültürü hem göçebe hem tarımcıydı; bu nedenle geçiş modeli tamamen yanlıştır",
            "C) Yabani tahıl toplayıcılığı, kültüre almayla tamamen aynı sonuçları üretmektedir",
            "D) Kalıcı köy, ancak tarım başladıktan sonra mümkün olabilmektedir",
            "E) Natuf kültürü kanıtları, göçebelik ile tarım arasında bir ilişki olmadığını göstermektedir"
        ],
        cevap: "A) Göçebelikten tarıma geçiş, ani bir 'aydınlanma anı' değil birden fazla ara aşamayı kapsayan uzun bir süreçtir",
        aciklama: "Doğru cevap A’dır. Natuf kültürü, toplayıcılıkla ekim arasında yoğunlaştırılmış toplayıcılık adı verilen bir ara evreyi belgeler. Bu, göçebelikten tarıma geçişin basit ve ani bir kırılma olmadığını, farklı ara adaptasyonları kapsayan uzun ve karmaşık bir süreç olduğunu göstermektedir."
    },
    {
        soru: "<i>\"Hintli tarihçi Romila Thapar, Eski Hint toplumlarını incelerken Hindistan'da tarımın yalnızca ekonomik değil aynı zamanda kastla ilgili bir anlam taşıdığını vurgular: Toprağı işleyen Shudra kastı, tahılı vergiye dönüştüren Kshatriya ve bilgiyi tapınağa taşıyan Brahmin kastı birlikte işliyordu. Tarımsal artı ürün, kast hiyerarşisinin her katmanını beslerken onu aynı zamanda yeniden üretiyordu.\" (Kaynak: Romila Thapar, Early India: From the Origins to AD 1300, 2002, s. 63 – uyarlanmıştır)</i><br><br><b>Thapar’ın bu analizi, tarımsal artı ürünün toplumsal hiyerarşiyle ilişkisi açısından ne söylemektedir?</b>",
        secenekler: [
            "A) Hindistan'da kast sistemi tarımdan tamamen bağımsız olarak gelişmiştir",
            "B) Tarımsal artı ürün, toplumsal hiyerarşiyi yalnızca beslemekle kalmaz, her katmanı bu sisteme işlevsel biçimde entegre ederek hiyerarşiyi yeniden üretir",
            "C) Tarımsal üretim, kast sistemini ortadan kaldıracak bir eşitlikçi yapı doğurmuştur",
            "D) Shudra kastı tarım yapmak yerine zanaatkârlığı tercih etmiştir",
            "E) Thapar'ın analizi yalnızca modern Hindistan için geçerlidir"
        ],
        cevap: "B) Tarımsal artı ürün, toplumsal hiyerarşiyi yalnızca beslemekle kalmaz, her katmanı bu sisteme işlevsel biçimde entegre ederek hiyerarşiyi yeniden üretir",
        aciklama: "Doğru cevap B’dir. Thapar, tarımsal artı ürünün yalnızca zenginlik üretmediğini, aynı zamanda her kastın bu sisteme farklı bir işlevle dahil edilmesiyle (üretici Shudra, vergi toplayan Kshatriya, bilgiyi yöneten Brahmin) toplumsal hiyerarşinin sürdürüldüğünü ortaya koymaktadır. Bu, tarımın sosyal yeniden üretim aracı olarak işlemesini kavramak için analitik beceri gerektirir."
    },
    {
        soru: "<i>\"Orta Çağ Arap coğrafyacısı İbn Haldun, Mukaddime'de şöyle yazar: Bedevilerin gücü üremde (şehir) yaşayan insanlardan daha büyüktür; zira bedevi çalışmak ve yokluğa katlanmakla yoğrulmuştur. Ama uygarlık, tarıma dayalı yerleşik hayattan doğar; çünkü ancak artık üretim lüksü, bilimi, sanatı ve kalabalık nüfusu besleyebilir.\" (Kaynak: İbn Haldun, Mukaddime, 14. yüzyıl – uyarlanmıştır)</i><br><br><b>İbn Haldun’un bu yorumu, uygarlık oluşumu sürecinde tarımın rolüne dair nasıl bir model sunmaktadır?</b>",
        secenekler: [
            "A) İbn Haldun'a göre göçebeler yerleşiklerden her zaman daha güçlü bir uygarlık kurabilir",
            "B) Tarımsal artı üretim, bilim, sanat ve büyük nüfusun gelişmesini mümkün kılan zorunlu temeli oluşturmaktadır; uygarlık bu temelin üzerine inşa edilmektedir",
            "C) İbn Haldun göçebelerin uygarlık kuramayacağını savunmaktadır",
            "D) Yerleşik tarım toplumları bedevi topluluklara kıyasla askeri bakımdan daha güçlüdür",
            "E) Lüks ve sanat üretimi, tarımdan önce göçebe topluluklarda başlamıştır"
        ],
        cevap: "B) Tarımsal artı üretim, bilim, sanat ve büyük nüfusun gelişmesini mümkün kılan zorunlu temeli oluşturmaktadır; uygarlık bu temelin üzerine inşa edilmektedir",
        aciklama: "Doğru cevap B’dir. İbn Haldun, göçebe gücünü kabul etmekle birlikte uygarlığın tarımsal artı üretime dayandığını net biçimde ifade etmektedir: 'Ancak artık üretim lüksü, bilimi, sanatı ve kalabalık nüfusu besleyebilir.' Bu, tarım artığı ile uygarlık kapasitesi arasında doğrudan bir bağ kuran klasik bir argümandır."
    },
    {
        soru: "<i>\"Anadolu Selçuklu coğrafyacısı Kaşgarlı Mahmud, 11. yüzyılda kaleme aldığı Divan-ı Lügati't-Türk'te Türklerin eski dönemlerine ait tarımsal sözcükleri derledi. \"Tarla\", \"ekin\", \"orak\", \"değirmen\" gibi sözcüklerin eski Türkçede de var olduğu görülmektedir. Dilbilimciler bu sözcük varlığını, Türklerin göçebeliğe geçmeden önce tarımla tanışmış olduğuna dair dilsel kanıt saymaktadır.\" (Kaynak: Kaşgarlı Mahmud, Divan-ı Lügati't-Türk, 1072; Talat Tekin, Tarihsel Türk Lehçeleri, 1987 – uyarlanmıştır)</i><br><br><b>Bu dilsel bulgu, tarihsel araştırma yöntemi açısından nasıl bir örnek oluşturmaktadır?</b>",
        secenekler: [
            "A) Kaşgarlı Mahmud'un sözlüğü tarih araştırmasında güvenilir bir kaynak değildir",
            "B) Dil kalıntıları (sözcükler), yazılı tarihin ulaşamadığı dönemlere dair toplumsal ve ekonomik pratikler hakkında kanıt sunabilir",
            "C) Bu sözcüklerin varlığı Türklerin hiçbir zaman göçebe olmadığını kanıtlamaktadır",
            "D) Dilbilimsel yöntem, tarihsel bilgi üretmek için arkeolojik yöntemin önüne geçmektedir",
            "E) Tarla ve orak sözcükleri Arapçadan ödünç alınmıştır; Türk tarımıyla ilgisi yoktur"
        ],
        cevap: "B) Dil kalıntıları (sözcükler), yazılı tarihin ulaşamadığı dönemlere dair toplumsal ve ekonomik pratikler hakkında kanıt sunabilir",
        aciklama: "Doğru cevap B’dir. Eski Türkçede tarımsal sözcüklerin varlığı, yazılı kaynak bulunmayan dönemlere dair bilgi sunmaktadır: Bu topluluklar bir dönemde tarımla tanışmıştı. Bu, dilsel kanıtın tarihsel araştırmada nasıl kullanılabileceğini gösteren metodolojik açıdan ilginç bir örnektir."
    },
    {
        soru: "<i>\"Marksist tarih yazımında Friedrich Engels, Ailenin, Özel Mülkiyetin ve Devletin Kökeni (1884) adlı eserinde tarımın toplumsal eşitsizliği nasıl ürettiğini açıklar: Tarım öncesinde herkes eşit tüketti; artık ürün ortaya çıkınca bazıları onu biriktirdi. Özel mülkiyet bu birikimiyle başladı; mülkiyet, aileyi, aile devleti doğurdu.\" (Kaynak: Friedrich Engels, Ailenin, Özel Mülkiyetin ve Devletin Kökeni, 1884 – uyarlanmıştır)</i><br><br><b>Engels’in bu nedensellik zincirini arkeolojik kanıtlarla karşılaştırdığımızda hangi değerlendirme yapılabilir?</b>",
        secenekler: [
            "A) Engels'in her adımı arkeolojik kanıtlarla doğrudan doğrulanmıştır",
            "B) Engels'in zinciri (artı ürün → özel mülk → aile → devlet) bazı arkeolojik verilerle örtüşmekle birlikte, tüm tarım toplumlarında aynı zincirin işlediğini kanıtlayacak evrensel kanıt bulunmamaktadır",
            "C) Tarım öncesi topluluklarda eşit tüketim olduğunu gösteren arkeolojik kanıtlar çoktur",
            "D) Özel mülkiyet, tarımdan önce avcı-toplayıcı topluluklarda ortaya çıkmıştır",
            "E) Engels'in çerçevesi ekonomik tarihi anlayışlı biçimde çözmekte; arkeolojik kanıtlar ise gereksizdir"
        ],
        cevap: "B) Engels'in zinciri (artı ürün → özel mülk → aile → devlet) bazı arkeolojik verilerle örtüşmekle birlikte, tüm tarım toplumlarında aynı zincirin işlediğini kanıtlayacak evrensel kanıt bulunmamaktadır",
        aciklama: "Doğru cevap B’dir. Engels’in artı ürün → özel mülk → aile → devlet zinciri, tarım sonrası ortaya çıkan eşitsizliği açıklamada teorik bir çerçeve sunmaktadır. Ancak Çatalhöyük gibi arkeolojik örnekler bu sürecin her yerde aynı şekilde işlemediğini göstermektedir. Teorik çerçeveyi arkeolojik kanıtlarla karşılaştırmak metodolojik bir beceri gerektirir."
    },
    {
        soru: "<i>\"Roma döneminde Plinius Yaşlı, Naturalis Historia adlı ansiklopedisinde şöyle yazar: Tahıl yalnızca ekmek değil, güç demektir. Roma hangi kıtadan ne kadar tahıl getirebilirse, o kıtayı yönetebilir. Mısır Roma'nın ambarıdır; Mısır'ı kaybetmek Roma'yı aç bırakmaktır.\" (Kaynak: Plinius Yaşlı, Naturalis Historia, MS 77 – uyarlanmıştır)</i><br><br><b>Plinius’un bu ifadesi, tarımsal üretimin jeopolitikle ilişkisi hakkında nasıl bir bakış açısı sunmaktadır?</b>",
        secenekler: [
            "A) Roma, Mısır tahılını yalnızca savunma amaçlı depoluyordu",
            "B) Tarımsal kaynaklara hâkimiyet, imparatorluk gücünün temel bileşenlerinden birini oluşturmaktadır; tahıl arzı siyasi bir araç olarak işlev görmektedir",
            "C) Plinius'a göre tahıl değil metal kaynakları Roma'nın gücünü belirlemiştir",
            "D) Mısır, Roma için yalnızca kültürel değer taşıyan bir eyalet olarak görülmüştür",
            "E) Roma Mısır'dan tahıl ithal etmemiş, tersine Mısır'a tahıl ihraç etmiştir"
        ],
        cevap: "B) Tarımsal kaynaklara hâkimiyet, imparatorluk gücünün temel bileşenlerinden birini oluşturmaktadır; tahıl arzı siyasi bir araç olarak işlev görmektedir",
        aciklama: "Doğru cevap B’dir. 'Mısır’ı kaybetmek Roma’yı aç bırakmaktır' ifadesi, tahıl arzının bir güç aracı olduğunu açıkça ortaya koymaktadır. Bu, tarımsal üretimin jeopolitik hesapların merkezine oturduğunu; hangi bölgenin tahıl ürettiğini kontrol etmenin imparatorluk gücünü doğrudan etkilediğini göstermektedir."
    },
    {
        soru: "<i>\"Çevre tarihçisi J. Donald Hughes, Antik Dünyada Çevre Sorunları (1994) adlı eserinde Mezopotamya'da sulama tarımının toprak verimliliği üzerindeki uzun vadeli etkilerini inceler: Sulama suyunun tuz bırakması, yüzyıllar içinde toprak tuzlanmasına yol açtı; MÖ 2000'lere gelindiğinde eskiden verimli olan bazı Sümer tarlaları büyük ölçüde verimsizleşmişti. Bu süreç, bazı tarihçilerce Sümer şehirlerinin çöküşüne katkıda bulunan faktörler arasında sayılmaktadır.\" (Kaynak: J. Donald Hughes, Pan's Travail: Environmental Problems of the Ancient Greeks and Romans, 1994 – uyarlanmıştır)</i><br><br><b>Bu çevre tarihi bulgusu, Eski Çağ medeniyetlerinin çöküşünü açıklamak açısından nasıl kullanılabilir?</b>",
        secenekler: [
            "A) Mezopotamya'nın çöküşü yalnızca işgallerle açıklanabilir; toprak sorunları ikincil derecede önemsizdir",
            "B) Uzun vadeli tarımsal sürdürülemezlik (toprak tuzlanması), uygarlık çöküşünde siyasi ve askeri faktörlere ek olarak çevresel bir boyut oluşturmaktadır",
            "C) Sümer şehirleri toprak bozulması nedeniyle değil nüfus patlaması nedeniyle çökmüştür",
            "D) Sulama tekniği MÖ 2000'lerde Sümer'de henüz uygulamaya konmamıştı",
            "E) Toprak tuzlanması yalnızca modern endüstriyel tarımda görülen bir sorundur"
        ],
        cevap: "B) Uzun vadeli tarımsal sürdürülemezlik (toprak tuzlanması), uygarlık çöküşünde siyasi ve askeri faktörlere ek olarak çevresel bir boyut oluşturmaktadır",
        aciklama: "Doğru cevap B’dir. Toprak tuzlanması, tarımsal üretimi azaltarak besin güvenliğini tehdit etmiştir. Bu çevresel baskı, Sümer şehirlerinin çöküşünde siyasi ve askeri nedenlerin yanı sıra çevresel bir boyut oluşturmaktadır. Çöküşü tek bir nedene bağlamak yerine çok değişkenli bir çerçeveye yerleştirmek daha açıklayıcıdır."
    },
    {
        soru: "<i>\"Arkeolog Ian Hodder, Çatalhöyük'te evlerin aynı konuma tekrar tekrar yeniden inşa edildiğini ve bu kalıbın yüzlerce yıl sürdüğünü saptadı. Bazı evler 8-12 kat inşa katmanı içermektedir. Hodder bu kalıbı \"yapı katılımı\" (building engagement) kavramıyla açıklar: Ev, atalar ve toprak arasındaki bağı koruyordu; bu bağ mülkten çok rituelden kaynaklanıyordu. Başka bir deyişle, yer bağlılığı ve mülkiyet kavramı, Çatalhöyük'te ekonomik değil ritüel bir içerik taşıyordu.\" (Kaynak: Ian Hodder, Entangled: An Archaeology of the Relationships between Humans and Things, 2012, s. 88 – uyarlanmıştır)</i><br><br><b>Hodder’ın 'yapı katılımı' kavramı, tarım toplumlarında mülkiyet ve yer bağlılığının kaynağı hakkındaki standart ekonomik açıklamaya nasıl bir alternatif sunmaktadır?</b>",
        secenekler: [
            "A) Hodder, Çatalhöyük'te özel mülkiyetin olmadığını ve dolayısıyla tarımın da yapılmadığını kanıtlamaktadır",
            "B) Standart açıklama yer bağlılığını tarımsal yatırıma (emek ve tohum) bağlarken, Hodder bunu ritüel ve ata bağlılığına dayandırmaktadır; bu iki model birbirini dışlayan değil tamamlayan mekanizmaları vurgulayabilir",
            "C) Hodder'ın bulguları, Çatalhöyük'ün ekonomik değil salt dini bir merkez olduğunu kanıtlamaktadır",
            "D) Ritüel bağlılık ve ekonomik bağlılık Çatalhöyük'te birbirinden tamamen bağımsız olgulardır",
            "E) Çatalhöyük'teki ev yeniden inşası, toplumun sürekli savaş hâlinde olduğunun kanıtıdır"
        ],
        cevap: "B) Standart açıklama yer bağlılığını tarımsal yatırıma (emek ve tohum) bağlarken, Hodder bunu ritüel ve ata bağlılığına dayandırmaktadır; bu iki model birbirini dışlayan değil tamamlayan mekanizmaları vurgulayabilir",
        aciklama: "Doğru cevap B’dir. Standart 'tarımsal yatırım → yer bağlılığı' açıklaması ekonomik mantığa yaslanır (tarlaya emeği verdim, terk edemem). Hodder ise yer bağlılığının Çatalhöyük’te ata ritüeli ve kimlik bağından kaynaklandığını öne sürmektedir. Bu iki mekanizma çelişmez; aynı anda farklı güçlerle işleyebilir. Bu soruyu yanıtlamak iki modelin ne söylediğini ve nasıl ilişkilendirilebileceğini birlikte değerlendirme becerisini gerektirmektedir."
    },
    {
        soru: "<i>\"Antropolog David Graeber, Borç: İlk 5000 Yıl (2011) adlı eserinde şunu öne sürer: İlk borç ilişkileri ticari değil tarımsal idi ve bu ilişkiler eşit taraflar arasında değil, tohumluğa muhtaç çiftçi ile tohum sağlayan tapınak ya da güçlü kişi arasında kuruluyordu. Faizin kendisi, tohumun çoğalma pratiğinden metafor olarak devşirildi: nasıl tohum çoğalırsa, borç da çoğalır.\" (Kaynak: David Graeber, Debt: The First 5000 Years, 2011, s. 64 – uyarlanmıştır)</i><br><br><b>Graeber’ın bu argümanı, faiz ve borç kurumlarının kökeni hakkında nasıl bir tarih yazımı önerisi içermektedir?</b>",
        secenekler: [
            "A) Faiz sistemi ticaret gemiciliğiyle birlikte Akdeniz'de ortaya çıkmıştır",
            "B) Faiz ve borç kurumları, tarımsal tohumun biyolojik çoğalma mantığından hem metafor hem de pratik olarak türeyen, tarımsal ekonominin özgün ürünleridir",
            "C) Graeber, borç ilişkilerinin her zaman eşit taraflar arasında kurulduğunu kanıtlamaktadır",
            "D) Tohumun çoğalma metaforu yalnızca sembolik düzeyde kalmış, gerçek borç pratiğini etkilememiştir",
            "E) Faiz, tarım toplumlarında devlet tarafından icat edilmiş ve zorla uygulanmıştır"
        ],
        cevap: "B) Faiz ve borç kurumları, tarımsal tohumun biyolojik çoğalma mantığından hem metafor hem de pratik olarak türeyen, tarımsal ekonominin özgün ürünleridir",
        aciklama: "Doğru cevap B’dir. Graeber, faizin hem kavramsal (tohumun çoğalma metaforu) hem de pratik (tohum borcunun geri ödenmesi) kökeninin tarımsal ekonomide yattığını savunmaktadır. Bu, finansal kurumları tarımsal pratiklerden türeyen yapılar olarak konumlandıran özgün bir tarih yazımı önerisidir. Bunu kavramak hem argümanın yapısını hem de tarihsel bağlamı anlamayı gerektirmektedir."
    },
    {
        soru: "<i>\"Nüfus ekolojisti Mark Cohen, The Food Crisis in Prehistory (1977) adlı eserinde şunu öne sürer: Tarıma geçiş, daha iyi bir yaşam için özgürce yapılmış bir tercih değildi. Artan nüfus yoğunluğu, avcı-toplayıcılığın yeterliliğini aşınca topluluklar daha düşük kaliteli besinlere (tahıl) yönelmek zorunda kaldı. Tarım, daha az tercih edilen ancak daha fazla insanı besleyebilen bir stratejidir.\" (Kaynak: Mark Nathan Cohen, The Food Crisis in Prehistory, 1977, s. 15 – uyarlanmıştır)</i><br><br><b>Cohen’ın hipotezi ile Harari ve Sahlins’in argümanları arasında nasıl bir sentez yapılabilir?</b>",
        secenekler: [
            "A) Üç görüş de tarımı özgür bir tercih olarak değerlendirmektedir",
            "B) Cohen nüfus baskısını, Sahlins avcı-toplayıcı refahını, Harari bireysel maliyet-fayda dengesini vurgular; bu üç perspektif birlikte ele alındığında tarıma geçişin zorunluluk, fırsat maliyeti ve kolektif rasyonalite boyutlarını içerdiği anlaşılır",
            "C) Sahlins ile Cohen birbiriyle tamamen uyumludur; Harari'nin görüşü ise çelişkilidir",
            "D) Bu üç akademisyen de aynı tarih metodolojisini paylaşmaktadır",
            "E) Tarıma geçiş yalnızca iklim faktörüyle açıklanabilir; nüfus ve refah argümanları gereksizdir"
        ],
        cevap: "B) Cohen nüfus baskısını, Sahlins avcı-toplayıcı refahını, Harari bireysel maliyet-fayda dengesini vurgular; bu üç perspektif birlikte ele alındığında tarıma geçişin zorunluluk, fırsat maliyeti ve kolektif rasyonalite boyutlarını içerdiği anlaşılır",
        aciklama: "Doğru cevap B’dir. Cohen nüfus baskısının tarımı zorunlu kıldığını, Sahlins avcı-toplayıcıların daha az çalışıp daha iyi yaşadığını (yani tarımın fırsat maliyeti olduğunu), Harari bireyin bu geçişten zarar gördüğünü ama kolektif nüfusun büyüdüğünü ortaya koyar. Bu üç çerçeveyi sentezlemek, geçişin hem zorunluluk hem de fırsat kaybı hem de kolektif-bireysel paradoks boyutlarını birlikte görmeyi sağlar. Üç ayrı akademisyenin argümanlarını sentezlemek ileri düzey analitik yetkinlik gerektirmektedir."
    },
    {
        soru: "<i>\"Tarih felsefecisi Walter Benjamin, Tarih Kavramı Üzerine Tezler (1940) adlı eserinde şöyle yazar: Her uygarlığın belgesi aynı zamanda barbarlığın bir belgesidir. Piramitleri ve zigguratları inşa eden uygarlıklar, bu yapıları tarımsal artı ürünü zorla toplayan ve işçileri sefalet içinde çalıştıran bir sistem sayesinde var etti.\" (Kaynak: Walter Benjamin, Tarih Kavramı Üzerine Tezler, 1940 – uyarlanmış çeviri)</i><br><br><b>Benjamin’in bu tezi, tarım medeniyetlerinin başarılarını nasıl yeniden çerçevelemektedir ve bu çerçevelemenin tarihçiler için önemi nedir?</b>",
        secenekler: [
            "A) Benjamin, tarımsal uygarlıkların hiçbir olumlu miras bırakmadığını savunmaktadır",
            "B) Benjamin, her uygarlığın başarısının altında sömürü ve zorunlu emek gibi karanlık bir tarihin yattığını hatırlatır; tarihçi için bu, yalnızca 'ne inşa edildi?' değil 'kim ve ne bedelle inşa etti?' sorusunu sormayı zorunlu kılar",
            "C) Piramit ve zigguratlar tamamen gönüllü emekle inşa edilmiş olduğundan Benjamin'in tezi temelsizdir",
            "D) Benjamin yalnızca mimari tarihi değil yalnızca siyaset tarihini eleştirmektedir",
            "E) Tarihçilerin görevi binaların yapılış koşullarını değil yalnızca mimari özelliklerini incelemektir"
        ],
        cevap: "B) Benjamin, her uygarlığın başarısının altında sömürü ve zorunlu emek gibi karanlık bir tarihin yattığını hatırlatır; tarihçi için bu, yalnızca 'ne inşa edildi?' değil 'kim ve ne bedelle inşa etti?' sorusunu sormayı zorunlu kılar",
        aciklama: "Doğru cevap B’dir. Benjamin, uygarlığın 'büyük yapıları' ile bu yapıların ardındaki sömürüyü birlikte görmeyi zorunlu kılmaktadır. Bu perspektif, tarihçileri salt 'başarı' ve 'ilerleme' anlatısından çıkararak 'bu başarı kimlerin emeğiyle ve hangi bedelle üretildi?' sorusunu merkeze almaya davet eder. Felsefi bir tarihin tarihçilik pratiğine nasıl uygulanacağını kavramak ileri düzey eleştirel düşünme gerektirmektedir."
    },
    {
        soru: "<i>\"Arkeoloji tarihçisi Matthew Johnson, Archaeological Theory: An Introduction (2010) adlı eserinde şunu saptar: 1960'lardan itibaren tarım kökenlerini araştıran arkeologlar, bulgu yorumlarında çevre determinizmi, nüfus determinizmi ve kültürel evrim gibi birbirinden farklı teorik çerçeveler kullandılar. Aynı arkeolojik bulgu, farklı teorik gözlüklerle okunduğunda farklı tarih anlatıları üretmektedir.\" (Kaynak: Matthew Johnson, Archaeological Theory: An Introduction, 2010, s. 148 – uyarlanmıştır)</i><br><br><b>Johnson’ın bu gözlemi, tarih bilgisinin üretimi hakkında hangi epistemolojik sonucu gündeme getirmektedir?</b>",
        secenekler: [
            "A) Arkeolojik bulgu yorumu nesneldir; teorik çerçeveler sonucu değiştirmez",
            "B) Tarihsel bilgi yalnızca bulgulardan değil, araştırmacının benimsediği teorik çerçeveden de şekillenir; bu nedenle bulgu ile yorum arasındaki fark tarih okuryazarlığının temel meselelerinden biridir",
            "C) Teorik çerçeveler, arkeolojik bulguların güvenilirliğini ortadan kaldırmaktadır",
            "D) Arkeoloji teoriden bağımsız olgusal bir bilimdir; teorik tartışmalar felsefecilere bırakılmalıdır",
            "E) Farklı teorik çerçeveler tarih araştırmasını imkânsız kıldığından tek bir evrensel yöntem benimsenmelidir"
        ],
        cevap: "B) Tarihsel bilgi yalnızca bulgulardan değil, araştırmacının benimsediği teorik çerçeveden de şekillenir; bu nedenle bulgu ile yorum arasındaki fark tarih okuryazarlığının temel meselelerinden biridir",
        aciklama: "Doğru cevap B’dir. Johnson, aynı bulgunun farklı teorik çerçevelerle okunduğunda farklı anlatılar ürettiğini göstermektedir. Bu, tarihsel bilginin nesnel bulgular ile öznel yorumlama çerçevesinin etkileşiminden doğduğunu ortaya koymaktadır. Bulgu ile yorum arasındaki ayrımı kavramak, tarihsel epistemoloji açısından temel bir yetkinliktir ve bu soruyu yanıtlamak ileri düzey eleştirel düşünme gerektirir."
    },
    {
        soru: "<i>\"Sosyal antropolog James Woodburn (1982), insan toplumlarını \"anlık getiri\" (immediate return) ve \"ertelenmiş getiri\" (delayed return) sistemleri olarak ikiye ayırdı. Anlık getiri toplulukları (avcı-toplayıcılar), bugün avlananı bugün tüketir ve biriktirmez. Ertelenmiş getiri toplulukları (çiftçiler), bugün emek verir; hasadı ileriki bir zamanda toplar. Woodburn'a göre ertelenmiş getiri sistemi, hem borcun hem de otoritenin ortaya çıkması için zorunlu koşulu oluşturur.\" (Kaynak: James Woodburn, Egalitarian Societies, Man, 1982 – uyarlanmıştır)</i><br><br><b>Woodburn’ın 'ertelenmiş getiri' kavramı, borç ve otorite ilişkilerinin tarihsel kökeni açısından nasıl yorumlanabilir ve bu yorumun sınırlılığı nedir?</b>",
        secenekler: [
            "A) Woodburn'ın modeli, tüm ertelenmiş getiri toplumlarının otoriter devletlere dönüştüğünü kanıtlamaktadır",
            "B) Ertelenmiş getiri, gelecekteki hasada bağımlılığı ve dolayısıyla borç ile otoriteye zemin hazırlayan koşulları yaratır; ancak bu koşulun otorite ve borca her zaman yol açıp açmadığı, başka değişkenlere bağlıdır ve model bu koşulluluğu tam olarak açıklayamaz",
            "C) Anlık getiri sistemleri de otoriteyi ve borcu üretebileceğinden Woodburn'ın ayrımı gereksizdir",
            "D) Tarımsal ertelenmiş getiri, toplumsal eşitliği artırmaktadır",
            "E) Woodburn'ın modeli yalnızca Afrika toplumları için geçerlidir"
        ],
        cevap: "B) Ertelenmiş getiri, gelecekteki hasada bağımlılığı ve dolayısıyla borç ile otoriteye zemin hazırlayan koşulları yaratır; ancak bu koşulun otorite ve borca her zaman yol açıp açmadığı, başka değişkenlere bağlıdır ve model bu koşulluluğu tam olarak açıklayamaz",
        aciklama: "Doğru cevap B’dir. Woodburn’ın modeli güçlüdür: Hasadı bekleyen çiftçi, tohumluğa ihtiyaç duyabilir ve bu bağımlılık hem borcu hem de bu borcu yöneten otorite yapılarını mümkün kılar. Ancak tüm ertelenmiş getiri toplumlarının otoriter devletlere dönüşmediği (örneğin Kuzey Amerika tarım toplulukları) modelin evrensel geçerliliğini sınırlamaktadır. Hem argümanın gücünü hem de sınırlılığını birlikte değerlendirmek bu soruyu zor kılmaktadır."
    },
    {
        soru: "<i>\"Tarih sosyolojisi alanından Michael Mann, The Sources of Social Power (1986) adlı eserinde dört iktidar kaynağını tanımlar: İdeolojik, ekonomik, askeri ve siyasi. Mann'a göre Mezopotamya ve Mısır gibi erken uygarlıklarda tarım, bu dört kaynağı birbiriyle bağlayan temel altyapıyı oluşturuyordu: Tahıl, tapınağı (ideoloji), devlet ambarını (ekonomi), orduyu (askeri) ve bürokrasiyi (siyasi) aynı anda besliyordu.\" (Kaynak: Michael Mann, The Sources of Social Power, Vol.1, 1986, s. 73 – uyarlanmıştır)</i><br><br><b>Mann’ın bu çerçevesini kullanarak Tarım Devrimi’nin Eski Çağ’a etkisinin en kapsamlı sentezi nasıl yapılabilir?</b>",
        secenekler: [
            "A) Mann'ın modeli yalnızca ekonomik iktikarı açıkladığından Tarım Devrimi'nin diğer etkileri için yetersiz kalır",
            "B) Tarım, Mann'ın dört iktidar kaynağını eş zamanlı olarak besleyerek bu güçlerin birbiriyle entegrasyonunu mümkün kıldı; bu çerçeve, Tarım Devrimi'nin yalnızca ekonomik değil ideolojik, askeri ve siyasi boyutlardaki etkilerini tek bir analitik modelde görmeyi sağlar",
            "C) Mann'ın modeli tarım öncesi toplumları kapsadığından Tarım Devrimi'ne uygulanamaz",
            "D) Dört iktidar kaynağı her zaman eşit güçte olduğundan tarımın öncelikli etkisi gösterilemez",
            "E) Mann'ın modeline göre ideolojik iktidar (tapınak), tarımdan bağımsız olarak en güçlü kaynaktır"
        ],
        cevap: "B) Tarım, Mann'ın dört iktidar kaynağını eş zamanlı olarak besleyerek bu güçlerin birbiriyle entegrasyonunu mümkün kıldı; bu çerçeve, Tarım Devrimi'nin yalnızca ekonomik değil ideolojik, askeri ve siyasi boyutlardaki etkilerini tek bir analitik modelde görmeyi sağlar",
        aciklama: "Doğru cevap B’dir. Mann’ın dört iktidar kaynağı (ideoloji, ekonomi, askeriye, siyaset) çerçevesi, Tarım Devrimi’nin bu dört boyutu aynı anda nasıl dönüştürdüğünü görmemizi sağlar: Tahıl tapınağı (ideoloji), devlet ambarını (ekonomi), orduyu (askeri), bürokrasiyi (siyasi) besliyordu. Bu sentez, öğrencilerin Tarım Devrimi’nin yalnızca besin üretimi değil, toplumsal iktidarın tüm biçimlerini şekillendiren çok boyutlu bir dönüşüm olduğunu kavramasını sağlar. En kapsamlı sentezi yapabilmek için hem Mann’ın modelini hem de tarihsel içeriği birlikte işlemek bu soruyu zor kılar."
    }
];

// --- 2. ÜNİTE: TARIM DEVRİMİNİN ESKİ ÇAĞ'A ETKİLERİ - TEST 6 ---
window.allTests["test_u2_tarim_6"] = [
    {
        soru: "<i>Jared Diamond, \"Tüfek, Mikrop ve Çelik\" (1997) adlı eserinde tarım toplumuna geçişi şu şekilde açıklar: \"Tarımcılığa geçiş, insanların daha iyi bir yaşam için bilinçli olarak verdikleri bir karar değildi. Aksine, nüfus baskısı ve iklim değişiklikleri insanları adım adım bu yola sürükledi. Avcı-toplayıcılar, günde ortalama dört saat çalışarak geçimlerini sağlarken, ilk çiftçiler çok daha uzun çalışma süreleriyle daha az çeşitli bir beslenme düzenine mahkûm oldular.\"</i><br><br><b>Bu metne göre, insanların tarıma geçmesini açıklamak için aşağıdaki yorumlardan hangisi en uygun sonucu çıkarmaktadır?</b>",
        secenekler: [
            "A) Tarımcılığa geçiş, insanların bilinçli ve planlı kararlarının bir sonucudur.",
            "B) Tarımcılığa geçiş, yaşam kalitesini doğrudan ve hızla artırmıştır.",
            "C) İnsan toplulukları, dış baskılar nedeniyle farkında olmadan tarıma yönelmiş olabilir.",
            "D) Avcı-toplayıcılar, çiftçilere göre daha çok çalışmak zorunda kalmıştır.",
            "E) İklim değişiklikleri, tarım toplumlarının ortaya çıkmasını tamamen engellemiştir."
        ],
        cevap: "C) İnsan toplulukları, dış baskılar nedeniyle farkında olmadan tarıma yönelmiş olabilir.",
        aciklama: "Doğru yanıt C'dir. Diamond'ın metninde tarıma geçişin \"bilinçli bir karar olmadığı\" ve \"nüfus baskısı ile iklim değişikliklerinin insanları sürüklediği\" vurgulanmaktadır. Bu durum, insanların dış koşullar karşısında farkında olmadan bu sürece dahil olduğuna işaret eder. A seçeneği metne doğrudan ters düşer; B seçeneği yanlıştır çünkü metin çiftçilerin daha az çeşitli beslenme ve daha uzun çalışma sürelerine mahkûm olduğunu söyler; D seçeneği tam tersidir (avcı-toplayıcılar daha az çalışıyordu); E seçeneği ise tarımın ortaya çıktığı gerçeğiyle çelişir."
    },
    {
        soru: "<i>Arkeolog Ian Hodder, Çatalhöyük kazılarına dair kaleme aldığı \"The Leopard's Tale\" (2006) adlı eserinde şunu aktarır: \"MÖ 7500–5700 yılları arasında faaliyet gösteren Çatalhöyük, kapısı olmayan evlerden oluşmaktaydı; insanlar çatıdaki deliklerden içeri girip çıkıyordu. Evler birbirine sıkıca yapışık inşa edilmiş, herhangi bir cadde ya da genel kamusal alan bırakılmamıştı. Ölüler ise doğrudan ev tabanlarının altına gömülüyordu.\"</i><br><br><b>Bu metinden yola çıkarak Çatalhöyük'teki yerleşik yaşam hakkında hangi çıkarım yapılabilir?</b>",
        secenekler: [
            "A) Çatalhöyük halkı, kamusal alanları gündelik hayatın merkezi olarak kullanmıştır.",
            "B) Ölü gömme geleneği, ata kültü ve aile bağlarının fiziksel mekânla iç içe geçtiğine işaret eder.",
            "C) Kapısız ev tasarımı, dışarıdan gelen tehlikelere karşı tamamen savunmasız bir toplumu yansıtır.",
            "D) Şehir planlaması, bu dönemde çok gelişmiş bir merkezi otorite varlığını kanıtlar.",
            "E) Çatalhöyük halkının tarımla herhangi bir ilgisi olmadığı anlaşılmaktadır."
        ],
        cevap: "B) Ölü gömme geleneği, ata kültü ve aile bağlarının fiziksel mekânla iç içe geçtiğine işaret eder.",
        aciklama: "Doğru yanıt B'dir. Ölülerin ev tabanlarına gömülmesi, ata kültü ve aile bağlarının fiziksel yaşam alanıyla birleştiğini gösterir; bu da yerleşik düzende dini ve sosyal ilişkilerin mekânla nasıl bütünleştiğini ortaya koyar. A seçeneği yanlıştır; çünkü metinde kamusal alan olmadığı belirtilmektedir. C seçeneği, çatı girişlerinin savunma amacıyla yapıldığı ihtimalini tek yönlü yorumlar; D'de ise bir merkezi otorite kanıtı yoktur. E seçeneği metnin kapsamı dışındadır."
    },
    {
        soru: "<i>Türk Tarih Kurumu'nun lise ders kitabında (2023) besin fazlası ve depolama şu şekilde ele alınmaktadır: \"Tarımla birlikte insanlar, yiyeceklerini mevsimlik olarak üretip yıl boyunca tüketebilmek için depolama yöntemleri geliştirdiler. Buğday ambarları ve küplerde saklanan tahıllar, topluluğun kışın ya da kıtlık döneminde hayatta kalmasını sağladı. Zamanla bu depoların yönetimi, belirli kişilerin elinde toplandı.\"</i><br><br><b>Metindeki bilgilere göre, besin fazlasının depolanmasının toplumsal yapıya yansıması hangi şekilde gerçekleşmiştir?</b>",
        secenekler: [
            "A) Depolama, topluluktaki her bireyin eşit kaynağa sahip olmasını kalıcı biçimde sağlamıştır.",
            "B) Depoların yönetiminin tek elde toplanması, toplumsal güç farklılıklarına zemin hazırlamıştır.",
            "C) Kış döneminde hayatta kalma sorununun çözülmesi, nüfusun hızla azalmasına neden olmuştur.",
            "D) Tahıl depoları, ticaretin tamamen ortadan kalkmasına yol açmıştır.",
            "E) Besin fazlası, topluluğun her dönem göçebe yaşamasını kolaylaştırmıştır."
        ],
        cevap: "B) Depoların yönetiminin tek elde toplanması, toplumsal güç farklılıklarına zemin hazırlamıştır.",
        aciklama: "Doğru yanıt B'dir. Metinde \"depoların yönetiminin belirli kişilerin elinde toplandığı\" açıkça ifade edilmektedir. Bu durum, kaynakların kontrolü aracılığıyla toplumsal hiyerarşinin ve güç farklılıklarının doğuşuna zemin hazırladığını gösterir. A seçeneği eşitlikçi bir sonucu ima eder ancak metin tam tersi bir eğilime dikkat çekmektedir. C'de nüfus azalması iddia edilmekte, bu da olgusal açıdan yanlıştır. D ve E seçenekleri metinle hiçbir ilişki kurmamaktadır."
    },
    {
        soru: "<i>Antropolog Marshall Sahlins, \"Stone Age Economics\" (1972) adlı yapıtında avcı-toplayıcı toplumları şu ifadelerle tanımlar: \"Avcı-toplayıcı topluluklar, doğanın sunduklarıyla yetindikleri için 'orijinal zengin toplumlar'dır; kıt kaynaklarla uzlaşmayı bildikleri için sınırsız ihtiyaç kavramından habersizdirler. Tarıma geçen toplumlar ise artık üretim zorunluluğuyla birlikte 'eksiklik' kavramını da icat etmişlerdir.\"</i><br><br><b>Sahlins'in bu değerlendirmesinden yola çıkarak tarıma geçişin insanın zihniyet dünyasına ne tür bir katkı yaptığı söylenebilir?</b>",
        secenekler: [
            "A) Tarım, insanın doğayla uyumlu ve ihtiyacı kadar tüketen bir anlayış geliştirmesini kalıcı kılmıştır.",
            "B) Tarım, 'daha fazlasına sahip olma' ve 'eksiklik' duygusunu beraberinde getirerek yeni bir ekonomik zihniyetin kapısını aralamıştır.",
            "C) Avcı-toplayıcılar, tarım toplumlarına göre her zaman daha fazla kaynak sıkıntısı çekmiştir.",
            "D) Tarım, insanların ihtiyaç duyduklarından daha az üretmesine yol açmıştır.",
            "E) Sahlins, tarım toplumlarını avcı-toplayıcılardan ekonomik açıdan daha başarılı bulmaktadır."
        ],
        cevap: "B) Tarım, 'daha fazlasına sahip olma' ve 'eksiklik' duygusunu beraberinde getirerek yeni bir ekonomik zihniyetin kapısını aralamıştır.",
        aciklama: "Doğru yanıt B'dir. Sahlins'e göre tarıma geçiş, \"artık üretim\" kavramını ve dolayısıyla \"eksiklik\" duygusunu ortaya çıkarmıştır. Bu, insanın zihniyet dünyasında büyük bir kırılmaya, yani \"daha fazlasına sahip olma\" güdüsünün doğmasına yol açmıştır. A seçeneği avcı-toplayıcıların zihniyetini tanımlar ama tarımın katkısını yanlış yorumlar. C seçeneği metnin tam tersini iddia eder. D ve E seçenekleri de metnin içeriğiyle çelişmektedir."
    },
    {
        soru: "<i>MEB onaylı 9. Sınıf Tarih Ders Kitabı'nda (2023) hayvan evcilleştirme şöyle aktarılır: \"İnsanlık tarihinde ilk evcilleştirilen hayvan köpek olmuş, onu koyun, keçi, sığır ve domuz izlemiştir. Evcil hayvanlar; et, süt ve yün gibi besin ve hammadde kaynağı işlevi görmüş, aynı zamanda tarla sürmek ve yük taşımak amacıyla da kullanılmıştır. Bu durum, insanın üretim kapasitesini önemli ölçüde artırmıştır.\"</i><br><br><b>Metne göre hayvan evcilleştirmesinin tarım toplumuna katkısını değerlendirdiğimizde, aşağıdaki yargılardan hangisi doğrudan desteklenmektedir?</b>",
        secenekler: [
            "A) Hayvanların evcilleştirilmesi yalnızca beslenme sorununu çözmüş, üretim süreçleriyle ilgisi olmamıştır.",
            "B) Evcilleştirme, insanın hem besin hem de iş gücü kaynaklarını çeşitlendirerek üretim kapasitesini artırmıştır.",
            "C) İlk evcilleştirilen hayvan, tarla işlerinde kullanılmak üzere sığır olmuştur.",
            "D) Hayvan evcilleştirmesi, insan nüfusunu olumsuz etkilemiştir.",
            "E) Yük taşımada kullanılan hayvanlar ticaret ağlarının gelişmesini engellemiştir."
        ],
        cevap: "B) Evcilleştirme, insanın hem besin hem de iş gücü kaynaklarını çeşitlendirerek üretim kapasitesini artırmıştır.",
        aciklama: "Doğru yanıt B'dir. Metin, hayvanların hem besin/hammadde (et, süt, yün) hem de iş gücü (tarla sürme, yük taşıma) kaynağı olduğunu belirtmekte ve üretim kapasitesinin arttığını vurgulamaktadır. A seçeneği metnin yalnızca bir kısmını alıyor ve iş gücü boyutunu yok sayıyor. C seçeneğinde ilk evcilleştirilen hayvanın köpek olduğu belirtilmiştir, sığır değil. D ve E seçenekleri metinle desteklenmemektedir."
    },
    {
        soru: "<i>Tarihçi Andrew Sherratt, \"The Secondary Products Revolution\" (1981) makalesinde şunu öne sürer: \"İlk çiftçiler hayvanları yalnızca kesip eti için kullanırken, MÖ 4. binyıldan itibaren süt, yün ve hayvan gücü gibi 'ikincil ürünler' sistematik biçimde kullanılmaya başlandı. Bu gelişme, hayvan sürülerinin değerini artırdı ve servetin bir göstergesi hâline getirdi.\"</i><br><br><b>Sherratt'ın bu tespitine göre, ikincil ürün devriminin toplumsal sonuçları hakkında hangi yorum yapılabilir?</b>",
        secenekler: [
            "A) Hayvan sürülerine sahip olmak, toplumsal statü ve servetin yeni bir göstergesi hâline gelmiştir.",
            "B) İkincil ürünler, hayvanların ekonomik değerini tamamen ortadan kaldırmıştır.",
            "C) Hayvan sürülerinin değer kazanması, eşitsizlikleri azaltarak toplumsal dengeyi sağlamıştır.",
            "D) Hayvan gücünün kullanılması, çiftçilerin tamamen göçebe yaşama geçmesine neden olmuştur.",
            "E) Süt ve yün üretimi yalnızca köylerin içindeki tüketime yönelik olmuş, ticarette kullanılmamıştır."
        ],
        cevap: "A) Hayvan sürülerine sahip olmak, toplumsal statü ve servetin yeni bir göstergesi hâline gelmiştir.",
        aciklama: "Doğru yanıt A'dır. Metin, sürülerin \"servetin bir göstergesi hâline geldiğini\" açıkça ifade etmektedir. Bu, hayvan sahipliğinin toplumsal statü ve servet eşitsizliğiyle doğrudan bağlantılı hale geldiğini gösterir. B seçeneği ekonomik değerin ortadan kalktığını iddia eder, bu yanlıştır. C seçeneğinde ise eşitsizliklerin azaldığı öne sürülmektedir; ancak metin tam aksine servet farklılaşmasına dikkat çekmektedir. D ve E seçenekleri metnin içeriğiyle desteklenmemektedir."
    },
    {
        soru: "<i>V. Gordon Childe, \"Man Makes Himself\" (İnsan Kendini Yarattı, 1936) adlı eserinde tarımın nüfus üzerindeki etkisini şöyle özetler: \"Tarım, besin üretiminde sürekliliği sağladı; bu da çocukların daha güvenli koşullarda büyümesine olanak tanıdı. Yerleşik topluluklar, avcı-toplayıcılara kıyasla daha kısa süreli emzirme uyguladı ve böylece doğurganlık aralıkları azaldı. Sonuç olarak nüfus artış hızı belirgin şekilde yükseldi.\"</i><br><br><b>Childe'ın bu açıklamasına göre, tarımın nüfus üzerindeki etkisini sağlayan temel zincir aşağıdakilerin hangisinde doğru sıralanmıştır?</b>",
        secenekler: [
            "A) Göç → emzirme süresinin uzaması → doğurganlığın azalması → nüfus düşüşü",
            "B) Besin sürekliliği → daha kısa emzirme → doğurganlık aralıklarının kısalması → nüfus artışı",
            "C) Göçebe yaşam → besin fazlası → nüfus artışı → yerleşik düzen",
            "D) Nüfus artışı → besin sürekliliği → tarımın başlaması → göç",
            "E) Tarım → daha uzun emzirme → nüfus azalması → yerleşik düzen"
        ],
        cevap: "B) Besin sürekliliği → daha kısa emzirme → doğurganlık aralıklarının kısalması → nüfus artışı",
        aciklama: "Doğru yanıt B'dir. Metin, \"besin sürekliliği → çocukların güvenli büyümesi → daha kısa emzirme → doğurganlık aralıklarının kısalması → nüfus artışı\" zincirini net biçimde ortaya koymaktadır. A seçeneğinde göç ve olumsuz sonuçlar yanlış sıralanmıştır. C seçeneği göçebe yaşamdan başlatmaktadır, bu ise metnin mantığıyla çelişir. D seçeneği sıralama ilişkisini tersine çevirmektedir. E seçeneğinde daha uzun emzirme ve nüfus azalması gibi metinden desteklenmeyen unsurlar yer almaktadır."
    },
    {
        soru: "<i>Sosyolog Gerhard Lenski, \"Power and Privilege\" (1966) eserinde toplumsal tabakalaşmayı şöyle açıklar: \"Avcı-toplayıcı topluluklarda servet birikimi, hareket kısıtlamaları nedeniyle neredeyse imkânsızdı; herkes aşağı yukarı eşit miktarda mala sahipti. Tarımsal yerleşimle birlikte arazi, hayvan ve tahıl gibi birikebilen değerler ortaya çıktı. Bu değerlerin farklı miktarlarda birikimiyle birlikte bazı aileler diğerlerinin üzerinde kalıcı bir ekonomik ve sosyal konum elde etti.\"</i><br><br><b>Bu metinden yola çıkarak tarım öncesi ve sonrası toplumsal yapı arasındaki farkı en iyi hangi yargı açıklar?</b>",
        secenekler: [
            "A) Her iki toplumda da servet birikimi aynı hızda gerçekleşmiş ve eşitsizlik değişmemiştir.",
            "B) Avcı-toplayıcı topluluklar, tarım toplumlarına göre daha katı bir sınıf yapısına sahipti.",
            "C) Tarımın sağladığı birikebilen değerler, eşit dağılımı bozarak kalıcı toplumsal hiyerarşinin temelini atmıştır.",
            "D) Tarım öncesinde arazi mülkiyeti toplumsal statünün tek belirleyicisiydi.",
            "E) Avcı-toplayıcılarda servetin paylaşılması, tarım toplumlarına göre daha adaletsizdi."
        ],
        cevap: "C) Tarımın sağladığı birikebilen değerler, eşit dağılımı bozarak kalıcı toplumsal hiyerarşinin temelini atmıştır.",
        aciklama: "Doğru yanıt C'dir. Lenski'nin temel argümanı, tarımla birlikte arazi, hayvan ve tahıl gibi \"birikebilen değerlerin\" ortaya çıkmasının eşit dağılımı bozduğu ve kalıcı hiyerarşinin temelini attığıdır. A seçeneği iki toplum arasındaki farkı yok sayar. B seçeneği metnin tam tersini söyler. D seçeneği, tarım öncesinde arazi mülkiyetinin belirleyici olduğunu öne sürer; oysa metin bunun tarımla başladığını anlatmaktadır. E seçeneği de mantıksal açıdan metnin içeriğiyle çelişmektedir."
    },
    {
        soru: "<i>Tarihçi Bruce Trigger, \"A History of Archaeological Thought\" (1989) kitabında din adamlarının yükselişini şöyle yorumlar: \"Tarımsal toplumlarda hasat zamanını öngörmek, yağmur duaları düzenlemek ve bereket ritüelleri icra etmek giderek uzmanlaşmış bir bilgi gerektirdi. Bu bilgiyi elinde bulunduran şamanlar ve din adamları, toplulukların doğaüstü güçlerle aracıları olarak tanındı. Zamanla bu aracılık rolü, onlara ekonomik ve siyasi bir güç de kazandırdı.\"</i><br><br><b>Metne göre din adamlarının toplumsal güç kazanmasındaki temel mekanizma nedir?</b>",
        secenekler: [
            "A) Din adamları, fiziksel güçleri sayesinde toplumda lider konumuna yükselmiştir.",
            "B) Tarım takviminin ve doğaüstü bilginin tekelleştirilmesi, din adamlarına çok boyutlu bir güç sağlamıştır.",
            "C) Ritüellerin icra edilmesi, topluluğun doğayla ilgisini tamamen kesmiş ve din adamlarını işlevsiz kılmıştır.",
            "D) Yağmur ve bereket ritüelleri, yalnızca ekonomik amaçlarla düzenlenmiştir.",
            "E) Din adamları, toplumsal güç elde etmek için siyasi kurumları ortadan kaldırmıştır."
        ],
        cevap: "B) Tarım takviminin ve doğaüstü bilginin tekelleştirilmesi, din adamlarına çok boyutlu bir güç sağlamıştır.",
        aciklama: "Doğru yanıt B'dir. Metin, din adamlarının hasat takvimi ve doğaüstü bilgiyi tekelleştirerek önce sembolik aracı konumuna yükseldiklerini, ardından bu konumun onlara ekonomik ve siyasi güç kazandırdığını açıklamaktadır. A seçeneğinde fiziksel güç vurgusu metinde yer almaz. C seçeneği din adamlarının işlevsizleştiğini iddia eder, bu ise metnin tam tersine aykırıdır. D seçeneği ritüelleri yalnızca ekonomik çerçeveye indirger. E seçeneği ise siyasi kurumların ortadan kaldırılmasına dair metinde hiçbir ipucu bulunmamaktadır."
    },
    {
        soru: "<i>Kolombiya Üniversitesi tarihçilerinden William McNeill, \"The Rise of the West\" (1963) eserinde erken ticaret ağlarını şöyle tanımlar: \"MÖ 4. binyılda Mezopotamya'daki kentsel merkezler, çevrelerindeki kırsal köylerle karmaşık bir değiş tokuş ilişkisine girmişti. Kentler el sanatları ürünleri ve örgütlü iş gücü sunarken köyler tahıl ve hayvansal ürünler sağlıyordu. Bu karşılıklı bağımlılık, birbirinden farklı ekolojik bölgeler arasında uzun mesafeli ticaret güzergâhlarının oluşmasının önünü açtı.\"</i><br><br><b>Bu metne göre Mezopotamya'daki erken ticaret ağlarının oluşmasında belirleyici olan temel unsur nedir?</b>",
        secenekler: [
            "A) Her topluluk kendi ihtiyacını karşılayabildiğinden, ticaret ağları tamamen gereksiz kalmıştır.",
            "B) Kent ve kırsal arasındaki üretim farklılıkları ve karşılıklı bağımlılık, ticaretin itici gücü olmuştur.",
            "C) Uzun mesafeli ticaret, yalnızca siyasi birlik sağlandıktan sonra mümkün olmuştur.",
            "D) Köyler, kentlere el sanatları ve zanaat ürünleri tedarik etmiştir.",
            "E) Ticaret ağları yalnızca tahıl ve hayvansal ürünler üzerine kurulmuş, el sanatları dahil edilmemiştir."
        ],
        cevap: "B) Kent ve kırsal arasındaki üretim farklılıkları ve karşılıklı bağımlılık, ticaretin itici gücü olmuştur.",
        aciklama: "Doğru yanıt B'dir. McNeill, kent-kır arasındaki farklı üretim kapasiteleri ve bunun yarattığı karşılıklı bağımlılığın ticaret ağlarını ortaya çıkardığını vurgulamaktadır. A seçeneği ticaret ağlarının gereksiz olduğunu söyler; bu metnin tam tersidir. C seçeneğinde \"siyasi birlik\" koşulu metinde yer almaz. D seçeneği, köylerin ve kentlerin rollerini yer değiştirmiştir; metin kentlerin el sanatları sağladığını belirtir. E seçeneği el sanatlarını dışarıda bırakır, bu da metne aykırıdır."
    },
    {
        soru: "<i>Karl Wittfogel, \"Oriental Despotism\" (1957) adlı tartışmalı eserinde sulama sistemleri ile siyasi örgütlenme arasındaki ilişkiyi şöyle açıklar: \"Büyük sulama kanallarının yapımı ve bakımı, binlerce kişinin koordineli çalışmasını zorunlu kılıyordu. Bu koordinasyonu sağlamak için merkezi bir otoriteye, yani geniş idari aygıta ihtiyaç duyuluyordu. Dolayısıyla sulama, despotik devlet yapılarının ortaya çıkmasında belirleyici bir etken olmuştur.\"</i><br><br><b>Wittfogel'in tezini sınayan bir tarihçi, hangi soruyu sormak zorundadır?</b>",
        secenekler: [
            "A) Sulama kanallarının yalnızca şehirlere yakın yerlerde inşa edilip edilmediği",
            "B) Büyük sulama projelerinin merkezi otorite olmadan da küçük topluluklar tarafından yönetilip yönetilemeyeceği",
            "C) Despotik yöneticilerin kanalları ne kadar sürede inşa ettirdiği",
            "D) Sulama sularının hangi mahsullere öncelikle tahsis edildiği",
            "E) Kanal işçilerinin ücretlerinin altın mı yoksa tahıl cinsinden mi ödendiği"
        ],
        cevap: "B) Büyük sulama projelerinin merkezi otorite olmadan da küçük topluluklar tarafından yönetilip yönetilemeyeceği",
        aciklama: "Doğru yanıt B'dir. Wittfogel, büyük sulamanın merkezi despotik otoriteyi zorunlu kıldığını savunmaktadır. Bu tezi test etmenin en kritik yolu, büyük sulama projelerinin merkezi otorite olmadan da yönetilip yönetilemeyeceğini araştırmaktır; çünkü bu durumun var olduğu kanıtlanırsa tez zayıflar. Diğer seçenekler (A, C, D, E) Wittfogel'in temel nedensellik zincirini doğrudan sorgulamaz; bunlar yardımcı ya da bağımsız sorulardır."
    },
    {
        soru: "<i>Eski Yakın Doğu uzmanı Denise Schmandt-Besserat, \"Before Writing\" (1992) çalışmasında şunu aktarır: \"Mezopotamya'da yazının ilk nüveleri, MÖ 8000'lerden itibaren kullanılan kil tokenlar (küçük nesneler) olarak karşımıza çıkmaktadır. Bu tokenlar tahıl, yağ veya hayvan miktarlarını temsil ediyor; depolama ve takas işlemlerini kaydetmek için kullanılıyordu. MÖ 3100'e gelindiğinde bu tokenlar düzleşerek kil tabletlere baskı yapılan sembollere dönüştü: çivi yazısı böyle doğdu.\"</i><br><br><b>Bu metne göre yazının kökenine ilişkin hangi yorum en destekli çıkarımdır?</b>",
        secenekler: [
            "A) Yazı, öncelikle dinî metinleri kayıt altına almak amacıyla icat edilmiştir.",
            "B) Yazı, ekonomik kayıt tutma ihtiyacından doğmuş ve tarımsal ticaretle doğrudan bağlantılıdır.",
            "C) Çivi yazısı, tarihte ilk kez MÖ 8000'lerde kullanılmaya başlanmıştır.",
            "D) Tokenlar; sanat, edebiyat ve mitoloji kayıtları için geliştirilmiştir.",
            "E) Yazının icadı, sulama sistemlerinin geliştirilmesinden sonra gerçekleşmiştir ve bu iki gelişme birbirinden tamamen bağımsızdır."
        ],
        cevap: "B) Yazı, ekonomik kayıt tutma ihtiyacından doğmuş ve tarımsal ticaretle doğrudan bağlantılıdır.",
        aciklama: "Doğru yanıt B'dir. Schmandt-Besserat'ın araştırması, yazının köklerinin tahıl, yağ ve hayvan miktarlarını kayıt altına almak için kullanılan kil tokenlara dayandığını ortaya koymaktadır. Bu, yazının ekonomik ve ticari ihtiyaçtan doğduğunu kanıtlar. A seçeneğinde dinî amaç ön plana çıkarılmış; ancak metinde bunun kanıtı yoktur. C seçeneğinde çivi yazısının MÖ 8000'de kullanıldığı söylenmektedir; oysa metin bu tarihi tokenlar için vermiş, çivi yazısını MÖ 3100'e bağlamıştır. D seçeneği edebiyat ve sanat kayıtlarını öne çıkarır, bu da metinle çelişir. E seçeneği iki gelişmenin bağımsız olduğunu öne sürer; metin ise bir ilişkiyi ima etmektedir."
    },
    {
        soru: "<i>Sosyolog Max Weber, \"Economy and Society\" (1922) adlı yapıtında mülkiyet kavramını şöyle çerçeveler: \"Tarımsal yerleşim, toprağı soyut bir değere dönüştürdü. İnsanlar artık belirli bir arazinin sürekliliğine yatırım yapıyor, onu sulayıp gübreliyor ve yıllar içinde verimliliğini artırmak için emek harcıyordu. Bu birikim ve yatırım, 'benim toprağım' duygusunun ve miras hukukunun temelini attı.\"</i><br><br><b>Weber'in bu çözümlemesine göre, tarımın ortaya çıkardığı en köklü zihinsel/hukuki dönüşüm aşağıdakilerden hangisidir?</b>",
        secenekler: [
            "A) İnsanların toprağı ortak mülk saydığı geleneksel düzenin güçlendirilmesi",
            "B) Toprağa yapılan uzun vadeli yatırımın, özel mülkiyet ve miras hukuku kavramlarının doğuşunu tetiklemesi",
            "C) Her köylünün eşit miktarda arazi sahibi olmasını güvence altına alan hukuk sistemlerinin gelişmesi",
            "D) Toprağın soyut bir değer kazanması sürecinin yalnızca ticari amaçlarla ortaya çıkması",
            "E) Miras hukukunun, tarımın başlamasından yüzyıllar sonra ve ondan tamamen bağımsız olarak gelişmesi"
        ],
        cevap: "B) Toprağa yapılan uzun vadeli yatırımın, özel mülkiyet ve miras hukuku kavramlarının doğuşunu tetiklemesi",
        aciklama: "Doğru yanıt B'dir. Weber'in argümanının özü, toprağa yapılan uzun vadeli emek ve yatırımın \"benim toprağım\" duygusunu ve miras hukukunu doğurduğudur. Bu, özel mülkiyet kavramının tarımla birlikte ortaya çıktığını gösterir. A seçeneği ortak mülk geleneğini güçlendirme söz eder; bu metnin aksine bir iddiadır. C seçeneği eşit arazi dağılımından bahseder; metinde böyle bir güvenceden söz edilmez. D seçeneği yalnızca ticari amacı öne çıkarır; Weber'in metninde ise yatırım ve birikim boyutu belirleyicidir. E seçeneği tarım ve miras hukukunu birbirinden koparır; metin ise bu iki olguyu nedensellik bağı içinde sunar."
    },
    {
        soru: "<i>Arkeolog Colin Renfrew, \"Archaeology and Language\" (1987) eserinde iş bölümünün ortaya çıkışını şu şekilde yorumlar: \"İlk köylerde herkes hem çiftçilik hem de basit araç yapımı gibi birden fazla işi yapıyordu. Ancak nüfus arttıkça ve besin fazlası oluştukça, bazı bireyler tarımsal üretimden çekilip tüm zamanlarını çanak çömlek, dokuma ya da maden işleme gibi alanlara ayırabildi. Bu uzmanlaşma, zanaatları bilim ve sanat boyutuna taşıdı.\"</i><br><br><b>Renfrew'ün bu aktarımına göre uzmanlaşmanın önkoşulu nedir ve uzmanlaşma topluma ne katar?</b>",
        secenekler: [
            "A) Uzmanlaşma, nüfusun azalması durumunda ortaya çıkar ve toplumu basitleştirir.",
            "B) Besin fazlası ve nüfus artışı, bazı bireylerin tarım dışı alanlara odaklanmasına olanak tanır ve bu durum zanaat bilgisini derinleştirir.",
            "C) Uzmanlaşma, herkesin aynı işi yapmasını zorunlu kılarak toplumsal farklılıkları azaltır.",
            "D) İş bölümü, besin fazlasından tamamen bağımsız olarak yalnızca kişisel yeteneklere göre ortaya çıkar.",
            "E) Uzmanlaşma, her bireyin tarım ve zanaat işlerini aynı anda daha iyi yapmasını sağlamıştır."
        ],
        cevap: "B) Besin fazlası ve nüfus artışı, bazı bireylerin tarım dışı alanlara odaklanmasına olanak tanır ve bu durum zanaat bilgisini derinleştirir.",
        aciklama: "Doğru yanıt B'dir. Renfrew'e göre besin fazlası ve nüfus artışı, bazı bireylerin tarımdan çekilip zanaata odaklanmasını mümkün kılmıştır; bu da zanaat bilgisini derinleştirmiştir. A seçeneğinde nüfus azalması ve toplumun basitleşmesi söz konusu edilmekte; bu metnin içeriğiyle çelişmektedir. C seçeneği uzmanlaşmanın eşitlik yarattığını ima eder; bu da yanlıştır. D seçeneği besin fazlasından bağımsız bir nedeni öne sürer; metinde ise açıkça korelasyon kurulmaktadır. E seçeneği, uzmanlaşmanın her bireyi çok yönlü kıldığını söyler; bu ise metindeki \"tarımdan çekilme\" ifadesiyle doğrudan çelişir."
    },
    {
        soru: "<i>Sümer uzmanı Samuel Noah Kramer, \"History Begins at Sumer\" (1956/1981) eserinde ilk şehirleri şu sözlerle tanımlar: \"MÖ 3500 civarında Güney Mezopotamya'da ortaya çıkan Uruk kenti, dünya tarihinin ilk gerçek şehri olarak kabul edilebilir. Surlarla çevrili bu kentte tapınak, depo, pazar ve idari bina gibi işlevsel bölgeler ayrışmıştı. Kentte yaşayan insanların yarısından fazlası doğrudan tarımla uğraşmıyor, başka hizmet ve meslekleri icra ediyordu.\"</i><br><br><b>Kramer'in aktardığı bilgilerden yola çıkarak Uruk'un 'ilk gerçek şehir' sayılmasının gerekçesi ne olabilir?</b>",
        secenekler: [
            "A) Uruk, tarihte ilk kez surlarla korunan bir yerleşim yeri olduğu için şehir sayılmaktadır.",
            "B) Tarım dışı mesleklerin varlığı ve işlevsel bölgelere ayrışma, toplumsal karmaşıklık ve uzmanlaşmanın geliştiğini gösterir; bu özellikler Uruk'u bir şehir yapar.",
            "C) Uruk'u şehir yapan yegâne unsur, tapınağın varlığıdır.",
            "D) Nüfusunun tamamı tarımla geçimini sağladığı için Uruk gerçek bir tarım kenti olarak öne çıkmaktadır.",
            "E) İdari bina ve depoların varlığı yalnızca askeri amaçlara hizmet ettiğinden şehri benzersiz kılmıştır."
        ],
        cevap: "B) Tarım dışı mesleklerin varlığı ve işlevsel bölgelere ayrışma, toplumsal karmaşıklık ve uzmanlaşmanın geliştiğini gösterir; bu özellikler Uruk'u bir şehir yapar.",
        aciklama: "Doğru yanıt B'dir. Kramer'in betimlemesinde birden fazla kriter dikkat çekmektedir: işlevsel bölgelere ayrışma ve nüfusun yarısından fazlasının tarım dışı mesleklerle geçimini sağlaması. Bu iki unsur, uzmanlaşmış ve karmaşık bir toplumsal örgütlenmeye, yani kentsel yaşamın temel özelliklerine işaret eder. A seçeneği tek bir kriteri (surlar) öne çıkarır; oysa metin birden fazla unsur sunmaktadır. C seçeneği tapınağı yegâne kriter olarak gösterir, bu da metnin bütünüyle çelişir. D seçeneği, metnin tam tersini söyler. E seçeneği idari yapıları yalnızca askeri amaçlara bağlar; metin ise bunları idari ve ekonomik işlevlere bağlamaktadır."
    },
    {
        soru: "<i>Tarihçi Mario Liverani, \"Uruk: The First City\" (2006) eserinde vergilendirme sistemlerini şöyle ele alır: \"Sümer tapınak ekonomisinde tahıl ve diğer ürünler, büyük tapınak depolarında toplanıyor; ardından işçilere, din adamlarına ve askerlere dağıtılıyordu. Bu sistem, fiilî bir yeniden dağıtım ekonomisi yaratmıştı. Tapınak yönetimi; kayıtları tutmak, işçi listelerini güncellemek ve tahsis miktarlarını belirlemek için bürokrasi geliştirdi.\"</i><br><br><b>Liverani'nin aktardığı tapınak ekonomisi modeline göre, bu sistemin en önemli siyasi ve idari sonucu nedir?</b>",
        secenekler: [
            "A) Tapınak ekonomisi, bireysel mülkiyeti güçlendirerek eşitsizlikleri kalıcı biçimde çözmüştür.",
            "B) Kaynakların toplanıp dağıtılması, kayıt tutma ve bürokrasiye olan ihtiyacı artırarak merkezi idari yapıyı güçlendirmiştir.",
            "C) Tapınak depoları, yalnızca din adamlarının kişisel zenginleşmesi amacıyla kullanılmıştır.",
            "D) Tahıl dağıtım sistemi, yazının gereksiz hâle gelmesine yol açmıştır.",
            "E) Tapınak ekonomisi, tarım dışı mesleklerin tamamen yok olmasına neden olmuştur."
        ],
        cevap: "B) Kaynakların toplanıp dağıtılması, kayıt tutma ve bürokrasiye olan ihtiyacı artırarak merkezi idari yapıyı güçlendirmiştir.",
        aciklama: "Doğru yanıt B'dir. Liverani'nin metninde tapınak ekonomisinin kayıt tutma, liste güncelleme ve bürokrasi gerektirdiği açıkça belirtilmektedir. Bu durum, merkezi idari yapının güçlendiğine işaret etmektedir. A seçeneği eşitsizliklerin çözıldüğünü iddia eder; metin bunun kanıtını vermemektedir. C seçeneği yalnızca din adamlarının çıkarını öne çıkarır; ancak metinde işçi ve askerlere de dağıtım yapıldığı belirtilmektedir. D seçeneği yazının gereksiz hale geldiğini söyler; bu ise tam tersi bir sonuçtur. E seçeneğinde tarım dışı mesleklerin yok olduğu iddia edilmekte, bu da metnin ruhuna aykırıdır."
    },
    {
        soru: "<i>Tarihçi Azar Gat, \"War in Human Civilization\" (2006) kitabında tarım öncesi ve sonrası savaş örüntülerini karşılaştırır: \"Avcı-toplayıcı topluluklarda çatışmalar genellikle anlık ve bireysel düzeydeydi. Tarımsal yerleşimle birlikte arazi, su kaynakları ve depolanmış besinler kalıcı ve savunulabilir değerlere dönüştü. Bu değerlerin korunması ya da ele geçirilmesi, örgütlü ve sürekli bir savaş kapasitesinin gelişmesini zorunlu kıldı.\"</i><br><br><b>Gat'ın bu analizine göre, tarımsal düzenin savaş biçimini dönüştürmesinin temel nedeni nedir?</b>",
        secenekler: [
            "A) Tarım toplumları, savaşı yalnızca dinî ritüel olarak benimsediğinden savaş kapasitesi gelişmiştir.",
            "B) Tarımla birlikte ortaya çıkan kalıcı ve savunulabilir değerler, örgütlü savaşın motivasyonunu ve gerekliliğini artırmıştır.",
            "C) Avcı-toplayıcı topluluklarda örgütlü savaş, tarım toplumlarından daha yaygındı.",
            "D) Savaş kapasitesi, tarımdan bağımsız olarak yalnızca nüfus artışının bir sonucudur.",
            "E) Tarım toplumları, kaynakları kolayca terk edebildiğinden savunma ihtiyacı duymamıştır."
        ],
        cevap: "B) Tarımla birlikte ortaya çıkan kalıcı ve savunulabilir değerler, örgütlü savaşın motivasyonunu ve gerekliliğini artırmıştır.",
        aciklama: "Doğru yanıt B'dir. Gat'ın temel argümanı, tarımla birlikte arazi, su ve depolanmış besin gibi \"kalıcı ve savunulabilir değerlerin\" ortaya çıkmasının savaşı örgütlü ve sürekli bir hale getirdiğidir. A seçeneğinde dinî ritüel gerekçesi metinde yer almaz. C seçeneği avcı-toplayıcılarda örgütlü savaşı daha yaygın gösterir; bu metnin tam tersidir. D seçeneği tarımdan bağımsız bir neden öne sürer; Gat ise değerlerle motivasyonu bağdaştırmaktadır. E seçeneği, tarım toplumlarının kaynakları terk edebildiğini söyler; bu ise \"savunulabilir değerler\" kavramıyla çelişir."
    },
    {
        soru: "<i>Feminist tarihçi Gerda Lerner, \"The Creation of Patriarchy\" (1986) eserinde toplumsal cinsiyet ilişkilerini şöyle yorumlar: \"Avcı-toplayıcı topluluklarda kadın ve erkek, birbirini tamamlayan üretim rolleri üstleniyordu. Tarımsal yerleşimle birlikte pulluk ve büyükbaş hayvanlarla çalışma erkek işine dönüşürken ev içi üretim ve çocuk bakımı kadınlar için öncelikli alan hâline geldi. Mülk devrinin erkek soyundan geçmesi için gereken 'kontrol edilebilir' üreme, kadın bedeni üzerinde denetim kurulmasını beraberinde getirdi.\"</i><br><br><b>Lerner'in bu çözümlemesine göre, tarımın toplumsal cinsiyet ilişkilerine etkisi nasıl özetlenebilir?</b>",
        secenekler: [
            "A) Tarım, kadın ve erkek arasındaki iş bölümünü daha eşit hâle getirmiştir.",
            "B) Pullukla ilişkili iş gücü ve mülk mirasına dayalı kaygılar, kadın bedeninin denetim altına alınmasını meşrulaştıran ataerkil bir yapının zeminini hazırlamıştır.",
            "C) Tarım öncesinde kadınlar, toplumsal yaşamda tamamen edilgen ve ikincil bir konumdaydı.",
            "D) Tarımsal üretimde kadın emeği yok sayılmış, tarih boyunca hiçbir katkıları olmamıştır.",
            "E) Lerner, ataerkilliğin yalnızca yazılı hukukun ortaya çıkmasıyla başladığını öne sürmektedir."
        ],
        cevap: "B) Pullukla ilişkili iş gücü ve mülk mirasına dayalı kaygılar, kadın bedeninin denetim altına alınmasını meşrulaştıran ataerkil bir yapının zeminini hazırlamıştır.",
        aciklama: "Doğru yanıt B'dir. Lerner'in argümanı iki sacayağına dayanır: (1) pullukla çalışmanın erkeğe özgü bir faaliyet hâline gelmesi ve (2) mülk devrinin erkek soyundan geçmesini güvence altına almak için kadın bedeninin denetlenmesi. Bu iki unsur ataerkil yapının zeminini oluşturmuştur. A seçeneği eşitlik arttığını söyler; metin ise tam tersini iddia eder. C seçeneği tarım öncesinde kadının zaten ikincil konumda olduğunu öne sürer; metin ise görevlerin tamamlayıcı olduğunu belirtir. D seçeneği kadın emeğini tamamen yok sayan aşırı bir yargıdır. E seçeneği ataerkilliği yalnızca hukuki sürece bağlar; Lerner ise ekonomik ve üreme dinamiklerini ön plana çıkarmaktadır."
    },
    {
        soru: "<i>Antikçağ tarihçisi Moses Finley, \"Ancient Slavery and Modern Ideology\" (1980) kitabında köleliğin kökenini şöyle inceler: \"Tarım öncesinde bir düşmanı öldürmek yerine onu tutsaklamanın ekonomik bir mantığı yoktu; çünkü taşınabilir fazla bir servet yoktu. Tarımsal artık ürünün ortaya çıkmasıyla birlikte tutsak insanların zorla çalıştırılması kârlı hâle geldi. Sulama kanalı kazımaktan tahıl ezmek, tahıl biçmekten inşaat yapmaya kadar uzanan ağır işlerde köle emeği giderek vazgeçilmez oldu.\"</i><br><br><b>Finley'in bu çözümlemesine göre, kölelik kurumunun ortaya çıkmasını mümkün kılan ekonomik koşul nedir?</b>",
        secenekler: [
            "A) Kölelik, tarımsal artığın ortaya çıkmasından çok önce avcı-toplayıcı dönemde yaygın bir pratik olarak zaten mevcuttu.",
            "B) Tarımsal artığın varlığı, zorla çalıştırmanın ekonomik olarak anlamlı ve kârlı hale gelmesini sağlamıştır.",
            "C) Kölelik, yalnızca savaş esirlerini mübadele aracı olarak kullanan ticaret ağlarından doğmuştur.",
            "D) Köle emeği, tarımsal toplumda yalnızca ev içi hizmetler için kullanılmıştır.",
            "E) Tarım öncesi topluluklarda tutsak almak, ekonomik olarak tarım dönemine göre çok daha kârlıydı."
        ],
        cevap: "B) Tarımsal artığın varlığı, zorla çalıştırmanın ekonomik olarak anlamlı ve kârlı hale gelmesini sağlamıştır.",
        aciklama: "Doğru yanıt B'dir. Finley'in argümanının özü şudur: Tarım öncesinde tutsaklamanın ekonomik bir mantığı yoktu; ancak tarımsal artık ortaya çıkınca zorla çalıştırma kârlı hale geldi. Bu nedenle tarımsal artık, kölelik kurumunun ekonomik temelini oluşturmuştur. A seçeneği köleliğin tarım öncesinde yaygın olduğunu iddia eder; metin bunun aksini söyler. C seçeneğinde ticaret ağları tek neden olarak gösterilmektedir; Finley'nin odak noktası ise ekonomik verimdir. D seçeneği köle emeğini yalnızca ev içi hizmetlere bağlar; metinde çok daha geniş bir işlev yelpazesi sayılmaktadır. E seçeneği tarihi olarak tutarsız ve metnin teriyle çelişen bir iddiadır."
    },
    {
        soru: "<i>Teknoloji tarihçisi Lynn White Jr., \"Medieval Technology and Social Change\" (1962) eserinde sabanın (pulluğun) etkisini şöyle değerlendirir: \"Ağır demir sabanın kullanılmasıyla birlikte ağır kil topraklar da tarıma açılabildi. Bu gelişme, büyük öküz ekiplerini besleyebilecek, dolayısıyla altyapı yatırımı yapabilecek büyük arazi sahiplerine avantaj sağladı. Küçük çiftçiler ise zamanla büyük toprak sahiplerine bağımlı hale geldi.\"</i><br><br><b>White'ın bu analizine göre, demir sabanın yaygınlaşması hangi toplumsal sonucu doğurmuştur?</b>",
        secenekler: [
            "A) Demir saban, küçük çiftçilerin büyük toprak sahiplerine karşı ekonomik bağımsızlığını artırmıştır.",
            "B) Teknolojik gelişme, kaynakları zaten olan büyük mülk sahiplerine avantaj sağlayarak küçük çiftçiler üzerindeki ekonomik bağımlılığı derinleştirmiştir.",
            "C) Ağır kil toprakların tarıma açılması, toplumsal hiyerarşiyi tamamen ortadan kaldırmıştır.",
            "D) Demir sabanın yaygınlaşması, hayvan gücünün tarımdan çekilmesine yol açmıştır.",
            "E) Büyük öküz ekipleri yalnızca din adamları tarafından kontrol edilmiştir."
        ],
        cevap: "B) Teknolojik gelişme, kaynakları zaten olan büyük mülk sahiplerine avantaj sağlayarak küçük çiftçiler üzerindeki ekonomik bağımlılığı derinleştirmiştir.",
        aciklama: "Doğru yanıt B'dir. White'ın argümanı, teknolojik yeniliğin (demir saban) büyük arazi sahiplerine orantısız bir avantaj sunduğunu ve küçük çiftçileri bağımlı hale getirdiğini ortaya koymaktadır. Bu, teknolojik ilerlemenin otomatik olarak eşitlikçi sonuçlar doğurmadığını gösterir. A seçeneği teknolojinin küçük çiftçilere yarar sağladığını söyler; metin bunun aksini belirtmektedir. C seçeneğinde hiyerarşinin tamamen kalktığı iddia edilmektedir; metin ise güç dengesizliğini vurgular. D seçeneğinde hayvan gücünün tarımdan çekilmesi söz konusu edilmektedir; metin ise büyük öküz ekiplerinin kullanımının arttığını anlatmaktadır. E seçeneği din adamlarına dair bir iddia taşır; metinde bu bilgi yer almaz."
    },
    {
        soru: "<i>Hammurabi Kanunları'ndan (MÖ 1754) alınan şu madde, tarımsal düzeni yansıtmaktadır: \"Eğer bir bahçıvan, birinin bahçesini kiralamak üzere alır ve sonunda bahçenin ürününü sahibine teslim etmezse; bahçe sahibi, o bahçenin komşu bahçelere göre verdiği ortalama ürünü hesaplayarak bahçıvandan alacaktır. Bahçıvan, toprağa bakım yapmamışsa tarlayı çevresindekilerle eşit hale getirinceye kadar kendisi işleyecektir.\"</i><br><br><b>Bu yasal düzenlemeyi okuyan bir öğrenci, toplumsal yapı hakkında hangi çıkarımı yapabilir?</b>",
        secenekler: [
            "A) Hammurabi Kanunları döneminde tarım tamamen devlet mülkiyetinde olup bireylerin arazi kiralaması yasaktı.",
            "B) Tarımsal ilişkilerin yasal çerçeveye oturtulması, kiracı-mal sahibi gibi toplumsal rollerin belirginleştiğini ve devletin üretimi düzenlemeye başladığını göstermektedir.",
            "C) Bu kanun maddesi, yalnızca kölelere yönelik yaptırımları düzenlemektedir.",
            "D) Komşu bahçelerle karşılaştırma yapılması, bireyselciliğin tarım toplumunda tamamen ortadan kalktığını kanıtlar.",
            "E) Hammurabi Kanunları, sözlü geleneklere dayandığından yazılı bir hukuk sisteminin varlığına kanıt sayılamaz."
        ],
        cevap: "B) Tarımsal ilişkilerin yasal çerçeveye oturtulması, kiracı-mal sahibi gibi toplumsal rollerin belirginleştiğini ve devletin üretimi düzenlemeye başladığını göstermektedir.",
        aciklama: "Doğru yanıt B'dir. Bu kanun maddesi, kiracı ve mal sahibi arasındaki anlaşmazlıkları çözmeye yönelik olup tarımsal ilişkilerin yazılı hukuk çerçevesine alındığını göstermektedir. Bu durum hem kiracı-mülk sahibi gibi toplumsal rollerin belirginleştiğini hem de devletin tarımsal üretimi düzenlemeye başladığını ortaya koymaktadır. A seçeneği devlet mülkiyetini ve bireysel kiralama yasağını öne sürer; metnin içeriği tam tersini göstermektedir. C seçeneği kölelere atıfta bulunmaktadır; oysa metin \"bahçıvan ve bahçe sahibinden\" söz etmektedir. D seçeneğinde toplumsal bireyselcilik ve komşu karşılaştırması arasında hatalı bir çıkarım yapılmaktadır. E seçeneğinde yazılı hukuk sistemi reddedilmektedir; oysa bu tableti bizatihi yazılı bir hukuk belgesidir."
    },
    {
        soru: "<i>Mısırbilimci John Romer, \"A History of Ancient Egypt\" (2012) eserinde Nil'in Mısır tarımını şöyle betimler: \"Her yıl düzenli olarak gerçekleşen Nil taşkını, çevresindeki arazileri verimli çamurla kaplıyor ve sulama kanallarına gerek kalmaksızın doğal bir gübrelik sağlıyordu. Bu düzenli ve öngörülebilir döngü, Mısırlılara Mezopotamyalılara kıyasla çok daha az idari koordinasyon gerektiren bir tarım sistemi kurma olanağı tanıdı.\"</i><br><br><b>Bu metni Mezopotamya ile karşılaştıran bir öğrenci, hangi analitik çıkarıma ulaşabilir?</b>",
        secenekler: [
            "A) Mısır ve Mezopotamya'da tarım tamamen aynı koşullar altında gelişmiş, ikisi arasında hiçbir fark bulunmamaktadır.",
            "B) Doğal koşulların farklılığı, iki medeniyetin idari ve siyasi örgütlenme biçimlerini de farklılaştırmış olabilir.",
            "C) Nil taşkınlarının düzenli olması, Mısır'da tarımın hiç gelişmemesine yol açmıştır.",
            "D) Mezopotamya, Mısır'a kıyasla daha az bürokrasi gerektirdiğinden daha güçlü bir devlet yapısı kurmuştur.",
            "E) Sulama kanallarının yokluğu, Mısır'da kentleşme sürecini tamamen engellemiştir."
        ],
        cevap: "B) Doğal koşulların farklılığı, iki medeniyetin idari ve siyasi örgütlenme biçimlerini de farklılaştırmış olabilir.",
        aciklama: "Doğru yanıt B'dir. Metin, Mısır'ın doğal Nil taşkınları sayesinde Mezopotamya'ya kıyasla daha az idari koordinasyona ihtiyaç duyduğunu belirtmektedir. Bu, coğrafi farklılıkların idari ve siyasi örgütlenmeye yansıdığı anlamına gelir; yani çevre ile kurumsal yapı arasında nedensellik ilişkisi kurulabilir. A seçeneği farkları yok sayar. C seçeneği Nil taşkınlarının tarımı engellediğini iddia eder; metin bunun aksini söyler. D seçeneği Mezopotamya ve Mısır'ın idari gereksinimlerini yanlış biçimde tersine çevirir. E seçeneği kentleşmenin engellendiğini öne sürer; metin kentleşmeden değil, sulama ihtiyacından söz etmektedir."
    },
    {
        soru: "<i>Arkeolog Philip Curtin, \"Cross-Cultural Trade in World History\" (1984) kitabında erken ticaret ağlarını şöyle tanımlar: \"Obsidyen, bakır, değerli taşlar ve tuz gibi bölgeye özgü hammaddeler, binlerce kilometre ötedeki topluluklar tarafından talep ediliyordu. Bu talep, farklı ekolojik bölgeler arasında sistematik takas güzergâhlarının oluşmasını sağladı. Ticaret, yalnızca mal alışverişi olmaktan çıkıp kültürel, teknolojik ve dilsel bilginin de aktarım kanalına dönüştü.\"</i><br><br><b>Curtin'in bu tespitine göre, erken ticaret ağlarının uygarlık tarihindeki rolü nasıl değerlendirilebilir?</b>",
        secenekler: [
            "A) Erken ticaret, yalnızca ekonomik işlev üstlenmiş; kültür veya teknoloji aktarımıyla hiçbir ilgisi olmamıştır.",
            "B) Ticaret ağları, farklı topluluklar arasında hem maddi hem de kültürel-teknolojik bilgi alışverişine aracılık ederek medeniyetlerin birbirini etkilemesini sağlamıştır.",
            "C) Bölgeye özgü hammaddelerin ticareti, ticaret güzergâhlarının ortadan kalkmasına yol açmıştır.",
            "D) Ticaret ağları, yalnızca komşu topluluklar arasında ve kısa mesafelerde işleyebilmiştir.",
            "E) Kültürel bilgi aktarımı, ticaret ağlarından tamamen bağımsız olarak gerçekleşmiştir."
        ],
        cevap: "B) Ticaret ağları, farklı topluluklar arasında hem maddi hem de kültürel-teknolojik bilgi alışverişine aracılık ederek medeniyetlerin birbirini etkilemesini sağlamıştır.",
        aciklama: "Doğru yanıt B'dir. Curtin, ticaretin hem mal alışverişi hem de kültürel, teknolojik ve dilsel bilgi aktarımının kanalı hâline geldiğini açıklamaktadır. Bu, ticaret ağlarının medeniyetlerarası etkileşimi mümkün kıldığına dair güçlü bir kanıttır. A seçeneği ticaretin kültürel boyutunu reddeder; metin ise tam tersi bir iddiayı içermektedir. C seçeneği ticaret güzergâhlarının ortadan kalktığını öne sürer; metin ise sistematik güzergâhların oluştuğunu belirtir. D seçeneği uzun mesafeli ticareti dışlar; metnin özünde ise uzak bölgeler arası değiş tokuş yer almaktadır. E seçeneği kültürel bilgi aktarımını ticaretten koparır; metin ise bu ikisini doğrudan ilişkilendirir."
    },
    {
        soru: "<i>Paleoantropolog Richard Wrangham, \"Catching Fire: How Cooking Made Us Human\" (2009) adlı eserinde tarımla birlikte ortaya çıkan toplumsal eşitsizliği şöyle yorumlar: \"Pişirme ve tarımın birlikte oluşturduğu besin artışı, hem nüfus patlamasına hem de artan işbölümüne zemin hazırladı. Ne var ki bu 'bolluk', herkese eşit dağılmadı; aksine depolayan, yöneten ve organize eden gruplar, yalnızca üretenlerden her zaman daha güçlü çıktı. Bunun paradoksu şudur: toplumun genel refahı artarken, bireylerin yaşam kalitesi ve sağlık düzeyi çoğunlukla geriledi.\"</i><br><br><b>Wrangham'ın 'paradoks' olarak nitelendirdiği durumu, tarih felsefesi açısından en doğru yorumlayan seçenek hangisidir?</b>",
        secenekler: [
            "A) Uygarlık, bireysel iyileşme olmaksızın da kolektif büyüme yaşayabilir; bu da ilerleme kavramının tek boyutlu değerlendirilemeyeceğini gösterir.",
            "B) Tarımın yarattığı bolluk, toplumun tüm kesimlerinde eşzamanlı ve eşit bir iyileşme sağlamıştır.",
            "C) Wrangham, uygarlığın her zaman bireysel refahı artırdığını tarih dışı bir kesinlikle ortaya koymaktadır.",
            "D) Toplumsal refahın artması, siyasi iktidar yapılarını otomatik olarak eşitlikçi hâle getirir.",
            "E) Tarım toplumlarında bireysel yaşam kalitesindeki gerileme, paradoksal olmaktan çok istisnai bir durumdur."
        ],
        cevap: "A) Uygarlık, bireysel iyileşme olmaksızın da kolektif büyüme yaşayabilir; bu da ilerleme kavramının tek boyutlu değerlendirilemeyeceğini gösterir.",
        aciklama: "Doğru yanıt A'dır. Wrangham'ın paradoksu, \"toplumsal refah artarken bireylerin sağlık ve yaşam kalitesinin gerileyebileceğini\" ortaya koyar. Bu, \"ilerleme\" kavramının kolektif ve bireysel boyutlarının birbirinden ayrışabileceğini, yani tarihsel ilerlemenin tek bir ölçütle değerlendirilemeyeceğini göstermektedir. B seçeneği eşit bir iyileşme olduğunu öne sürer; bu paradoksun tanımına aykırıdır. C seçeneği Wrangham'ın her koşulda iyileşme savunduğunu iddia eder; metin ise tam tersini içermektedir. D seçeneği refahın iktidar yapılarını otomatik eşitlikçileştirdiğini söyler; metin güç farklılıklarının derinleştiğini aktarmaktadır. E seçeneğinde yaşam kalitesindeki gerileme \"istisnai\" olarak küçümsenir; metin bunu genel bir eğilim olarak sunar."
    },
    {
        soru: "<i>Çevre tarihçisi Clive Ponting, \"A Green History of the World\" (1991) eserinde tarımın ekolojik maliyetini şöyle değerlendirir: \"İlk tarım toplulukları, ormansızlaşma, toprak erozyonu ve sulama tuzlanması gibi çevresel bozulmaya yol açtılar. Mezopotamya'da yoğun sulama, zamanla toprağı tuzlaştırdı ve bir dönem son derece verimli olan toprakları üretimsiz bıraktı. Sümer medeniyetinin çöküşünü açıklamak için bu ekolojik çöküşü göz ardı edemeyiz.\"</i><br><br><b>Ponting'in bu değerlendirmesini tarih metodolojisi açısından eleştirmek isteyen bir tarihçi, hangi argümanı öne sürebilir?</b>",
        secenekler: [
            "A) Ekolojik faktörler tarihsel açıklamada hiçbir zaman geçerli değildir; yalnızca siyasi nedenler kullanılmalıdır.",
            "B) Sümer'in çöküşünü tek bir etkenle (ekolojik bozulma) açıklamak, çok nedenli tarihsel olayları aşırı basitleştirebilir; başka faktörleri dışarıda bırakmak metodolojik bir sorun yaratır.",
            "C) Tuzlanma sorununun yalnızca modern dönemte ortaya çıktığını kanıtlamak, Ponting'i haklı çıkarır.",
            "D) Çevre tarihçilerinin tarihsel açıklamada yer almaması gerektiği ilkesi, Ponting'i geçersiz kılar.",
            "E) Ponting'in tezi, ancak Sümer'in çöküşünün MÖ 3000'den sonra gerçekleşmediği kanıtlanırsa çürütülmüş sayılır."
        ],
        cevap: "B) Sümer'in çöküşünü tek bir etkenle (ekolojik bozulma) açıklamak, çok nedenli tarihsel olayları aşırı basitleştirebilir; başka faktörleri dışarıda bırakmak metodolojik bir sorun yaratır.",
        aciklama: "Doğru yanıt B'dir. Tarih metodolojisinde tek bir etkenle karmaşık bir olayı açıklamak (monokauzalite) güçlü bir eleştiri konusudur. Ponting ekolojik bozulmayı öne çıkarmakta ancak siyasi çöküş, işgaller, ticaret yollarının değişmesi gibi faktörleri göz ardı edebilmektedir. Bu metodolojik zayıflık, \"çok nedenli açıklama\" ilkesini ihlal etmektedir. A seçeneği ekolojik açıklamanın geçersizliğini savunur; bu ise tarih felsefesinde kabul görmez. C seçeneği tuzlanmanın modern bir sorun olduğunu kanıtlamanın Ponting'i haklı çıkaracağını söyler; bu da mantıksal açıdan tutarsızdır. D seçeneği çevre tarihçilerini dışlar; bu ise tarih alanında kabul görmez. E seçeneği zaman koşuluna bağlı bir çürütme önerir; oysa asıl metodolojik sorun neden-sonuç bağının tek etkenle kurulmasıdır."
    },
    {
        soru: "<i>Arkeolog Ian Morris, \"Why the West Rules—For Now\" (2010) adlı yapıtında coğrafya ile uygarlık gelişimi arasındaki ilişkiyi şöyle çerçeveler: \"Evcilleştirilebilir bitki ve hayvan türlerinin dağılımı, hangi bölgelerin tarıma önce geçeceğini ve dolayısıyla kentleşme, uzmanlaşma ve teknoloji gibi 'sosyal kalkınma' göstergelerinde önde olacağını büyük ölçüde belirledi. Ancak bu coğrafi şans, tarihin geri kalanını tamamen deterministik biçimde belirlemiyor; sosyal kurumlar ve tarihsel krizler devreye girince sonuçlar değişebilmektedir.\"</i><br><br><b>Morris'in bu yaklaşımını doğru yorumlayan ifade hangisidir?</b>",
        secenekler: [
            "A) Morris, tarihin tamamıyla coğrafya tarafından belirlendiğini ve insan iradesinin hiçbir rolü olmadığını savunmaktadır.",
            "B) Morris, coğrafyayı belirleyici bir başlangıç avantajı olarak görürken, sosyal kurumlar ve tarihsel krizlerin bu avantajı değiştirebileceğini kabul eder.",
            "C) Morris'e göre evcilleştirilebilir türlerin dağılımı, hangi toplumların her zaman galip geleceğini kesin olarak belirlemektedir.",
            "D) Sosyal kurumlar, coğrafyanın tarihsel etkisini tamamen ortadan kaldırmaktadır.",
            "E) Tarımın önce başladığı bölgeler, tarih boyunca hiçbir zaman güç kaybetmemiş ve daima dünyaya egemen olmuştur."
        ],
        cevap: "B) Morris, coğrafyayı belirleyici bir başlangıç avantajı olarak görürken, sosyal kurumlar ve tarihsel krizlerin bu avantajı değiştirebileceğini kabul eder.",
        aciklama: "Doğru yanıt B'dir. Morris'in yaklaşımı \"yumuşak determinizm\" olarak nitelendirilebilir: Coğrafya ve evcilleştirilebilir türlerin dağılımı güçlü bir başlangıç avantajı sunar; ancak bu avantaj sonuçları tamamen belirlemez. Sosyal kurumlar ve tarihsel krizler devreye girince tablolar değişebilir. A seçeneği tam determinist bir yorumdur; Morris bunu reddetmektedir. C seçeneği kesin bir üstünlük savunur; Morris ise \"tamamen deterministik değil\" demektedir. D seçeneği coğrafyanın etkisini sıfıra indirmektedir; bu da metinle çelişir. E seçeneği kalıcı hâkimiyeti savunur; tarih ise güç dengelerinin değiştiğini göstermektedir."
    },
    {
        soru: "<i>Tarihçi James C. Scott, \"Against the Grain: A Deep History of the Earliest States\" (2017) kitabında ilk devletleri sert bir eleştiri süzgecinden geçirir: \"İlk devletler, tahıl tarımının etrafında örgütlendi; çünkü tahıl sayılabilir, taşınabilir ve depolanabilirdi—kısacası vergilendirilebilirdi. Devlet, vergilendirebildiği şeyin etrafında şekillendi. Kökleri yenilemeyen insanlar, taro (gölevez) yetiştirmeyen insanlar, kısmen de bu nedenle devlet dışında kaldılar.\"</i><br><br><b>Scott'ın bu savına dayanarak, ilk devletlerin ortaya çıkmasında en belirleyici etkenin ne olduğu çıkarılabilir?</b>",
        secenekler: [
            "A) İlk devletler, tahılın vergilendirilebilir yapısından değil yalnızca askeri fetihlerden doğdu.",
            "B) Devletin varlığı ile tahıl tarımı arasında derin bir yapısal bağ bulunmaktadır; devlet, vergilendirip kayıt altına alabildiği artığın peşinden gitmiştir.",
            "C) Scott'a göre kök bitkileri yetiştiren topluluklar da aynı kolaylıkla devlet kurabilmiş ve devlet dışında kalmamıştır.",
            "D) Vergilendirme, devlet kurulmadan çok önce tahıl tarımından bağımsız biçimde gelişmiştir.",
            "E) Devletlerin örgütlenmesinde tahıl tarımının hiçbir rolü olmamış; yalnızca nüfus yoğunluğu belirleyici olmuştur."
        ],
        cevap: "B) Devletin varlığı ile tahıl tarımı arasında derin bir yapısal bağ bulunmaktadır; devlet, vergilendirip kayıt altına alabildiği artığın peşinden gitmiştir.",
        aciklama: "Doğru yanıt B'dir. Scott'ın temel iddiası, tahılın \"sayılabilir, taşınabilir ve depolanabilir\" özelliklerinin onu vergilendirilebilir kıldığı ve bu sayede devletin tahıl tarımının etrafında örgütlendiğidir. Bu, devlet ile tahıl tarımı arasında derin bir yapısal bağ olduğunu ortaya koymaktadır. A seçeneği askeri fetihleri tek neden olarak gösterir; metin ise ekonomik-yönetsel bir çerçeve sunar. C seçeneği kök bitkileri yetiştirenlerin devlet kurabileceğini söyler; Scott tam tersini ima etmektedir. D seçeneği vergilendirmeyi tarımdan bağımsız gösterir; metin bu iki olguyu birbirine bağlamaktadır. E seçeneği nüfus yoğunluğunu tek etken olarak öne çıkarır; Scott'ın odağı ise vergilendirilebilir artık kavramı etrafında şekillenmektedir."
    },
    {
        soru: "<i>Biyolog ve paleoantropolog Spencer Wells, \"Pandora's Seed: The Unforeseen Cost of Civilization\" (2010) kitabında tarımın biyolojik paradoksunu şu şekilde özetler: \"Köprü üzerinde incelenen Neolitik dönem iskeletleri, avcı-toplayıcıların kemiklerine kıyasla daha düşük boylu, daha fazla diş çürüğüne ve kemik rahatsızlıklarına sahip bireyler olduğunu gösterdi. Kalabalık yaşam ve hayvanlarla temas, salgın hastalıkların yayılmasını kolaylaştırdı. Ancak paradoks şu: bu döneme ait toplulukların nüfusu yine de hızla artıyordu.\"</i><br><br><b>Wells'in aktardığı bu paradoksu, Darwinci evrim kuramı çerçevesinde en tutarlı biçimde hangi seçenek açıklar?</b>",
        secenekler: [
            "A) Bireylerin sağlık düzeyinin düşmesi, toplumun çoğalma hızını daima olumsuz etkiler.",
            "B) Nüfus artışı için bireylerin optimal sağlığa sahip olması şart değildir; üreme başarısı arttığı sürece nüfus büyüyebilir, bu da bireysel sağlık ile demografik büyümenin her zaman paralel gitmediğini gösterir.",
            "C) Kalabalık yaşam koşulları, bağışıklık sistemini güçlendirerek nüfus artışına katkı sağlamıştır.",
            "D) Wells'in verileri yanlıştır; Neolitik döneme ait iskeletler avcı-toplayıcılara kıyasla daha sağlıklı bir yapı göstermektedir.",
            "E) Salgın hastalıkların yayılması, Neolitik topluluklarda genetik mutasyonları hızlandırarak boyu uzatmıştır."
        ],
        cevap: "B) Nüfus artışı için bireylerin optimal sağlığa sahip olması şart değildir; üreme başarısı arttığı sürece nüfus büyüyebilir, bu da bireysel sağlık ile demografik büyümenin her zaman paralel gitmediğini gösterir.",
        aciklama: "Doğru yanıt B'dir. Evrim kuramı açısından değerlendirildiğinde, \"uyum\" bireyin optimal sağlığı değil üreme başarısını ifade eder. Tarımsal yaşam bireylerin sağlığını olumsuz etkilese de düzenli besin temini ve kısa doğum aralıkları gibi etkenler üreme başarısını artırmış; bu da nüfus büyümesini sağlamıştır. Paradoks burada çözülmektedir: bireysel sağlık ile demografik başarı her zaman paralel seyretmez. A seçeneği sağlık düşüşünün nüfusu azaltacağını öne sürer; metin ise nüfusun arttığını göstermektedir. C seçeneği kalabalık yaşamın bağışıklığı güçlendirdiğini iddia eder; metin ise salgın hastalıkların kolaylaştığını söyler. D seçeneği Wells'in verilerini tersine çevirir. E seçeneği salgın hastalıkların boyu uzattığını iddia eder; bu biyolojik açıdan desteklenmez."
    },
    {
        soru: "<i>Din tarihçisi Karen Armstrong, \"A History of God\" (1993) eserinde tarımla beraber dini düşüncenin dönüşümünü şöyle aktarır: \"Avcı-toplayıcıların tanrıları çoğunlukla hayvan ruhları ve hareket eden doğa güçleriyle ilgiliydi. Yerleşik çiftçiler ise bereket, yağmur ve mevsimleri yöneten gök tanrıları ve toprak anaları geliştirdi. Tapınak, bu tanrılarla 'sözleşme' yapılan mekân hâline geldi; kurbanlar ve sunular, doğal döngülerin sürekliliğini güvence altına alan ritüel ekonomisi oluşturdu.\"</i><br><br><b>Armstrong'un çözümlemesine göre tarımla birlikte din anlayışındaki dönüşümü ve bu dönüşümün toplumsal işlevini en bütünlüklü açıklayan seçenek hangisidir?</b>",
        secenekler: [
            "A) Tarım toplumlarında dini düşünce tamamen ekonomik kaygılardan bağımsız bir gelişme göstermiştir.",
            "B) Tarımsal yaşamın düzenli, öngörülebilir bir doğa döngüsüne bağımlılığı; bereket ve mevsimleri yöneten tanrılar ile tapınak-sözleşme ritüellerini doğurmuş, din böylece tarımsal üretim riskini yönetme işlevi üstlenmiştir.",
            "C) Avcı-toplayıcıların dini inançları, tarım toplumlarından çok daha gelişmiş ve karmaşık bir yapıya sahipti.",
            "D) Tapınaklar yalnızca siyasi iktidarın merkezleri olarak tasarlanmış; doğa güçleriyle herhangi bir ilişki kurulmamıştır.",
            "E) Tarım toplumlarındaki ritüel ekonomi, din ve ekonominin birbirinden tamamen ayrılmasını sağlamıştır."
        ],
        cevap: "B) Tarımsal yaşamın düzenli, öngörülebilir bir doğa döngüsüne bağımlılığı; bereket ve mevsimleri yöneten tanrılar ile tapınak-sözleşme ritüellerini doğurmuş, din böylece tarımsal üretim riskini yönetme işlevi üstlenmiştir.",
        aciklama: "Doğru yanıt B'dir. Armstrong'un argümanı birbirini tamamlayan iki unsur içermektedir: (1) Tarımsal yaşamın doğa döngülerine bağımlılığı, bereket ve mevsimleri kontrol eden tanrıların gelişmesine yol açmıştır. (2) Tapınak ve kurban ritüelleri, bu tanrılarla \"sözleşme\" kurarak tarımsal riskleri yönetmenin sembolik bir aracına dönüşmüştür. Yani din, bu dönemde toplumsal bir risk yönetim mekanizması işlevi üstlenmiştir. A seçeneği dini ekonomik süreçlerden koparır; metin ise bu iki olguyu doğrudan ilişkilendirir. C seçeneği avcı-toplayıcıların daha gelişmiş bir dini yapısı olduğunu öne sürer; metin farklı bir karmaşıklıktan söz eder. D seçeneği tapınak ve doğa güçleri arasındaki bağı reddeder; metin ise tam tersini savunmaktadır. E seçeneği din ile ekonominin birbirinden ayrıldığını iddia eder; Armstrong'un \"ritüel ekonomisi\" kavramı bu ikisinin iç içe geçtiğini göstermektedir."
    },
    {
        soru: "<i>Tarih felsefecisi Oswald Spengler, \"The Decline of the West\" (1918-1922) adlı eserinde uygarlıkları canlı organizmalar gibi ele alır ve tarımı şöyle değerlendirir: \"Toprak köylünün ruhunun temelidir; o toprağı kazarken uygarlığın tohumlarını da eker. Ama aynı toprak, ürettiği kentleri ve o kentlerin yarattığı 'para ekonomisi'ni besleyince, kendi ruhunu çürütecek bir güç doğurmuş olur.\"</i><br><br><b>Spengler'in bu metaforik ifadesinden yola çıkarak, tarımın uygarlık tarihi üzerindeki diyalektik etkisini en doğru yorumlayan seçenek hangisidir?</b>",
        secenekler: [
            "A) Spengler'e göre tarım, uygarlıkları güçlendiren tek etkendir ve herhangi bir olumsuz sonuç doğurmaz.",
            "B) Tarım, uygarlıkların hem kuruluşunu hem de içsel çöküşünü besleyen bir diyalektik güç olarak işlev görür; kentleşme ve para ekonomisi, tarımın doğurduğu ama köklü değerlerini aşındıran bir karşı güç oluşturur.",
            "C) Spengler, para ekonomisinin ortaya çıkmasını yalnızca köylünün ahlaki yozlaşmasına bağlamaktadır.",
            "D) Spengler'in metaforu, tarımın kentleşmeyi tamamen engellediği anlamına gelmektedir.",
            "E) Spengler, tarım ve ticaret arasındaki ilişkiyi incelemeksizin yalnızca politik çöküşü analiz etmektedir."
        ],
        cevap: "B) Tarım, uygarlıkların hem kuruluşunu hem de içsel çöküşünü besleyen bir diyalektik güç olarak işlev görür; kentleşme ve para ekonomisi, tarımın doğurduğu ama köklü değerlerini aşındıran bir karşı güç oluşturur.",
        aciklama: "Doğru yanıt B'dir. Spengler'in diyalektik mantığı şudur: Tarım, köylünün ruhu ve uygarlığın temeli olarak bir inşa gücüdür. Ancak tarım, kentleri ve para ekonomisini besleyerek bu köklü değerlerin aşınmasına zemin hazırlar. Bu, Hegelci \"tez-antitez\" mantığını tarih felsefesine uygulamaktadır: tarım hem inşa eden hem de kendi karşıtını doğuran bir güçtür. A seçeneği olumlu-olumsuz diyalektiği görmezden gelir. C seçeneği para ekonomisini yalnızca bireysel ahlaki yozlaşmaya bağlar; Spengler ise yapısal bir güç ilişkisinden söz eder. D seçeneği kentleşmenin engellendiğini öne sürer; metin tam tersini anlatmaktadır. E seçeneğinde politik çöküşe odaklanıldığı iddia edilir; metnin odağı ise kültürel-uygarlık diyalektiğidir."
    }
];
// --- 2. ÜNİTE: TARIM DEVRİMİNİN ESKİ ÇAĞ'A ETKİLERİ - KLASİK SINAV 1 ---
window.allTests["klasik_u2_tarim_1"] = [
    {
        soru: "<i>Kaynak: Eskiçağ Tarihi Ders Kitabı<br>\"Avcı-toplayıcı insanlar doğada bulduklarıyla yetinirken, tohumların yeşerdiğini fark eden insanlık, buğday ve arpa gibi bitkileri kendi kontrolleri altında yetiştirmeye başladı. Bu durum, tarlaların yanına kalıcı kulübeler yapılmasını zorunlu kıldı.\"</i><br><br><b>Metne göre Tarım Devrimi, insanlık tarihindeki hangi büyük fiziksel/mekansal değişimin temel sebebi olmuştur?</b>",
        cevap: "Tarım Devrimi, insanların göçebe (avcı-toplayıcı) yaşam tarzını bırakarak 'Yerleşik Hayata' geçmelerinin ve ilk köyleri kurmalarının temel sebebi olmuştur. Tarlaları koruma ve işleme zorunluluğu kalıcı yerleşimi getirmiştir."
    },
    {
        soru: "<i>Kaynak: Arkeolojik Kazı Raporları, Çayönü<br>\"Kazılarda, tahılların öğütüldüğü bazalt taşından havanlar, topraktan yapılmış ve fırınlanmış büyük tahıl saklama kapları (çömlekler) bulunmuştur.\"</i><br><br><b>Çanak çömlek yapımının Tarım Devrimi ile birlikte ortaya çıkmasının temel ekonomik nedeni nedir?</b>",
        cevap: "Tarım sayesinde insanların günlük ihtiyaçlarından daha fazla (artı ürün) gıda üretmeleri, bu fazla ürünleri bozulmadan saklama (depolama) ihtiyacını doğurmuş; bu ihtiyaç da çanak çömlek (seramik) sanatının ortaya çıkmasına neden olmuştur."
    },
    {
        soru: "<i>Kaynak: İnsanlık Tarihi Belgeseli<br>\"Koyun, keçi ve sığır gibi hayvanlar sadece etleri için değil; sütleri, yünleri ve tarlalarda saban çekmek için kullanılan kas güçleri için evcilleştirildi.\"</i><br><br><b>Hayvanların evcilleştirilmesinin tarımsal üretime ve ekonomiye katkısını metinden hareketle açıklayınız.</b>",
        cevap: "Hayvanlar tarımda kas gücü (saban çekme) olarak kullanılarak üretimi hızlandırmış ve kolaylaştırmıştır. Ayrıca yünleri dokumacılığın, sütleri ise yeni gıda kollarının gelişmesini sağlayarak ekonomiyi çeşitlendirmiştir."
    },
    {
        soru: "<i>Kaynak: V. Gordon Childe, Kendini Yaratan İnsan<br>\"Eriha (Jericho) yerleşkesinin etrafı devasa taş surlar ve hendeklerle çevrilmişti. Bu durum, yerleşkedekilerin dışarıdan gelebilecek tehlikelere karşı ciddi bir hazırlık içinde olduğunu gösteriyordu.\"</i><br><br><b>İlk tarım köylerinin etrafının surlarla çevrilmesinin temel sebebi nedir? Çatışmaların kaynağı ne olabilir?</b>",
        cevap: "Tarım köylerinde depolanan zengin gıda stokları (artı ürün), çevredeki açlık çeken avcı-toplayıcı grupların veya diğer göçebe toplulukların saldırılarına hedef oluyordu. Surlar, bu birikimi koruma (savunma) ihtiyacından doğmuştur."
    },
    {
        soru: "<i>Kaynak: Tarih Öncesi Değişimler<br>\"Neolitik dönemde insanlar sadece tarım yapmadı; doğada buldukları obsidyen (volkanik cam) taşlarını işleyerek kesici aletler yaptılar ve bu taşın bulunmadığı yüzlerce kilometre uzaklıktaki köylerle değiş tokuş yaptılar.\"</i><br><br><b>Bu durum, Tarım Devrimi döneminde hangi ekonomik faaliyetin başladığını gösterir?</b>",
        cevap: "İhtiyaç fazlası ürünlerin (veya nadir madenlerin) başka köylerle değiş tokuş edilmesi, tarihteki ilk 'Takas (Tramp) Ticaretinin' başladığını gösterir."
    },
    {
        soru: "<i>Kaynak: Antropoloji Notları<br>\"Tarıma geçişle birlikte, insanların kemik yapılarında değişimler, eklem rahatsızlıkları ve diş çürükleri görülmeye başlanmıştır.\"</i><br><br><b>Tarıma geçişin insan sağlığı üzerindeki bu olumsuz etkileri hangi nedenlere bağlanabilir?</b>",
        cevap: "Diş çürükleri karbonhidrat (tahıl) ağırlıklı tek tip beslenmeden; eklem rahatsızlıkları ise tarlada saatlerce iki büklüm çalışmanın getirdiği ağır fiziksel iş yükünden kaynaklanmıştır."
    },
    {
        soru: "<i>Kaynak: Mezopotamya Mitolojisi<br>\"Sümerlerde bereket, yağmur ve toprak tanrıları en önemli panteonu oluştururdu. Tanrılara sunulan en büyük hediyeler ilk hasat buğdaylarıydı.\"</i><br><br><b>Toplumların inanç sistemlerinin doğa ve bereket üzerine şekillenmesi, onların hangi özelliğiyle doğrudan ilişkilidir?</b>",
        cevap: "Toplumların ekonomik geçim kaynağının (tarım) inançlarını doğrudan şekillendirdiğini gösterir. Hayatta kalmaları yağmura ve hasada bağlı olduğu için dinleri de tamamen tarımsal döngü üzerine kurulmuştur."
    },
    {
        soru: "<i>Kaynak: Yuval Noah Harari, Sapiens<br>\"Eskiden herkes kendi yemeğini avlamak zorundaydı. Ancak tarımla birlikte bir çiftçi ailesi, on aileyi doyuracak kadar tahıl üretebiliyordu. Böylece diğer dokuz aile tarladan çekilip çömlekçi, rahip, asker veya dokumacı olabildi.\"</i><br><br><b>Metne göre, tarımda 'Artı Ürün (İhtiyaç Fazlası Üretim)' kavramının toplumsal yapıdaki en önemli sonucu nedir?</b>",
        cevap: "Artı ürün, toplumda 'İş Bölümü ve Meslekleşmenin' doğmasına neden olmuştur. Herkesin gıda üretmek zorunda kalmaması, zanaatkâr, asker ve din adamı gibi yeni sosyal sınıfların/mesleklerin ortaya çıkmasını sağlamıştır."
    },
    {
        soru: "<i>Kaynak: Jean-Jacques Rousseau, İnsanlar Arasındaki Eşitsizliğin Kaynağı<br>\"Bir toprak parçasının etrafını çitle çevirip 'Bu bana aittir' diyen ve buna inanacak kadar saf insanlar bulan ilk insan, sivil toplumun (ve eşitsizliğin) gerçek kurucusudur.\"</i><br><br><b>Rousseau'nun bu sözünden hareketle, tarım devriminin toplumsal hayatta hangi hukuki/ekonomik kavramı yarattığı söylenebilir? Bunun sosyolojik sonucu ne olmuştur?</b>",
        cevap: "Tarım devrimi 'Özel Mülkiyet' kavramını yaratmıştır. Toprağın ve ürünün kişiselleşmesi, tarih boyunca sürecek olan zengin-fakir ayrımına (toplumsal sınıf eşitsizliklerine) zemin hazırlamıştır."
    },
    {
        soru: "<i>Kaynak: Çatalhöyük Kazı Günlükleri (Ian Hodder)<br>\"Çatalhöyük'te evler birbirine bitişikti ve sokak yoktu; insanlar evlerine çatılardan açılan deliklerden giriyordu. Ancak tüm evlerin büyüklüğü ve içindeki eşyalar neredeyse birbirinin aynısıydı.\"</i><br><br><b>Çatalhöyük'teki evlerin eşit büyüklükte olması, bu ilk tarım toplumunun sosyal yapısı hakkında bize ne gibi bir ipucu verir?</b>",
        cevap: "Bu durum, Çatalhöyük'te henüz keskin bir 'sınıf ayrımının' veya katı bir hiyerarşinin oluşmadığını; eşitlikçi (egaliteryan) bir tarım toplumu yapısının sürdüğünü gösterir."
    }
];
